def _wiki_feature_table_exists(cur: Any, table_name: str) -> bool:
    cur.execute("SELECT to_regclass(%s)", (table_name,))
    row = cur.fetchone()
    return bool(row and row[0] is not None)


def _sanitize_wiki_upload_filename(raw_name: str | None) -> str:
    value = str(raw_name or "").strip()
    if not value:
        return "attachment.bin"
    value = value.replace("\\", "/").split("/")[-1].strip()
    value = re.sub(r"[^\w.\-() ]+", "_", value)
    value = re.sub(r"\s+", " ", value).strip()
    return value[:240] if value else "attachment.bin"


def _wiki_upload_extension_allowed(filename: str) -> bool:
    lower = filename.lower()
    idx = lower.rfind(".")
    if idx <= 0:
        return False
    return lower[idx:] in _WIKI_UPLOAD_ALLOWED_EXTENSIONS


def _wiki_upload_is_image(filename: str, content_type: str | None) -> bool:
    content_type_value = str(content_type or "").strip().lower()
    if content_type_value.startswith("image/"):
        return True
    lower = filename.lower()
    return any(lower.endswith(ext) for ext in (".png", ".jpg", ".jpeg", ".gif", ".webp", ".svg", ".avif", ".bmp"))


def _wiki_space_key_from_slug(slug: str | None) -> str:
    normalized = str(slug or "").strip().lower().replace("\\", "/")
    if not normalized:
        return "general"
    first = normalized.split("/", 1)[0].strip()
    return _slugify_segment(first or "general")


def _extract_wiki_mentions(text: str) -> list[str]:
    seen: set[str] = set()
    mentions: list[str] = []
    for match in _WIKI_MENTION_PATTERN.finditer(str(text or "")):
        actor = str(match.group(1) or "").strip()
        if not actor:
            continue
        key = actor.lower()
        if key in seen:
            continue
        seen.add(key)
        mentions.append(actor)
    return mentions


def _load_wiki_space_policy(cur: Any, *, project_id: str, space_key: str) -> dict[str, Any]:
    default_policy = {
        "project_id": project_id,
        "space_key": space_key,
        "write_mode": "open",
        "comment_mode": "open",
        "review_assignment_required": False,
        "metadata": {},
        "exists": False,
    }
    if not _wiki_feature_table_exists(cur, "public.wiki_space_policies"):
        return default_policy
    cur.execute(
        """
        SELECT write_mode, comment_mode, review_assignment_required, metadata
        FROM wiki_space_policies
        WHERE project_id = %s
          AND space_key = %s
        LIMIT 1
        """,
        (project_id, space_key),
    )
    row = cur.fetchone()
    if row is None:
        return default_policy
    return {
        "project_id": project_id,
        "space_key": space_key,
        "write_mode": str(row[0] or "open"),
        "comment_mode": str(row[1] or "open"),
        "review_assignment_required": bool(row[2]),
        "metadata": row[3] if isinstance(row[3], dict) else {},
        "exists": True,
    }


def _normalized_wiki_space_policy_snapshot(*, write_mode: str, comment_mode: str, review_assignment_required: bool, metadata: dict[str, Any] | None) -> dict[str, Any]:
    return {
        "write_mode": str(write_mode or "open"),
        "comment_mode": str(comment_mode or "open"),
        "review_assignment_required": bool(review_assignment_required),
        "metadata": dict(metadata or {}),
    }


def _wiki_space_policy_changed_fields(before_policy: dict[str, Any], after_policy: dict[str, Any]) -> list[str]:
    changed: list[str] = []
    if str(before_policy.get("write_mode") or "open") != str(after_policy.get("write_mode") or "open"):
        changed.append("write_mode")
    if str(before_policy.get("comment_mode") or "open") != str(after_policy.get("comment_mode") or "open"):
        changed.append("comment_mode")
    if bool(before_policy.get("review_assignment_required")) != bool(after_policy.get("review_assignment_required")):
        changed.append("review_assignment_required")
    before_metadata = before_policy.get("metadata") if isinstance(before_policy.get("metadata"), dict) else {}
    after_metadata = after_policy.get("metadata") if isinstance(after_policy.get("metadata"), dict) else {}
    if before_metadata != after_metadata:
        changed.append("metadata")
        before_preset = str(before_metadata.get("publish_checklist_preset") or "").strip().lower()
        after_preset = str(after_metadata.get("publish_checklist_preset") or "").strip().lower()
        if before_preset != after_preset:
            changed.append("publish_checklist_preset")
    return changed


def _wiki_publish_checklist_preset_from_metadata(metadata: Any) -> str:
    if not isinstance(metadata, dict):
        return "none"
    preset = str(metadata.get("publish_checklist_preset") or "").strip().lower()
    if preset in {"ops_standard", "policy_strict"}:
        return preset
    return "none"


def _summarize_wiki_space_policy_audit_rows(rows: list[Any]) -> dict[str, Any]:
    checklist_usage = {"none": 0, "ops_standard": 0, "policy_strict": 0}
    actor_counts: dict[str, int] = {}
    checklist_transitions = 0
    timeline_ts: list[datetime] = []

    for row in rows:
        changed_by = str(row[1] or "").strip() or "unknown"
        actor_counts[changed_by] = actor_counts.get(changed_by, 0) + 1

        before_policy = row[2] if isinstance(row[2], dict) else {}
        after_policy = row[3] if isinstance(row[3], dict) else {}
        before_preset = _wiki_publish_checklist_preset_from_metadata(before_policy.get("metadata"))
        after_preset = _wiki_publish_checklist_preset_from_metadata(after_policy.get("metadata"))
        checklist_usage[after_preset] += 1
        if before_preset != after_preset:
            checklist_transitions += 1

        created_at = row[6]
        if isinstance(created_at, datetime):
            timeline_ts.append(created_at)

    sorted_actor_counts = sorted(actor_counts.items(), key=lambda item: (-item[1], item[0]))
    top_actor = None
    top_actor_updates = 0
    if sorted_actor_counts:
        top_actor = sorted_actor_counts[0][0]
        top_actor_updates = int(sorted_actor_counts[0][1])

    avg_update_interval_days: float | None = None
    first_updated_at: str | None = None
    last_updated_at: str | None = None
    if timeline_ts:
        timeline_ts_sorted = sorted(timeline_ts)
        first_updated_at = timeline_ts_sorted[0].isoformat()
        last_updated_at = timeline_ts_sorted[-1].isoformat()
        if len(timeline_ts_sorted) >= 2:
            deltas_seconds: list[float] = []
            previous = timeline_ts_sorted[0]
            for current in timeline_ts_sorted[1:]:
                deltas_seconds.append(max(0.0, (current - previous).total_seconds()))
                previous = current
            if deltas_seconds:
                avg_update_interval_days = float(sum(deltas_seconds) / len(deltas_seconds) / 86400.0)

    return {
        "total_updates": len(rows),
        "unique_actors": len(actor_counts),
        "top_actor": top_actor,
        "top_actor_updates": top_actor_updates,
        "avg_update_interval_days": avg_update_interval_days,
        "checklist_usage": checklist_usage,
        "checklist_transitions": checklist_transitions,
        "first_updated_at": first_updated_at,
        "last_updated_at": last_updated_at,
    }


def _wiki_actor_is_owner(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    actor: str,
    page_id: str | None = None,
) -> bool:
    normalized_actor = str(actor or "").strip()
    if not normalized_actor:
        return False
    actor_lower = normalized_actor.lower()
    if page_id and _wiki_feature_table_exists(cur, "public.wiki_page_owners"):
        cur.execute(
            """
            SELECT 1
            FROM wiki_page_owners
            WHERE project_id = %s
              AND page_id::text = %s
              AND lower(owner) = %s
            LIMIT 1
            """,
            (project_id, page_id, actor_lower),
        )
        if cur.fetchone() is not None:
            return True
    if _wiki_feature_table_exists(cur, "public.wiki_space_owners"):
        cur.execute(
            """
            SELECT 1
            FROM wiki_space_owners
            WHERE project_id = %s
              AND space_key = %s
              AND lower(owner) = %s
            LIMIT 1
            """,
            (project_id, space_key, actor_lower),
        )
        if cur.fetchone() is not None:
            return True
    return False


def _wiki_space_owner_count(cur: Any, *, project_id: str, space_key: str) -> int:
    if not _wiki_feature_table_exists(cur, "public.wiki_space_owners"):
        return 0
    cur.execute(
        """
        SELECT COUNT(*)::int
        FROM wiki_space_owners
        WHERE project_id = %s
          AND space_key = %s
        """,
        (project_id, space_key),
    )
    row = cur.fetchone()
    return int(row[0] if row and row[0] is not None else 0)


def _wiki_page_owner_count(cur: Any, *, project_id: str, page_id: str) -> int:
    if not _wiki_feature_table_exists(cur, "public.wiki_page_owners"):
        return 0
    cur.execute(
        """
        SELECT COUNT(*)::int
        FROM wiki_page_owners
        WHERE project_id = %s
          AND page_id::text = %s
        """,
        (project_id, page_id),
    )
    row = cur.fetchone()
    return int(row[0] if row and row[0] is not None else 0)


def _check_wiki_policy_access(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    actor: str,
    action: str,
    page_id: str | None = None,
) -> dict[str, Any]:
    policy = _load_wiki_space_policy(cur, project_id=project_id, space_key=space_key)
    actor_is_owner = _wiki_actor_is_owner(
        cur,
        project_id=project_id,
        space_key=space_key,
        actor=actor,
        page_id=page_id,
    )
    mode = policy["write_mode"] if action == "write" else policy["comment_mode"]
    if mode == "owners_only" and not actor_is_owner:
        return {
            "allowed": False,
            "reason": "owners_only",
            "space_key": space_key,
            "action": action,
            "policy": policy,
            "actor_is_owner": actor_is_owner,
        }
    return {
        "allowed": True,
        "reason": "allowed",
        "space_key": space_key,
        "action": action,
        "policy": policy,
        "actor_is_owner": actor_is_owner,
    }


def _wiki_notifications_enabled(cur: Any) -> bool:
    return _wiki_feature_table_exists(cur, "public.wiki_notifications")


def _collect_wiki_page_watchers(cur: Any, *, project_id: str, page_id: str) -> list[str]:
    if not _wiki_feature_table_exists(cur, "public.wiki_page_watchers"):
        return []
    cur.execute(
        """
        SELECT watcher
        FROM wiki_page_watchers
        WHERE project_id = %s
          AND page_id::text = %s
        ORDER BY watcher ASC
        """,
        (project_id, page_id),
    )
    rows = cur.fetchall()
    return [str(row[0]) for row in rows if row and row[0]]


def _insert_wiki_notifications(
    cur: Any,
    *,
    project_id: str,
    recipients: set[str],
    actor: str | None,
    kind: str,
    title: str,
    body: str | None,
    link: str | None,
    metadata: dict[str, Any] | None = None,
) -> list[str]:
    if not recipients or not _wiki_notifications_enabled(cur):
        return []
    actor_value = str(actor or "").strip() or None
    actor_lower = actor_value.lower() if actor_value else None
    inserted: list[str] = []
    for recipient in sorted(recipients):
        recipient_value = str(recipient or "").strip()
        if not recipient_value:
            continue
        if actor_lower and recipient_value.lower() == actor_lower:
            continue
        notification_id = str(uuid4())
        cur.execute(
            """
            INSERT INTO wiki_notifications (
              id, project_id, recipient, actor, kind, title, body, link, metadata, status
            )
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, 'unread')
            """,
            (
                notification_id,
                project_id,
                recipient_value,
                actor_value,
                kind,
                title[:500],
                (body or "")[:2000] if body is not None else None,
                (link or "")[:1000] if link is not None else None,
                Jsonb(metadata or {}),
            ),
        )
        inserted.append(notification_id)
    return inserted


def _inject_statement_into_markdown(markdown: str, section_heading: str, statement_text: str) -> str:
    line = f"- {statement_text}"
    normalized_lines = markdown.splitlines()
    if not normalized_lines:
        return f"## {section_heading}\n{line}\n"

    heading = f"## {section_heading}"
    if heading not in normalized_lines:
        suffix = "\n" if markdown.endswith("\n") else "\n\n"
        return f"{markdown}{suffix}{heading}\n{line}\n"

    heading_index = normalized_lines.index(heading)
    next_heading_index = None
    for idx in range(heading_index + 1, len(normalized_lines)):
        if normalized_lines[idx].startswith("## "):
            next_heading_index = idx
            break

    insert_at = next_heading_index if next_heading_index is not None else len(normalized_lines)
    normalized_lines.insert(insert_at, line)
    return "\n".join(normalized_lines).rstrip() + "\n"


def _apply_section_statements_to_markdown(
    markdown: str,
    *,
    section_heading: str,
    statements: list[str],
    mode: str,
) -> str:
    cleaned = [item.strip() for item in statements if item.strip()]
    if not cleaned:
        return markdown

    lines = markdown.splitlines()
    heading_line = f"## {section_heading}"

    if not lines:
        body = "\n".join([heading_line] + [f"- {item}" for item in cleaned])
        return body.rstrip() + "\n"

    if heading_line not in lines:
        suffix = "\n" if markdown.endswith("\n") else "\n\n"
        block = "\n".join([heading_line] + [f"- {item}" for item in cleaned])
        return f"{markdown}{suffix}{block}\n"

    start_idx = lines.index(heading_line)
    end_idx = len(lines)
    for idx in range(start_idx + 1, len(lines)):
        if lines[idx].startswith("## "):
            end_idx = idx
            break

    existing_block = lines[start_idx + 1 : end_idx]
    if mode == "replace":
        replacement = [f"- {item}" for item in cleaned]
    else:
        existing_norm = {
            _normalize_statement_text(item[2:])
            for item in existing_block
            if item.strip().startswith("- ")
        }
        addition = [f"- {item}" for item in cleaned if _normalize_statement_text(item) not in existing_norm]
        replacement = existing_block + addition

    updated = lines[: start_idx + 1] + replacement + lines[end_idx:]
    return "\n".join(updated).rstrip() + "\n"


def _compute_claim_fingerprint(project_id: str, entity_key: str, category: str, claim_text: str) -> str:
    material = "|".join(
        [
            project_id.strip().lower(),
            entity_key.strip().lower(),
            category.strip().lower(),
            _normalize_statement_text(claim_text),
        ]
    )
    return hashlib.sha256(material.encode("utf-8")).hexdigest()


def _canonical_json_payload(payload: dict[str, Any]) -> str:
    return json.dumps(payload, ensure_ascii=True, separators=(",", ":"), sort_keys=True, default=str)


def _verify_openclaw_provenance_payload(
    *,
    provenance: dict[str, Any],
    payload: dict[str, Any],
) -> dict[str, Any]:
    schema = str(provenance.get("schema") or "").strip()
    signature_alg = str(provenance.get("signature_alg") or "").strip().lower()
    signature = str(provenance.get("signature") or "").strip().lower()
    mode = str(provenance.get("mode") or "").strip().lower()
    payload_sha256 = str(provenance.get("payload_sha256") or "").strip().lower()
    key_id = str(provenance.get("key_id") or "").strip() or None
    integration = str(provenance.get("integration") or "").strip().lower()

    canonical_payload = _canonical_json_payload(payload)
    computed_payload_sha256 = hashlib.sha256(canonical_payload.encode("utf-8")).hexdigest()
    payload_hash_match = bool(payload_sha256) and hmac.compare_digest(payload_sha256, computed_payload_sha256)

    if schema and schema != "synapse.openclaw.provenance.v1":
        return {
            "valid": False,
            "reason": "schema_mismatch",
            "schema": schema,
            "expected_schema": "synapse.openclaw.provenance.v1",
            "integration": integration or None,
            "mode": mode or None,
            "signature_alg": signature_alg or None,
            "key_id": key_id,
            "computed_payload_sha256": computed_payload_sha256,
            "provided_payload_sha256": payload_sha256 or None,
            "payload_hash_match": payload_hash_match,
            "signature_match": False,
        }

    if integration and integration != "openclaw":
        return {
            "valid": False,
            "reason": "integration_mismatch",
            "schema": schema or "synapse.openclaw.provenance.v1",
            "integration": integration,
            "expected_integration": "openclaw",
            "mode": mode or None,
            "signature_alg": signature_alg or None,
            "key_id": key_id,
            "computed_payload_sha256": computed_payload_sha256,
            "provided_payload_sha256": payload_sha256 or None,
            "payload_hash_match": payload_hash_match,
            "signature_match": False,
        }

    secret = str(os.getenv("SYNAPSE_OPENCLAW_PROVENANCE_SECRET") or os.getenv("SYNAPSE_PROVENANCE_SECRET") or "").strip()
    configured_key_id = (
        str(os.getenv("SYNAPSE_OPENCLAW_PROVENANCE_KEY_ID") or os.getenv("SYNAPSE_PROVENANCE_KEY_ID") or "").strip()
        or "openclaw-default"
    )
    key_id_match = key_id is None or not configured_key_id or key_id == configured_key_id

    if signature_alg == "hmac-sha256" or mode == "signed":
        if not secret:
            return {
                "valid": False,
                "reason": "secret_missing_for_signed_provenance",
                "schema": schema or "synapse.openclaw.provenance.v1",
                "integration": integration or "openclaw",
                "mode": mode or "signed",
                "signature_alg": signature_alg or "hmac-sha256",
                "key_id": key_id,
                "configured_key_id": configured_key_id,
                "key_id_match": key_id_match,
                "computed_payload_sha256": computed_payload_sha256,
                "provided_payload_sha256": payload_sha256 or None,
                "payload_hash_match": payload_hash_match,
                "signature_match": False,
            }
        expected_signature = hmac.new(secret.encode("utf-8"), canonical_payload.encode("utf-8"), hashlib.sha256).hexdigest()
        signature_match = bool(signature) and hmac.compare_digest(signature, expected_signature)
        valid = payload_hash_match and signature_match and key_id_match
        return {
            "valid": valid,
            "reason": "ok" if valid else ("key_id_mismatch" if not key_id_match else "signature_or_payload_mismatch"),
            "schema": schema or "synapse.openclaw.provenance.v1",
            "integration": integration or "openclaw",
            "mode": mode or "signed",
            "signature_alg": signature_alg or "hmac-sha256",
            "key_id": key_id,
            "configured_key_id": configured_key_id,
            "key_id_match": key_id_match,
            "computed_payload_sha256": computed_payload_sha256,
            "provided_payload_sha256": payload_sha256 or None,
            "payload_hash_match": payload_hash_match,
            "signature_match": signature_match,
            "expected_signature": expected_signature,
        }

    expected_signature = computed_payload_sha256
    signature_match = bool(signature) and hmac.compare_digest(signature, expected_signature)
    valid = payload_hash_match and signature_match
    return {
        "valid": valid,
        "reason": "ok" if valid else "signature_or_payload_mismatch",
        "schema": schema or "synapse.openclaw.provenance.v1",
        "integration": integration or "openclaw",
        "mode": mode or "digest_only",
        "signature_alg": signature_alg or "sha256",
        "key_id": key_id,
        "configured_key_id": configured_key_id,
        "key_id_match": key_id_match,
        "computed_payload_sha256": computed_payload_sha256,
        "provided_payload_sha256": payload_sha256 or None,
        "payload_hash_match": payload_hash_match,
        "signature_match": signature_match,
        "expected_signature": expected_signature,
    }


_TASK_ACTIVE_STATUSES = ("todo", "in_progress", "blocked")


