def _extract_bearer_token_header(authorization: str | None) -> str | None:
    value = str(authorization or "").strip()
    if not value:
        return None
    if value.lower().startswith("bearer "):
        token = value[7:].strip()
        return token or None
    return None


def _scim_token_hash(value: str) -> str:
    return hashlib.sha256(value.encode("utf-8")).hexdigest()


def _generate_scim_token_secret() -> str:
    raw = base64.urlsafe_b64encode(os.urandom(32)).decode("ascii").rstrip("=")
    return f"scim_{raw}"


def _mask_token_hash(value: str | None) -> str | None:
    text = str(value or "").strip()
    if not text:
        return None
    if len(text) <= 10:
        return "********"
    return f"{text[:6]}...{text[-4:]}"


def _normalize_scim_scopes(values: list[str] | None) -> list[str]:
    allowed = {"users:read", "users:write"}
    out: list[str] = []
    seen: set[str] = set()
    for raw in values or []:
        scope = str(raw or "").strip().lower()
        if scope not in allowed or scope in seen:
            continue
        seen.add(scope)
        out.append(scope)
    if not out:
        out = ["users:read", "users:write"]
    return out[:16]


def _resolve_scim_auth_context(conn, authorization: str | None) -> dict[str, Any]:
    if not _scim_api_tokens_table_exists(conn):
        raise HTTPException(status_code=503, detail={"code": "scim_not_configured"})
    token = _extract_bearer_token_header(authorization)
    if not token:
        raise HTTPException(status_code=401, detail={"code": "scim_token_required"})
    token_hash = _scim_token_hash(token)
    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT id::text, tenant_id::text, name, scopes, status, expires_at, metadata
            FROM scim_api_tokens
            WHERE token_hash = %s
            LIMIT 1
            """,
            (token_hash,),
        )
        row = cur.fetchone()
        if row is None:
            raise HTTPException(status_code=401, detail={"code": "scim_token_invalid"})
        status = str(row[4] or "active").strip().lower()
        expires_at = row[5]
        if status != "active":
            raise HTTPException(status_code=401, detail={"code": "scim_token_inactive", "status": status})
        if expires_at is not None and expires_at <= datetime.now(UTC):
            cur.execute(
                """
                UPDATE scim_api_tokens
                SET status = 'expired',
                    updated_at = NOW()
                WHERE id = %s::uuid
                """,
                (str(row[0]),),
            )
            raise HTTPException(status_code=401, detail={"code": "scim_token_expired"})
        cur.execute(
            """
            UPDATE scim_api_tokens
            SET last_used_at = NOW(),
                updated_at = NOW()
            WHERE id = %s::uuid
            """,
            (str(row[0]),),
        )
    return {
        "token_id": str(row[0]),
        "tenant_id": str(row[1]),
        "name": str(row[2] or ""),
        "scopes": _normalize_scim_scopes(row[3] if isinstance(row[3], list) else []),
        "status": status,
        "expires_at": expires_at.isoformat() if expires_at is not None else None,
        "metadata": dict(row[6] or {}) if isinstance(row[6], dict) else {},
    }


def _require_scim_scope(context: dict[str, Any], required_scope: str) -> None:
    scopes = [str(item).strip().lower() for item in (context.get("scopes") or []) if str(item).strip()]
    if required_scope in scopes:
        return
    raise HTTPException(
        status_code=403,
        detail={
            "code": "scim_scope_forbidden",
            "required_scope": required_scope,
            "token_scopes": scopes,
        },
    )


def _scim_pick_email(emails: list[ScimEmailValue] | None) -> str | None:
    if not emails:
        return None
    primary = next((item for item in emails if bool(item.primary)), None)
    target = primary or emails[0]
    value = str(target.value or "").strip()
    return value[:512] if value else None


def _scim_roles_from_payload(roles: list[ScimRoleValue] | None) -> list[str]:
    return _normalize_roles_list([item.value for item in (roles or []) if str(item.value or "").strip()])


def _parse_scim_user_filter(value: str | None) -> dict[str, str] | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    match = re.match(r'^(userName|externalId)\s+eq\s+"([^"]+)"$', raw, flags=re.IGNORECASE)
    if not match:
        raise HTTPException(status_code=422, detail={"code": "scim_filter_not_supported", "filter": raw})
    field = str(match.group(1) or "").strip()
    expected = str(match.group(2) or "").strip()
    if not expected:
        raise HTTPException(status_code=422, detail={"code": "scim_filter_not_supported", "filter": raw})
    return {"field": field, "value": expected}


def _scim_user_resource_from_row(row: tuple[Any, ...]) -> dict[str, Any]:
    user_id = str(row[0] or "")
    email = str(row[1]) if row[1] is not None else None
    display_name = str(row[2]) if row[2] is not None else user_id
    roles = _normalize_roles_list(row[3] if isinstance(row[3], list) else [])
    status_value = str(row[4] or "active").strip().lower()
    updated_at = row[5]
    external_id = str(row[6]) if row[6] is not None else None
    active = status_value == "active"
    payload: dict[str, Any] = {
        "schemas": ["urn:ietf:params:scim:schemas:core:2.0:User"],
        "id": user_id,
        "userName": user_id,
        "displayName": display_name,
        "active": active,
        "meta": {
            "resourceType": "User",
            "lastModified": updated_at.isoformat() if updated_at is not None else None,
        },
    }
    if external_id:
        payload["externalId"] = external_id
    if email:
        payload["emails"] = [{"value": email, "primary": True}]
    if roles:
        payload["roles"] = [{"value": role} for role in roles]
    return payload


def _upsert_scim_user(
    conn,
    *,
    tenant_id: str,
    payload: ScimUserWriteRequest,
    actor: str,
    override_user_id: str | None = None,
) -> dict[str, Any]:
    user_id = str(override_user_id or payload.userName).strip()
    if not user_id:
        raise HTTPException(status_code=422, detail={"code": "scim_username_required"})
    email = _scim_pick_email(payload.emails)
    display_name = str(payload.displayName or "").strip() or user_id
    roles = _scim_roles_from_payload(payload.roles)
    membership_status = "active" if bool(payload.active) else "disabled"
    external_id = str(payload.externalId or "").strip() or None
    with conn.cursor() as cur:
        cur.execute(
            """
            INSERT INTO tenant_memberships (
              id,
              tenant_id,
              user_id,
              email,
              display_name,
              roles,
              status,
              metadata,
              created_by,
              updated_by
            )
            VALUES (
              %s, %s::uuid, %s, %s, %s, %s, %s, %s, %s, %s
            )
            ON CONFLICT (tenant_id, user_id)
            DO UPDATE
              SET email = EXCLUDED.email,
                  display_name = EXCLUDED.display_name,
                  roles = EXCLUDED.roles,
                  status = EXCLUDED.status,
                  metadata = EXCLUDED.metadata,
                  updated_by = EXCLUDED.updated_by,
                  updated_at = NOW()
            RETURNING user_id, email, display_name, roles, status, updated_at
            """,
            (
                uuid4(),
                tenant_id,
                user_id,
                email,
                display_name,
                roles,
                membership_status,
                Jsonb(
                    {
                        "source": "scim",
                        "external_id": external_id,
                    }
                ),
                actor,
                actor,
            ),
        )
        membership_row = cur.fetchone()
        if _scim_directory_users_table_exists(conn):
            try:
                cur.execute(
                    """
                    INSERT INTO scim_directory_users (
                      id,
                      tenant_id,
                      external_id,
                      user_id,
                      email,
                      display_name,
                      active,
                      roles,
                      metadata,
                      raw_payload,
                      created_by,
                      updated_by
                    )
                    VALUES (
                      %s, %s::uuid, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s
                    )
                    ON CONFLICT (tenant_id, user_id)
                    DO UPDATE
                      SET external_id = EXCLUDED.external_id,
                          email = EXCLUDED.email,
                          display_name = EXCLUDED.display_name,
                          active = EXCLUDED.active,
                          roles = EXCLUDED.roles,
                          metadata = EXCLUDED.metadata,
                          raw_payload = EXCLUDED.raw_payload,
                          updated_by = EXCLUDED.updated_by,
                          updated_at = NOW()
                    """,
                    (
                        uuid4(),
                        tenant_id,
                        external_id,
                        user_id,
                        email,
                        display_name,
                        bool(payload.active),
                        roles,
                        Jsonb({"source": "scim"}),
                        Jsonb(payload.model_dump(mode="json")),
                        actor,
                        actor,
                    ),
                )
            except Exception as exc:
                raise HTTPException(status_code=409, detail={"code": "scim_external_id_conflict", "message": str(exc)}) from exc

        external_id_row_value = external_id
        if _scim_directory_users_table_exists(conn):
            cur.execute(
                """
                SELECT external_id
                FROM scim_directory_users
                WHERE tenant_id = %s::uuid
                  AND user_id = %s
                LIMIT 1
                """,
                (tenant_id, user_id),
            )
            external_row = cur.fetchone()
            if external_row is not None and external_row[0] is not None:
                external_id_row_value = str(external_row[0])
    return _scim_user_resource_from_row(
        (
            membership_row[0],
            membership_row[1],
            membership_row[2],
            membership_row[3],
            membership_row[4],
            membership_row[5],
            external_id_row_value,
        )
    )


def _normalize_source_system(value: Any, *, default: str = "unknown") -> str:
    text = str(value or "").strip().lower()
    text = re.sub(r"[^a-z0-9_./:-]+", "_", text)
    text = re.sub(r"_+", "_", text).strip("_")
    if not text:
        return default
    return text[:128]


def _normalize_backfill_ingest_lane(value: Any, *, default: str = "event") -> str:
    lane = str(value or "").strip().lower()
    if lane not in {"event", "knowledge"}:
        lane = str(default or "event").strip().lower()
    if lane not in {"event", "knowledge"}:
        return "event"
    return lane


def _normalize_source_system_list(value: Any) -> list[str]:
    if not isinstance(value, list):
        return []
    out: list[str] = []
    seen: set[str] = set()
    for item in value:
        source = _normalize_source_system(item, default="")
        if not source or source in seen:
            continue
        seen.add(source)
        out.append(source)
    return out


def _normalize_source_system_csv(value: Any) -> list[str]:
    if not isinstance(value, str):
        return []
    parts = [item for item in value.split(",")]
    return _normalize_source_system_list(parts)


def _normalize_namespace(value: Any, *, default: str = "") -> str:
    text = str(value or "").strip().lower()
    text = re.sub(r"[^a-z0-9_./:-]+", "_", text)
    text = re.sub(r"_+", "_", text).strip("_")
    if not text:
        return default
    return text[:128]


def _normalize_namespace_list(value: Any) -> list[str]:
    if not isinstance(value, list):
        return []
    out: list[str] = []
    seen: set[str] = set()
    for item in value:
        namespace = _normalize_namespace(item, default="")
        if not namespace or namespace in seen:
            continue
        seen.add(namespace)
        out.append(namespace)
    return out


def _normalize_namespace_csv(value: Any) -> list[str]:
    if not isinstance(value, str):
        return []
    parts = [item for item in value.split(",")]
    return _normalize_namespace_list(parts)


def _normalize_source_ownership_domain(value: Any, *, default: str = "runtime_memory") -> str:
    text = str(value or "").strip().lower()
    if text not in _SOURCE_OWNERSHIP_DOMAINS:
        return default
    return text


def _load_source_ownership_policies(conn, project_id: str) -> dict[str, dict[str, Any]]:
    if not _source_ownership_table_exists(conn):
        return {}
    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT domain, write_master, allowed_source_systems, enforcement_mode, metadata, updated_by, created_at, updated_at
            FROM source_ownership_policies
            WHERE project_id = %s
            ORDER BY domain ASC
            """,
            (project_id,),
        )
        rows = cur.fetchall() or []
    out: dict[str, dict[str, Any]] = {}
    for row in rows:
        domain = _normalize_source_ownership_domain(row[0], default="")
        if not domain:
            continue
        write_master = _normalize_source_system(row[1], default="unknown")
        allowed = _normalize_source_system_list(row[2] if isinstance(row[2], list) else [])
        if write_master and write_master not in allowed:
            allowed.append(write_master)
        enforcement_mode = str(row[3] or "enforce").strip().lower()
        if enforcement_mode not in {"off", "advisory", "enforce"}:
            enforcement_mode = "enforce"
        out[domain] = {
            "domain": domain,
            "write_master": write_master,
            "allowed_source_systems": allowed,
            "enforcement_mode": enforcement_mode,
            "metadata": dict(row[4] or {}) if isinstance(row[4], dict) else {},
            "updated_by": str(row[5]) if row[5] is not None else None,
            "created_at": row[6].isoformat() if row[6] is not None else None,
            "updated_at": row[7].isoformat() if row[7] is not None else None,
        }
    return out


def _extract_source_system_from_payload(payload: Any, *, fallback: str | None = None) -> str:
    if isinstance(payload, dict):
        direct = payload.get("source_system") or payload.get("_source_system")
        if direct is not None:
            return _normalize_source_system(direct, default=_normalize_source_system(fallback))
        meta = payload.get("metadata")
        if isinstance(meta, dict):
            source = meta.get("source_system") or meta.get("source")
            if source is not None:
                return _normalize_source_system(source, default=_normalize_source_system(fallback))
        backfill = payload.get("backfill")
        if isinstance(backfill, dict):
            source = backfill.get("source_system")
            if source is not None:
                return _normalize_source_system(source, default=_normalize_source_system(fallback))
    return _normalize_source_system(fallback)


def _resolve_request_source_system(request: Request | None, *, fallback: str | None = None) -> str:
    if request is None:
        return _normalize_source_system(fallback)
    for header_name in ("X-Synapse-Source-System", "X-Source-System"):
        value = request.headers.get(header_name)
        if value is not None and str(value).strip():
            return _normalize_source_system(value, default=_normalize_source_system(fallback))
    return _normalize_source_system(fallback)


def _enforce_source_ownership_write(
    *,
    policies_by_domain: dict[str, dict[str, Any]],
    project_id: str,
    domain: str,
    source_system: str,
    endpoint: str,
) -> dict[str, Any]:
    normalized_domain = _normalize_source_ownership_domain(domain)
    source = _normalize_source_system(source_system)
    policy = policies_by_domain.get(normalized_domain)
    if not policy:
        return {
            "status": "allow",
            "project_id": project_id,
            "domain": normalized_domain,
            "source_system": source,
            "reason": "policy_not_configured",
        }
    allowed_sources = _normalize_source_system_list(policy.get("allowed_source_systems"))
    write_master = _normalize_source_system(policy.get("write_master"), default="unknown")
    if write_master not in allowed_sources:
        allowed_sources.append(write_master)
    enforcement_mode = str(policy.get("enforcement_mode") or "enforce").strip().lower()
    if enforcement_mode not in {"off", "advisory", "enforce"}:
        enforcement_mode = "enforce"
    allowed = source in allowed_sources
    if allowed or enforcement_mode == "off":
        return {
            "status": "allow",
            "project_id": project_id,
            "domain": normalized_domain,
            "source_system": source,
            "write_master": write_master,
            "allowed_source_systems": allowed_sources,
            "enforcement_mode": enforcement_mode,
        }
    if enforcement_mode == "advisory":
        return {
            "status": "advisory",
            "project_id": project_id,
            "domain": normalized_domain,
            "source_system": source,
            "write_master": write_master,
            "allowed_source_systems": allowed_sources,
            "enforcement_mode": enforcement_mode,
            "reason": "source_not_in_allowed_list",
            "endpoint": endpoint,
        }
    raise HTTPException(
        status_code=403,
        detail={
            "error": "source_ownership_denied",
            "project_id": project_id,
            "domain": normalized_domain,
            "source_system": source,
            "write_master": write_master,
            "allowed_source_systems": allowed_sources,
            "enforcement_mode": enforcement_mode,
            "endpoint": endpoint,
        },
    )


def _public_table_exists(conn, table_name: str) -> bool:
    global _PUBLIC_TABLE_EXISTS_CACHE
    normalized = str(table_name or "").strip().lower()
    if not normalized:
        return False
    cached = _PUBLIC_TABLE_EXISTS_CACHE.get(normalized)
    if cached is not None:
        return cached
    with conn.cursor() as cur:
        cur.execute("SELECT to_regclass(%s)", (f"public.{normalized}",))
        row = cur.fetchone()
        exists = bool(row and row[0] is not None)
    _PUBLIC_TABLE_EXISTS_CACHE[normalized] = exists
    return exists


def _adoption_project_resets_table_exists(conn) -> bool:
    global _ADOPTION_PROJECT_RESETS_TABLE_EXISTS
    if _ADOPTION_PROJECT_RESETS_TABLE_EXISTS is True:
        return True
    exists = _public_table_exists(conn, "adoption_project_resets")
    if exists:
        _ADOPTION_PROJECT_RESETS_TABLE_EXISTS = True
    return exists


