def _normalize_adoption_project_reset_scopes(value: Any) -> list[str]:
    requested = value if isinstance(value, list) else []
    out: list[str] = []
    seen: set[str] = set()
    valid_scopes = set(_ADOPTION_PROJECT_RESET_SCOPE_ORDER)
    for item in requested:
        scope = str(item or "").strip().lower()
        if not scope or scope not in valid_scopes or scope in seen:
            continue
        out.append(scope)
        seen.add(scope)
    if not out:
        out = list(_ADOPTION_PROJECT_RESET_DEFAULT_SCOPES)
        seen = set(out)
    changed = True
    while changed:
        changed = False
        for scope in list(out):
            for dependency in _ADOPTION_PROJECT_RESET_SCOPE_DEPENDENCIES.get(scope, ()):
                if dependency in valid_scopes and dependency not in seen:
                    out.append(dependency)
                    seen.add(dependency)
                    changed = True
    order = {scope: idx for idx, scope in enumerate(_ADOPTION_PROJECT_RESET_SCOPE_ORDER)}
    out.sort(key=lambda scope: order.get(scope, 999))
    return out


def _collect_adoption_project_reset_preview(conn, *, project_id: str, scopes: list[str]) -> dict[str, Any]:
    plan_by_scope = _adoption_project_reset_scope_plan()
    preview_scopes: list[dict[str, Any]] = []
    totals: dict[str, int] = {}
    with conn.cursor() as cur:
        for scope in scopes:
            operations = plan_by_scope.get(scope, [])
            scope_total = 0
            rows: list[dict[str, Any]] = []
            for operation in operations:
                table_key = str(operation.get("table_key") or "unknown")
                required_tables = [str(item) for item in (operation.get("required_tables") or []) if str(item).strip()]
                available = bool(required_tables) and all(_public_table_exists(conn, name) for name in required_tables)
                count_value = 0
                if available:
                    cur.execute(str(operation["count_sql"]), (project_id,))
                    count_row = cur.fetchone()
                    count_value = int((count_row[0] if count_row else 0) or 0)
                rows.append(
                    {
                        "table": table_key,
                        "available": available,
                        "rows": count_value,
                    }
                )
                scope_total += count_value
                totals[table_key] = int(totals.get(table_key, 0)) + count_value
            preview_scopes.append({"scope": scope, "rows_total": scope_total, "tables": rows})
    return {
        "scopes": preview_scopes,
        "totals": {
            "rows_total": int(sum(item["rows_total"] for item in preview_scopes)),
            "tables": totals,
        },
    }


def _apply_adoption_project_reset(conn, *, project_id: str, scopes: list[str]) -> dict[str, int]:
    plan_by_scope = _adoption_project_reset_scope_plan()
    deleted: dict[str, int] = {}
    with conn.cursor() as cur:
        for scope in scopes:
            for operation in plan_by_scope.get(scope, []):
                table_key = str(operation.get("table_key") or "unknown")
                required_tables = [str(item) for item in (operation.get("required_tables") or []) if str(item).strip()]
                available = bool(required_tables) and all(_public_table_exists(conn, name) for name in required_tables)
                if not available:
                    continue
                cur.execute(str(operation["delete_sql"]), (project_id,))
                deleted[table_key] = int(deleted.get(table_key, 0)) + int(cur.rowcount or 0)
    return deleted


def _insert_adoption_project_reset_audit(
    conn,
    *,
    reset_id: UUID,
    project_id: str,
    requested_by: str,
    reason: str | None,
    scopes: list[str],
    dry_run: bool,
    status: str,
    rows_preview: dict[str, Any],
    rows_deleted: dict[str, Any],
    error_message: str | None = None,
) -> None:
    with conn.cursor() as cur:
        cur.execute(
            """
            INSERT INTO adoption_project_resets (
              id,
              project_id,
              requested_by,
              reason,
              scopes,
              dry_run,
              status,
              rows_preview,
              rows_deleted,
              error_message,
              created_at
            )
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, NOW())
            """,
            (
                reset_id,
                project_id,
                requested_by,
                reason,
                Jsonb(scopes),
                bool(dry_run),
                status,
                Jsonb(rows_preview),
                Jsonb(rows_deleted),
                error_message,
            ),
        )


def _normalize_adoption_bootstrap_profile(value: Any) -> str:
    profile = str(value or "").strip().lower()
    if profile in _ADOPTION_BOOTSTRAP_PROFILE_ORDER:
        return profile
    return _ADOPTION_BOOTSTRAP_PROFILE_ORDER[0]


def _build_adoption_bootstrap_profile_target_config(
    *,
    profile: str,
    current_config: dict[str, Any],
) -> dict[str, Any]:
    normalized_profile = _normalize_adoption_bootstrap_profile(profile)
    current = current_config if isinstance(current_config, dict) else {}
    target = dict(current)
    routing_current = _normalize_gatekeeper_routing_policy(current.get("routing_policy"))
    routing_target = dict(routing_current)
    routing_target.update(_ADOPTION_BOOTSTRAP_PROFILE_ROUTING_OVERRIDES.get(normalized_profile, {}))
    target.update(_ADOPTION_BOOTSTRAP_PROFILE_CONFIG_OVERRIDES.get(normalized_profile, {}))
    target["routing_policy"] = routing_target
    return target


def _build_adoption_bootstrap_profile_diff(
    *,
    current_config: dict[str, Any],
    target_config: dict[str, Any],
) -> dict[str, Any]:
    current = current_config if isinstance(current_config, dict) else {}
    target = target_config if isinstance(target_config, dict) else {}
    top_level_keys = [
        "min_sources_for_golden",
        "conflict_free_days",
        "min_score_for_golden",
        "publish_mode_default",
        "auto_publish_min_score",
        "auto_publish_min_sources",
        "auto_publish_require_golden",
        "auto_publish_allow_conflicts",
    ]
    top_level: dict[str, dict[str, Any]] = {}
    for key in top_level_keys:
        old = current.get(key)
        new = target.get(key)
        if old != new:
            top_level[key] = {"current": old, "target": new}

    routing_current = _normalize_gatekeeper_routing_policy(current.get("routing_policy"))
    routing_target = _normalize_gatekeeper_routing_policy(target.get("routing_policy"))
    routing_keys = [
        "require_multi_source_for_wiki",
        "min_sources_for_wiki_candidate",
        "min_evidence_for_wiki_candidate",
        "min_durable_signal_hits",
        "min_durable_signal_hits_for_backfill",
        "backfill_requires_policy_signal",
        "allow_policy_or_incident_override",
    ]
    routing: dict[str, dict[str, Any]] = {}
    for key in routing_keys:
        old = routing_current.get(key)
        new = routing_target.get(key)
        if old != new:
            routing[key] = {"current": old, "target": new}

    return {
        "top_level": top_level,
        "routing_policy": routing,
        "changed_keys": {
            "top_level": sorted(top_level.keys()),
            "routing_policy": sorted(routing.keys()),
        },
    }


def _adoption_bootstrap_profile_gatekeeper_excerpt(config: dict[str, Any]) -> dict[str, Any]:
    routing = _normalize_gatekeeper_routing_policy(config.get("routing_policy"))
    return {
        "min_sources_for_golden": config.get("min_sources_for_golden"),
        "conflict_free_days": config.get("conflict_free_days"),
        "min_score_for_golden": config.get("min_score_for_golden"),
        "publish_mode_default": config.get("publish_mode_default"),
        "auto_publish_min_score": config.get("auto_publish_min_score"),
        "auto_publish_min_sources": config.get("auto_publish_min_sources"),
        "auto_publish_require_golden": config.get("auto_publish_require_golden"),
        "auto_publish_allow_conflicts": config.get("auto_publish_allow_conflicts"),
        "routing_policy": {
            "require_multi_source_for_wiki": routing.get("require_multi_source_for_wiki"),
            "min_sources_for_wiki_candidate": routing.get("min_sources_for_wiki_candidate"),
            "min_evidence_for_wiki_candidate": routing.get("min_evidence_for_wiki_candidate"),
            "min_durable_signal_hits": routing.get("min_durable_signal_hits"),
            "min_durable_signal_hits_for_backfill": routing.get("min_durable_signal_hits_for_backfill"),
            "backfill_requires_policy_signal": routing.get("backfill_requires_policy_signal"),
            "allow_policy_or_incident_override": routing.get("allow_policy_or_incident_override"),
        },
    }


def _coerce_int(value: Any, default: int) -> int:
    try:
        if isinstance(value, bool):
            return default
        if isinstance(value, int):
            return value
        if isinstance(value, float):
            return int(value)
        if isinstance(value, str):
            text = value.strip()
            if text:
                return int(float(text))
    except Exception:
        return default
    return default


def _coerce_float(value: Any, default: float) -> float:
    try:
        if isinstance(value, bool):
            return default
        if isinstance(value, (int, float)):
            return float(value)
        if isinstance(value, str):
            text = value.strip()
            if text:
                return float(text)
    except Exception:
        return default
    return default


def _coerce_bool(value: Any, default: bool) -> bool:
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    if isinstance(value, str):
        text = value.strip().lower()
        if text in {"1", "true", "yes", "y", "on"}:
            return True
        if text in {"0", "false", "no", "n", "off"}:
            return False
    return default


def _normalize_publish_mode(value: Any, *, default: str = "auto_publish") -> str:
    mode = str(value or "").strip().lower()
    if mode not in {"human_required", "conditional", "auto_publish"}:
        return default
    return mode


def _normalize_publish_mode_map(value: Any) -> dict[str, str]:
    if not isinstance(value, dict):
        return {}
    out: dict[str, str] = {}
    for raw_key, raw_mode in value.items():
        key = str(raw_key or "").strip().lower()
        if not key:
            continue
        out[key[:64]] = _normalize_publish_mode(raw_mode)
    return out


def _normalize_policy_keyword_list(value: Any, *, fallback: list[str], limit: int = 64) -> list[str]:
    if not isinstance(value, list):
        return list(fallback)
    out: list[str] = []
    seen: set[str] = set()
    for item in value:
        text = unicodedata.normalize("NFKC", str(item or "")).strip().lower()
        text = re.sub(r"\s+", " ", text)
        if not text:
            continue
        if len(text) > 96:
            text = text[:96]
        if text in seen:
            continue
        seen.add(text)
        out.append(text)
        if len(out) >= limit:
            break
    if not out:
        return list(fallback)
    return out


def _normalize_timezone_name(value: Any, *, default: str = "UTC") -> str:
    timezone_name = str(value or "").strip()
    if not timezone_name:
        return default
    try:
        ZoneInfo(timezone_name)
    except ZoneInfoNotFoundError:
        return default
    return timezone_name


def _normalize_gatekeeper_routing_policy(value: Any) -> dict[str, Any]:
    base = dict(_DEFAULT_GATEKEEPER_ROUTING_POLICY)
    if not isinstance(value, dict):
        return base
    normalized = dict(base)
    normalized["blocked_category_keywords"] = _normalize_policy_keyword_list(
        value.get("blocked_category_keywords"),
        fallback=list(base["blocked_category_keywords"]),
    )
    normalized["blocked_source_system_keywords"] = _normalize_policy_keyword_list(
        value.get("blocked_source_system_keywords"),
        fallback=list(base["blocked_source_system_keywords"]),
    )
    normalized["blocked_source_type_keywords"] = _normalize_policy_keyword_list(
        value.get("blocked_source_type_keywords"),
        fallback=list(base["blocked_source_type_keywords"]),
    )
    normalized["blocked_entity_keywords"] = _normalize_policy_keyword_list(
        value.get("blocked_entity_keywords"),
        fallback=list(base["blocked_entity_keywords"]),
    )
    normalized["blocked_source_id_keywords"] = _normalize_policy_keyword_list(
        value.get("blocked_source_id_keywords"),
        fallback=list(base["blocked_source_id_keywords"]),
    )
    normalized["event_stream_token_keywords"] = _normalize_policy_keyword_list(
        value.get("event_stream_token_keywords"),
        fallback=list(base["event_stream_token_keywords"]),
    )
    normalized["durable_signal_keywords"] = _normalize_policy_keyword_list(
        value.get("durable_signal_keywords"),
        fallback=list(base["durable_signal_keywords"]),
    )
    normalized["auto_publish_risk_keywords_high"] = _normalize_policy_keyword_list(
        value.get("auto_publish_risk_keywords_high"),
        fallback=list(base["auto_publish_risk_keywords_high"]),
    )
    normalized["auto_publish_risk_keywords_medium"] = _normalize_policy_keyword_list(
        value.get("auto_publish_risk_keywords_medium"),
        fallback=list(base["auto_publish_risk_keywords_medium"]),
    )
    normalized["auto_publish_force_human_required_levels"] = _normalize_policy_keyword_list(
        value.get("auto_publish_force_human_required_levels"),
        fallback=list(base["auto_publish_force_human_required_levels"]),
        limit=5,
    )
    normalized["process_simulation_require_for_page_types"] = _normalize_policy_keyword_list(
        value.get("process_simulation_require_for_page_types"),
        fallback=list(base["process_simulation_require_for_page_types"]),
        limit=10,
    )
    normalized["process_simulation_block_levels"] = _normalize_policy_keyword_list(
        value.get("process_simulation_block_levels"),
        fallback=list(base["process_simulation_block_levels"]),
        limit=5,
    )
    normalized["process_simulation_sample_limit"] = max(
        1,
        min(50, _coerce_int(value.get("process_simulation_sample_limit"), int(base["process_simulation_sample_limit"]))),
    )
    normalized["publish_mode_by_assertion_class"] = _normalize_publish_mode_map(
        value.get("publish_mode_by_assertion_class")
    )
    if not normalized["publish_mode_by_assertion_class"]:
        normalized["publish_mode_by_assertion_class"] = dict(base["publish_mode_by_assertion_class"])
    normalized["event_stream_min_numeric_token_ratio"] = max(
        0.0,
        min(1.0, _coerce_float(value.get("event_stream_min_numeric_token_ratio"), 0.45)),
    )
    normalized["event_stream_min_token_hits"] = max(
        1,
        min(20, _coerce_int(value.get("event_stream_min_token_hits"), 2)),
    )
    normalized["event_stream_min_kv_hits"] = max(
        1,
        min(20, _coerce_int(value.get("event_stream_min_kv_hits"), 2)),
    )
    normalized["min_durable_signal_hits"] = max(
        0,
        min(20, _coerce_int(value.get("min_durable_signal_hits"), 1)),
    )
    normalized["min_durable_signal_hits_for_backfill"] = max(
        0,
        min(20, _coerce_int(value.get("min_durable_signal_hits_for_backfill"), 1)),
    )
    normalized["retrieval_feedback_window_days"] = max(
        1,
        min(365, _coerce_int(value.get("retrieval_feedback_window_days"), 30)),
    )
    normalized["retrieval_feedback_min_events"] = max(
        1,
        min(200, _coerce_int(value.get("retrieval_feedback_min_events"), 3)),
    )
    normalized["retrieval_feedback_block_negative_ratio"] = max(
        0.0,
        min(1.0, _coerce_float(value.get("retrieval_feedback_block_negative_ratio"), 0.7)),
    )
    normalized["retrieval_feedback_block_balance"] = max(
        1,
        min(500, _coerce_int(value.get("retrieval_feedback_block_balance"), 2)),
    )
    normalized["require_multi_source_for_wiki"] = _coerce_bool(value.get("require_multi_source_for_wiki"), True)
    normalized["min_sources_for_wiki_candidate"] = max(
        1,
        min(20, _coerce_int(value.get("min_sources_for_wiki_candidate"), 2)),
    )
    normalized["min_evidence_for_wiki_candidate"] = max(
        1,
        min(20, _coerce_int(value.get("min_evidence_for_wiki_candidate"), 2)),
    )
    normalized["allow_policy_or_incident_override"] = _coerce_bool(
        value.get("allow_policy_or_incident_override"),
        True,
    )
    normalized["backfill_requires_policy_signal"] = _coerce_bool(
        value.get("backfill_requires_policy_signal"),
        True,
    )
    llm_mode_raw = str(
        value.get("backfill_llm_classifier_mode", base["backfill_llm_classifier_mode"]) or ""
    ).strip().lower()
    normalized["backfill_llm_classifier_mode"] = (
        llm_mode_raw if llm_mode_raw in {"off", "assist", "enforce"} else str(base["backfill_llm_classifier_mode"])
    )
    normalized["backfill_llm_classifier_min_confidence"] = max(
        0.0,
        min(
            1.0,
            _coerce_float(
                value.get(
                    "backfill_llm_classifier_min_confidence",
                    base["backfill_llm_classifier_min_confidence"],
                ),
                float(base["backfill_llm_classifier_min_confidence"]),
            ),
        ),
    )
    normalized["backfill_llm_classifier_ambiguous_only"] = _coerce_bool(
        value.get("backfill_llm_classifier_ambiguous_only"),
        bool(base["backfill_llm_classifier_ambiguous_only"]),
    )
    model_value = str(value.get("backfill_llm_classifier_model") or "").strip()
    normalized["backfill_llm_classifier_model"] = model_value[:128] if model_value else ""
    normalized["agent_worklog_timezone"] = _normalize_timezone_name(
        value.get("agent_worklog_timezone"),
        default=str(base["agent_worklog_timezone"]),
    )
    normalized["agent_worklog_schedule_hour_local"] = max(
        0,
        min(23, _coerce_int(value.get("agent_worklog_schedule_hour_local"), int(base["agent_worklog_schedule_hour_local"]))),
    )
    normalized["agent_worklog_schedule_minute_local"] = max(
        0,
        min(59, _coerce_int(value.get("agent_worklog_schedule_minute_local"), int(base["agent_worklog_schedule_minute_local"]))),
    )
    normalized["agent_worklog_min_activity_score"] = max(
        0,
        min(1000, _coerce_int(value.get("agent_worklog_min_activity_score"), int(base["agent_worklog_min_activity_score"]))),
    )
    normalized["agent_worklog_include_idle_days"] = _coerce_bool(
        value.get("agent_worklog_include_idle_days"),
        bool(base["agent_worklog_include_idle_days"]),
    )
    normalized["agent_worklog_realtime_enabled"] = _coerce_bool(
        value.get("agent_worklog_realtime_enabled"),
        bool(base["agent_worklog_realtime_enabled"]),
    )
    normalized["agent_worklog_realtime_lookback_minutes"] = max(
        1,
        min(
            240,
            _coerce_int(
                value.get("agent_worklog_realtime_lookback_minutes"),
                int(base["agent_worklog_realtime_lookback_minutes"]),
            ),
        ),
    )
    return normalized


def _resolve_publish_mode_for_category(
    *,
    default_mode: str,
    category_map: dict[str, str],
    assertion_class_map: dict[str, str] | None,
    assertion_class: str | None,
    category: str | None,
    page_type: str | None,
) -> str:
    normalized_assertion_class = str(assertion_class or "").strip().lower()
    class_map = assertion_class_map if isinstance(assertion_class_map, dict) else {}
    if normalized_assertion_class and normalized_assertion_class in class_map:
        return _normalize_publish_mode(class_map.get(normalized_assertion_class), default=default_mode)
    normalized_category = str(category or "").strip().lower()
    normalized_page_type = str(page_type or "").strip().lower()
    for key in (
        normalized_category,
        normalized_page_type,
        normalized_category.split("/")[0] if normalized_category else "",
        normalized_page_type.split("/")[0] if normalized_page_type else "",
    ):
        if key and key in category_map:
            return _normalize_publish_mode(category_map.get(key), default=default_mode)
    return _normalize_publish_mode(default_mode)


def _match_policy_keywords(*, text: str, keywords: list[str]) -> list[str]:
    haystack = str(text or "").strip().lower()
    if not haystack:
        return []
    hits: list[str] = []
    for keyword in keywords:
        probe = str(keyword or "").strip().lower()
        if not probe:
            continue
        if probe in haystack:
            hits.append(probe)
        if len(hits) >= 12:
            break
    return hits


def _classify_auto_publish_risk(
    *,
    assertion_class: str | None,
    category: str | None,
    page_type: str | None,
    claim_text: str | None,
    routing_policy: dict[str, Any] | None,
) -> dict[str, Any]:
    policy = routing_policy if isinstance(routing_policy, dict) else {}
    high_keywords = [
        str(item).strip().lower()
        for item in (policy.get("auto_publish_risk_keywords_high") or [])
        if str(item).strip()
    ]
    medium_keywords = [
        str(item).strip().lower()
        for item in (policy.get("auto_publish_risk_keywords_medium") or [])
        if str(item).strip()
    ]
    force_levels = [
        str(item).strip().lower()
        for item in (policy.get("auto_publish_force_human_required_levels") or ["high"])
        if str(item).strip()
    ]

    normalized_assertion_class = str(assertion_class or "").strip().lower()
    normalized_category = str(category or "").strip().lower()
    normalized_page_type = str(page_type or "").strip().lower()
    normalized_claim_text = str(claim_text or "").strip().lower()
    haystack = " ".join(
        item
        for item in (
            normalized_assertion_class,
            normalized_category,
            normalized_page_type,
            normalized_claim_text,
        )
        if item
    )

    high_hits = _match_policy_keywords(text=haystack, keywords=high_keywords)
    medium_hits = _match_policy_keywords(text=haystack, keywords=medium_keywords)
    score = 0
    if normalized_assertion_class == "policy":
        score += 2
    if normalized_assertion_class == "incident":
        score += 1
    score += 2 * len(high_hits)
    score += len(medium_hits)

    level = "low"
    if score >= 3:
        level = "high"
    elif score >= 1:
        level = "medium"

    force_human = level in set(force_levels)
    return {
        "level": level,
        "score": score,
        "high_hits": high_hits,
        "medium_hits": medium_hits,
        "force_human_required": force_human,
    }


def _extract_text_terms(text: str, *, limit: int = 40) -> list[str]:
    tokens = re.findall(r"[a-zа-я0-9_]+", str(text or "").strip().lower())
    out: list[str] = []
    seen: set[str] = set()
    for token in tokens:
        if len(token) < 3:
            continue
        if token in seen:
            continue
        seen.add(token)
        out.append(token)
        if len(out) >= limit:
            break
    return out


def _load_project_routing_policy(conn, *, project_id: str) -> dict[str, Any]:
    default_policy = _normalize_gatekeeper_routing_policy(None)
    has_routing_policy_column = _gatekeeper_config_has_routing_policy_column(conn)
    if not has_routing_policy_column:
        return default_policy
    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT routing_policy
            FROM gatekeeper_project_configs
            WHERE project_id = %s
            LIMIT 1
            """,
            (project_id,),
        )
        row = cur.fetchone()
    if row is None:
        return default_policy
    return _normalize_gatekeeper_routing_policy(row[0] if len(row) > 0 else None)


def _classify_process_simulation_risk(
    *,
    proposed_markdown: str,
    changed_terms: list[str],
    removed_terms: list[str],
    impacted_pages_total: int,
    pending_process_drafts: int,
    open_process_conflicts: int,
    routing_policy: dict[str, Any] | None,
) -> dict[str, Any]:
    policy = routing_policy if isinstance(routing_policy, dict) else {}
    high_hits = _match_policy_keywords(
        text=proposed_markdown,
        keywords=[str(item) for item in (policy.get("auto_publish_risk_keywords_high") or [])],
    )
    medium_hits = _match_policy_keywords(
        text=proposed_markdown,
        keywords=[str(item) for item in (policy.get("auto_publish_risk_keywords_medium") or [])],
    )
    score = 0
    score += 2 * len(high_hits)
    score += len(medium_hits)
    if len(changed_terms) >= 20:
        score += 1
    if removed_terms:
        score += 1
    if impacted_pages_total >= 10:
        score += 2
    elif impacted_pages_total >= 4:
        score += 1
    if pending_process_drafts >= 20:
        score += 2
    elif pending_process_drafts >= 8:
        score += 1
    if open_process_conflicts > 0:
        score += 1

    level = "low"
    if score >= 6:
        level = "high"
    elif score >= 3:
        level = "medium"

    should_block_publish = bool(level == "high" or len(high_hits) > 0)
    suggested_mode = "human_required" if should_block_publish else ("conditional" if level == "medium" else "auto_publish")
    return {
        "level": level,
        "score": int(score),
        "high_risk_hits": high_hits,
        "medium_risk_hits": medium_hits,
        "should_block_publish": should_block_publish,
        "suggested_publish_mode": suggested_mode,
    }


def _build_wiki_onboarding_pack(
    conn,
    *,
    project_id: str,
    role: str | None,
    max_items_per_section: int,
    freshness_days: int,
) -> dict[str, Any]:
    normalized_role = str(role or "").strip().lower()
    section_limit = max(1, min(20, int(max_items_per_section)))
    freshness_days = max(1, min(90, int(freshness_days)))
    rows: list[dict[str, Any]] = []

    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT
              st.id::text,
              st.statement_text,
              st.section_key,
              st.created_at,
              p.title,
              p.slug,
              p.page_type,
              p.entity_key,
              p.updated_at,
              COALESCE(claim_meta.category, '')
            FROM wiki_statements st
            JOIN wiki_pages p ON p.id = st.page_id
            LEFT JOIN LATERAL (
              SELECT c.category
              FROM claims c
              WHERE c.project_id = st.project_id
                AND c.claim_fingerprint = st.claim_fingerprint
              ORDER BY c.updated_at DESC
              LIMIT 1
            ) claim_meta ON TRUE
            WHERE st.project_id = %s
              AND p.status = 'published'
              AND st.status = 'active'
              AND (st.valid_from IS NULL OR st.valid_from <= NOW())
              AND (st.valid_to IS NULL OR st.valid_to >= NOW())
              AND p.page_type IN ('process', 'policy', 'incident', 'general', 'operations')
            ORDER BY p.updated_at DESC, st.created_at DESC
            LIMIT 1000
            """,
            (project_id,),
        )
        for row in cur.fetchall() or []:
            statement_text = str(row[1] or "")
            title_text = str(row[4] or "")
            entity_text = str(row[7] or "")
            role_match = 0
            if normalized_role:
                haystack = f"{statement_text} {title_text} {entity_text}".lower()
                if normalized_role in haystack:
                    role_match = 1
            rows.append(
                {
                    "statement_id": row[0],
                    "statement_text": statement_text,
                    "section_key": str(row[2] or ""),
                    "created_at": row[3].isoformat() if row[3] is not None else None,
                    "page": {
                        "title": title_text,
                        "slug": str(row[5] or ""),
                        "page_type": str(row[6] or ""),
                        "entity_key": entity_text,
                        "updated_at": row[8].isoformat() if row[8] is not None else None,
                    },
                    "category": str(row[9] or "") or None,
                    "role_match": role_match,
                }
            )

    def _priority(item: dict[str, Any]) -> tuple[int, str]:
        created_at = str(item.get("created_at") or "")
        return (int(item.get("role_match") or 0), created_at)

    escalation_tokens = ("escalat", "tier", "handoff", "pager", "on-call", "эскалац")
    forbidden_tokens = ("must not", "forbidden", "prohibited", "do not", "never", "запрещ", "нельзя")
    fresh_cutoff = datetime.now(UTC) - timedelta(days=freshness_days)

    critical_playbooks: list[dict[str, Any]] = []
    escalation_rules: list[dict[str, Any]] = []
    forbidden_actions: list[dict[str, Any]] = []
    fresh_changes: list[dict[str, Any]] = []
    seen_statement_ids: set[str] = set()

    for item in sorted(rows, key=_priority, reverse=True):
        statement_id = str(item.get("statement_id") or "")
        if not statement_id or statement_id in seen_statement_ids:
            continue
        seen_statement_ids.add(statement_id)

        page = item.get("page") if isinstance(item.get("page"), dict) else {}
        page_type = str(page.get("page_type") or "").lower()
        section_key = str(item.get("section_key") or "").lower()
        text = str(item.get("statement_text") or "").lower()
        created_at_text = str(item.get("created_at") or "").strip()
        is_fresh = False
        if created_at_text:
            try:
                created_at = datetime.fromisoformat(created_at_text.replace("Z", "+00:00"))
                is_fresh = created_at >= fresh_cutoff
            except Exception:
                is_fresh = False

        if (
            len(critical_playbooks) < section_limit
            and page_type == "process"
            and section_key in {"triggers", "steps", "exceptions", "verification"}
        ):
            critical_playbooks.append(item)
        if (
            len(escalation_rules) < section_limit
            and (section_key == "escalation" or page_type == "incident" or any(token in text for token in escalation_tokens))
        ):
            escalation_rules.append(item)
        if (
            len(forbidden_actions) < section_limit
            and page_type in {"policy", "process"}
            and any(token in text for token in forbidden_tokens)
        ):
            forbidden_actions.append(item)
        if len(fresh_changes) < section_limit and is_fresh:
            fresh_changes.append(item)

        if (
            len(critical_playbooks) >= section_limit
            and len(escalation_rules) >= section_limit
            and len(forbidden_actions) >= section_limit
            and len(fresh_changes) >= section_limit
        ):
            break

    return {
        "project_id": project_id,
        "role": normalized_role or None,
        "freshness_days": freshness_days,
        "sections": {
            "critical_playbooks": critical_playbooks[:section_limit],
            "escalation_rules": escalation_rules[:section_limit],
            "forbidden_actions": forbidden_actions[:section_limit],
            "fresh_changes": fresh_changes[:section_limit],
        },
        "generated_at": datetime.now(UTC).isoformat(),
    }


def _run_wiki_process_simulation(
    conn,
    *,
    project_id: str,
    page_slug: str | None,
    proposed_markdown: str,
    baseline_markdown: str | None,
    sample_limit: int,
) -> dict[str, Any]:
    normalized_slug = (
        _normalize_wiki_slug(page_slug, page_slug)
        if isinstance(page_slug, str) and page_slug.strip()
        else None
    )
    proposed_markdown = str(proposed_markdown or "").strip()
    baseline_markdown = str(baseline_markdown or "").strip()
    sample_limit = max(1, min(50, int(sample_limit)))
    if not proposed_markdown:
        raise HTTPException(status_code=422, detail={"code": "proposed_markdown_required"})

    routing_policy = _load_project_routing_policy(conn, project_id=project_id)
    page_context: dict[str, Any] | None = None
    if normalized_slug:
        with conn.cursor() as cur:
            page_row = _resolve_wiki_page_row_by_slug_or_alias(
                cur,
                project_id=project_id,
                slug_or_alias=normalized_slug,
                for_update=False,
            )
            if page_row is not None:
                page_context = {
                    "id": str(page_row[0]),
                    "title": str(page_row[1] or ""),
                    "slug": str(page_row[2] or normalized_slug),
                    "entity_key": str(page_row[3] or "") or None,
                    "page_type": str(page_row[4] or "") or None,
                    "status": str(page_row[5] or "") or None,
                }
                if not baseline_markdown:
                    cur.execute(
                        """
                        SELECT markdown
                        FROM wiki_page_versions
                        WHERE page_id = %s::uuid
                        ORDER BY version DESC
                        LIMIT 1
                        """,
                        (str(page_row[0]),),
                    )
                    baseline_row = cur.fetchone()
                    baseline_markdown = str(baseline_row[0] or "").strip() if baseline_row else ""

    proposed_terms = _extract_text_terms(proposed_markdown, limit=50)
    baseline_terms = _extract_text_terms(baseline_markdown, limit=50)
    proposed_set = set(proposed_terms)
    baseline_set = set(baseline_terms)
    added_terms = sorted(proposed_set - baseline_set)
    removed_terms = sorted(baseline_set - proposed_set)
    changed_terms = sorted(set(added_terms + removed_terms))
    if not changed_terms:
        changed_terms = proposed_terms[:20]
    like_patterns = [f"%{term}%" for term in changed_terms[:20]]

    impacted_pages: list[dict[str, Any]] = []
    pending_process_drafts = 0
    open_process_conflicts = 0
    with conn.cursor() as cur:
        if like_patterns:
            cur.execute(
                """
                SELECT
                  p.slug,
                  p.title,
                  p.page_type,
                  p.updated_at,
                  COALESCE(
                    (
                      SELECT string_agg(lower(s.statement_text), ' ')
                      FROM (
                        SELECT statement_text
                        FROM wiki_statements s
                        WHERE s.page_id = p.id
                          AND s.status = 'active'
                        ORDER BY s.created_at DESC
                        LIMIT 20
                      ) s
                    ),
                    ''
                  ) AS corpus
                FROM wiki_pages p
                WHERE p.project_id = %s
                  AND p.status = 'published'
                  AND p.page_type IN ('process', 'policy', 'incident', 'operations')
                  AND (
                    lower(p.title) LIKE ANY(%s::text[])
                    OR lower(p.slug) LIKE ANY(%s::text[])
                    OR EXISTS (
                      SELECT 1
                      FROM wiki_statements st
                      WHERE st.page_id = p.id
                        AND st.status = 'active'
                        AND lower(st.statement_text) LIKE ANY(%s::text[])
                    )
                  )
                ORDER BY p.updated_at DESC
                LIMIT %s
                """,
                (project_id, like_patterns, like_patterns, like_patterns, sample_limit),
            )
            for row in cur.fetchall() or []:
                text_haystack = " ".join(
                    item
                    for item in (
                        str(row[0] or "").lower(),
                        str(row[1] or "").lower(),
                        str(row[4] or "").lower(),
                    )
                    if item
                )
                matched_terms = [term for term in changed_terms if term in text_haystack][:8]
                impacted_pages.append(
                    {
                        "slug": str(row[0] or ""),
                        "title": str(row[1] or ""),
                        "page_type": str(row[2] or ""),
                        "updated_at": row[3].isoformat() if row[3] is not None else None,
                        "matched_terms": matched_terms,
                    }
                )

        cur.execute(
            """
            SELECT COUNT(*)::bigint
            FROM wiki_draft_changes d
            JOIN wiki_pages p ON p.id = d.page_id
            WHERE d.project_id = %s
              AND d.status = 'pending_review'
              AND p.page_type IN ('process', 'policy', 'incident', 'operations')
            """,
            (project_id,),
        )
        pending_row = cur.fetchone()
        pending_process_drafts = int(pending_row[0] or 0) if pending_row else 0

        cur.execute(
            """
            SELECT COUNT(*)::bigint
            FROM wiki_conflicts wc
            JOIN wiki_pages p ON p.id = wc.page_id
            WHERE wc.project_id = %s
              AND wc.resolution_status = 'open'
              AND p.page_type IN ('process', 'policy', 'incident', 'operations')
            """,
            (project_id,),
        )
        conflict_row = cur.fetchone()
        open_process_conflicts = int(conflict_row[0] or 0) if conflict_row else 0

    risk = _classify_process_simulation_risk(
        proposed_markdown=proposed_markdown.lower(),
        changed_terms=changed_terms,
        removed_terms=removed_terms,
        impacted_pages_total=len(impacted_pages),
        pending_process_drafts=pending_process_drafts,
        open_process_conflicts=open_process_conflicts,
        routing_policy=routing_policy,
    )
    recommendation = (
        "Require human review before publish and prepare rollback note."
        if bool(risk.get("should_block_publish"))
        else "Safe for conditional/auto publish with monitoring."
    )
    return {
        "status": "ok",
        "project_id": project_id,
        "page": page_context,
        "diff": {
            "changed_terms_total": len(changed_terms),
            "added_terms": added_terms[:20],
            "removed_terms": removed_terms[:20],
        },
        "impact": {
            "candidate_pages_total": len(impacted_pages),
            "top_impacted_pages": impacted_pages,
            "pending_process_drafts": pending_process_drafts,
            "open_process_conflicts": open_process_conflicts,
        },
        "risk": risk,
        "recommendation": {
            "action": recommendation,
            "suggested_publish_mode": risk.get("suggested_publish_mode"),
            "rollback_hint": {
                "wiki_page_rollback_endpoint": "/v1/wiki/pages/{slug}/rollback",
                "gatekeeper_rollback_endpoint": "/v1/gatekeeper/config/rollback/preview",
            },
        },
        "generated_at": datetime.now(UTC).isoformat(),
    }


def _extract_source_diversity(features: dict[str, Any]) -> int:
    for key in ("source_diversity", "historical_source_count", "incoming_source_count"):
        value = features.get(key)
        try:
            if isinstance(value, bool):
                continue
            if isinstance(value, (int, float)):
                return max(0, int(value))
            if isinstance(value, str) and value.strip():
                return max(0, int(float(value.strip())))
        except Exception:
            continue
    return 0


def _extract_ticket_outcome_signal(claim_metadata: dict[str, Any] | None) -> dict[str, Any]:
    metadata = claim_metadata if isinstance(claim_metadata, dict) else {}
    operator_decision = metadata.get("operator_decision") if isinstance(metadata.get("operator_decision"), dict) else {}
    raw_ticket_ids = (
        metadata.get("linked_ticket_ids")
        or metadata.get("ticket_ids")
        or operator_decision.get("ticket_ids")
        or []
    )
    if not isinstance(raw_ticket_ids, list):
        raw_ticket_ids = [raw_ticket_ids]
    ticket_ids: list[str] = []
    for item in raw_ticket_ids:
        value = str(item or "").strip()
        if not value:
            continue
        if value in ticket_ids:
            continue
        ticket_ids.append(value)
        if len(ticket_ids) >= 20:
            break

    outcome = str(
        metadata.get("resolution_outcome")
        or metadata.get("outcome")
        or operator_decision.get("outcome")
        or ""
    ).strip().lower()
    positive_outcomes = {"resolved", "fixed", "completed", "success", "mitigated", "restored"}
    negative_outcomes = {"failed", "rejected", "escalated_unresolved", "regressed"}
    positive = outcome in positive_outcomes
    negative = outcome in negative_outcomes

    bonus = 0.0
    if ticket_ids:
        bonus += 0.05
    if positive:
        bonus += 0.08
    elif negative:
        bonus -= 0.05
    return {
        "ticket_ids": ticket_ids,
        "ticket_count": len(ticket_ids),
        "outcome": outcome or None,
        "positive_outcome": positive,
        "negative_outcome": negative,
        "score_bonus": round(float(bonus), 4),
    }


def _extract_assertion_class(features: dict[str, Any], *, category: str | None, page_type: str | None) -> str:
    value = str(features.get("assertion_class") or "").strip().lower()
    if value in {"policy", "process", "preference", "incident", "event", "fact"}:
        return value
    normalized_page_type = str(page_type or "").strip().lower()
    normalized_category = str(category or "").strip().lower()
    if normalized_page_type in {"access", "operations"}:
        return "policy"
    if normalized_page_type == "process":
        return "process"
    if normalized_page_type == "incident":
        return "incident"
    if normalized_page_type == "customer":
        return "preference"
    if any(token in normalized_category for token in ("incident", "error", "сбой", "инцидент")):
        return "incident"
    if any(token in normalized_category for token in ("customer", "client", "preference", "клиент", "предпочт")):
        return "preference"
    if any(token in normalized_category for token in ("policy", "rule", "process", "процесс", "правило")):
        if "process" in normalized_category or "процесс" in normalized_category:
            return "process"
        return "policy"
    return "fact"


def _load_retrieval_feedback_summary(
    conn,
    *,
    project_id: str,
    claim_ids: list[str],
    window_days: int,
) -> dict[str, dict[str, int | float]]:
    if not claim_ids or not _wiki_retrieval_feedback_table_exists(conn):
        return {}
    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT
              claim_id::text,
              SUM(CASE WHEN feedback = 'positive' THEN 1 ELSE 0 END) AS positive_count,
              SUM(CASE WHEN feedback = 'negative' THEN 1 ELSE 0 END) AS negative_count,
              SUM(CASE WHEN feedback = 'neutral' THEN 1 ELSE 0 END) AS neutral_count
            FROM wiki_retrieval_feedback
            WHERE project_id = %s
              AND claim_id = ANY(%s::uuid[])
              AND created_at >= NOW() - make_interval(days => %s)
            GROUP BY claim_id
            """,
            (project_id, claim_ids, int(window_days)),
        )
        rows = cur.fetchall() or []
    out: dict[str, dict[str, int | float]] = {}
    for row in rows:
        claim_id = str(row[0] or "").strip()
        if not claim_id:
            continue
        positive = int(row[1] or 0)
        negative = int(row[2] or 0)
        neutral = int(row[3] or 0)
        total = positive + negative + neutral
        negative_ratio = (float(negative) / float(total)) if total > 0 else 0.0
        out[claim_id] = {
            "positive": positive,
            "negative": negative,
            "neutral": neutral,
            "total": total,
            "negative_ratio": round(negative_ratio, 4),
            "negative_balance": negative - positive,
        }
    return out


def _extract_calibration_holdout_metrics(calibration_report: dict[str, Any] | None) -> dict[str, float | None]:
    report = calibration_report if isinstance(calibration_report, dict) else {}
    best = report.get("best_candidate")
    holdout = best.get("holdout_metrics") if isinstance(best, dict) else None
    if not isinstance(holdout, dict):
        holdout = report.get("holdout_metrics")
    if not isinstance(holdout, dict):
        holdout = {}
    by_tier = holdout.get("by_tier") if isinstance(holdout.get("by_tier"), dict) else {}
    golden = by_tier.get("golden_candidate") if isinstance(by_tier.get("golden_candidate"), dict) else {}
    accuracy = holdout.get("accuracy")
    macro_f1 = holdout.get("macro_f1")
    if isinstance(accuracy, bool):
        accuracy = None
    if isinstance(macro_f1, bool):
        macro_f1 = None
    accuracy_value = _coerce_float(accuracy, 0.0) if accuracy is not None else None
    macro_f1_value = _coerce_float(macro_f1, 0.0) if macro_f1 is not None else None
    golden_precision = golden.get("precision")
    if isinstance(golden_precision, bool):
        golden_precision = None
    golden_precision_value = _coerce_float(golden_precision, 0.0) if golden_precision is not None else None
    return {
        "accuracy": accuracy_value,
        "macro_f1": macro_f1_value,
        "golden_precision": golden_precision_value,
    }


def _normalize_threshold_list(values: list[float] | None, *, field_name: str) -> list[float]:
    if values is None:
        return []
    if len(values) > 40:
        raise HTTPException(status_code=422, detail=f"{field_name} length must be <= 40")
    normalized: list[float] = []
    for item in values:
        value = _coerce_float(item, 0.0)
        if value < 0.0 or value > 1.0:
            raise HTTPException(status_code=422, detail=f"{field_name} values must be in range [0, 1]")
        normalized.append(round(value, 4))
    return normalized


def _serialize_gatekeeper_calibration_schedule_row(row: Any) -> dict[str, Any]:
    return {
        "id": row[0],
        "project_id": row[1],
        "name": row[2],
        "enabled": bool(row[3]),
        "preset": row[4],
        "interval_hours": row[5],
        "lookback_days": int(row[6]),
        "limit_rows": int(row[7]),
        "holdout_ratio": float(row[8]),
        "split_seed": row[9],
        "weights": row[10] if isinstance(row[10], list) else [],
        "confidences": row[11] if isinstance(row[11], list) else [],
        "score_thresholds": row[12] if isinstance(row[12], list) else [],
        "top_k": int(row[13]),
        "allow_guardrail_fail": bool(row[14]),
        "snapshot_note": row[15],
        "updated_by": row[16],
        "last_run_at": None if row[17] is None else row[17].isoformat(),
        "last_status": row[18],
        "last_run_summary": row[19] if isinstance(row[19], dict) else {},
        "created_at": row[20].isoformat(),
        "updated_at": row[21].isoformat(),
    }


def _coerce_feature_bool(value: Any) -> bool:
    return _coerce_bool(value, False)


def _coerce_feature_int(value: Any) -> int:
    return _coerce_int(value, 0)


def _coerce_feature_float(value: Any) -> float | None:
    if isinstance(value, bool):
        return None
    if isinstance(value, (int, float)):
        return float(value)
    if isinstance(value, str):
        text = value.strip()
        if not text:
            return None
        try:
            return float(text)
        except Exception:
            return None
    return None


def _normalize_gatekeeper_config_for_apply(project_id: str, config: dict[str, Any], updated_by: str) -> GatekeeperConfigUpsertRequest:
    return GatekeeperConfigUpsertRequest(
        project_id=project_id,
        updated_by=updated_by,
        min_sources_for_golden=max(2, min(50, _coerce_int(config.get("min_sources_for_golden"), 3))),
        conflict_free_days=max(1, min(365, _coerce_int(config.get("conflict_free_days"), 7))),
        min_score_for_golden=max(0.0, min(1.0, _coerce_float(config.get("min_score_for_golden"), 0.72))),
        operational_short_text_len=max(8, min(512, _coerce_int(config.get("operational_short_text_len"), 32))),
        operational_short_token_len=max(1, min(128, _coerce_int(config.get("operational_short_token_len"), 5))),
        llm_assist_enabled=_coerce_bool(config.get("llm_assist_enabled"), False),
        llm_provider="openai",
        llm_model=str(config.get("llm_model") or "gpt-4.1-mini"),
        llm_score_weight=max(0.0, min(1.0, _coerce_float(config.get("llm_score_weight"), 0.35))),
        llm_min_confidence=max(0.0, min(1.0, _coerce_float(config.get("llm_min_confidence"), 0.65))),
        llm_timeout_ms=max(200, min(20000, _coerce_int(config.get("llm_timeout_ms"), 3500))),
        publish_mode_default=_normalize_publish_mode(config.get("publish_mode_default"), default="auto_publish"),
        publish_mode_by_category=_normalize_publish_mode_map(config.get("publish_mode_by_category")),
        routing_policy=_normalize_gatekeeper_routing_policy(config.get("routing_policy")),
        auto_publish_min_score=max(0.0, min(1.0, _coerce_float(config.get("auto_publish_min_score"), 0.9))),
        auto_publish_min_sources=max(1, min(100, _coerce_int(config.get("auto_publish_min_sources"), 3))),
        auto_publish_require_golden=_coerce_bool(config.get("auto_publish_require_golden"), True),
        auto_publish_allow_conflicts=_coerce_bool(config.get("auto_publish_allow_conflicts"), False),
    )


def _load_gatekeeper_snapshot(project_id: str, snapshot_id: UUID) -> dict[str, Any]:
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  id::text,
                  source,
                  config,
                  guardrails_met,
                  holdout_meta,
                  calibration_report,
                  artifact_refs,
                  created_at
                FROM gatekeeper_config_snapshots
                WHERE project_id = %s
                  AND id = %s
                LIMIT 1
                """,
                (project_id, snapshot_id),
            )
            row = cur.fetchone()
    if row is None:
        raise HTTPException(status_code=404, detail="gatekeeper snapshot not found")
    return {
        "id": row[0],
        "source": row[1],
        "config": row[2] if isinstance(row[2], dict) else {},
        "guardrails_met": row[3],
        "holdout_meta": row[4] if isinstance(row[4], dict) else {},
        "calibration_report": row[5] if isinstance(row[5], dict) else {},
        "artifact_refs": row[6] if isinstance(row[6], dict) else {},
        "created_at": row[7].isoformat(),
    }


def _estimate_gatekeeper_tier_from_features(
    *,
    features: dict[str, Any],
    current_score: float,
    target_config: dict[str, Any],
) -> dict[str, Any]:
    evidence_count = max(0, _coerce_feature_int(features.get("evidence_count")))
    repeated_count = max(0, _coerce_feature_int(features.get("repeated_count")))
    source_diversity = max(0, _coerce_feature_int(features.get("source_diversity")))
    is_short = _coerce_feature_bool(features.get("is_short"))
    has_operational_pattern = _coerce_feature_bool(features.get("has_operational_pattern"))
    has_policy_signal = _coerce_feature_bool(features.get("has_policy_signal"))
    has_recent_open_conflict = _coerce_feature_bool(features.get("has_recent_open_conflict"))

    min_sources_for_golden = max(2, min(50, _coerce_int(target_config.get("min_sources_for_golden"), 3)))
    min_score_for_golden = max(0.0, min(1.0, _coerce_float(target_config.get("min_score_for_golden"), 0.72)))
    llm_assist_enabled = _coerce_bool(target_config.get("llm_assist_enabled"), False)
    llm_weight = max(0.0, min(1.0, _coerce_float(target_config.get("llm_score_weight"), 0.35)))
    llm_min_confidence = max(0.0, min(1.0, _coerce_float(target_config.get("llm_min_confidence"), 0.65)))

    score_before_llm = _coerce_float(features.get("score_before_llm"), current_score)
    score = max(0.0, min(1.0, score_before_llm))
    llm_applied = False
    llm_score = _coerce_feature_float(features.get("llm_score"))
    llm_confidence = _coerce_feature_float(features.get("llm_confidence"))
    llm_suggested_tier = str(features.get("llm_suggested_tier") or "").strip()

    if llm_assist_enabled and llm_score is not None and llm_confidence is not None and llm_confidence >= llm_min_confidence:
        score = max(0.0, min(1.0, round((1.0 - llm_weight) * score + llm_weight * llm_score, 4)))
        llm_applied = True

    rationale = "informative fact requires moderation before promotion"
    if has_operational_pattern and is_short and repeated_count == 0:
        tier = "operational_memory"
        rationale = "short operational event with low reusable signal"
    elif has_policy_signal and (evidence_count >= 2 or repeated_count >= 1):
        tier = "golden_candidate"
        rationale = "policy-like fact with multi-signal support"
    elif repeated_count >= 2:
        tier = "golden_candidate"
        rationale = "repeated claim pattern reached promotion threshold"
    else:
        tier = "insight_candidate"

    if (
        tier == "insight_candidate"
        and source_diversity >= min_sources_for_golden
        and score >= min_score_for_golden
        and not has_recent_open_conflict
    ):
        tier = "golden_candidate"
        rationale = "auto-promoted by source diversity threshold and conflict-free horizon"

    if llm_applied:
        if llm_suggested_tier == "golden_candidate":
            if not has_recent_open_conflict and score >= min_score_for_golden:
                if tier != "golden_candidate":
                    tier = "golden_candidate"
                    rationale = "llm-assisted promotion: high-confidence model signal and score threshold met"
        elif llm_suggested_tier == "operational_memory":
            if is_short and repeated_count == 0 and not has_policy_signal:
                if tier != "operational_memory":
                    tier = "operational_memory"
                    rationale = "llm-assisted demotion: short low-value operational event"
        elif llm_suggested_tier == "insight_candidate":
            if tier == "golden_candidate" and not has_policy_signal:
                tier = "insight_candidate"
                rationale = "llm-assisted moderation: held in insight queue pending more evidence"

    if has_recent_open_conflict and tier == "golden_candidate":
        tier = "insight_candidate"
        rationale = "open conflicts for entity in recent horizon; kept as insight candidate"

    return {
        "estimated_tier": tier,
        "estimated_score": score,
        "estimated_rationale": rationale,
        "llm_applied": llm_applied,
    }


def _build_gatekeeper_config_diff(current: dict[str, Any], target: dict[str, Any]) -> dict[str, dict[str, Any]]:
    keys = [
        "min_sources_for_golden",
        "conflict_free_days",
        "min_score_for_golden",
        "operational_short_text_len",
        "operational_short_token_len",
        "llm_assist_enabled",
        "llm_model",
        "llm_score_weight",
        "llm_min_confidence",
        "llm_timeout_ms",
    ]
    diff: dict[str, dict[str, Any]] = {}
    for key in keys:
        old = current.get(key)
        new = target.get(key)
        if old != new:
            diff[key] = {"current": old, "target": new}
    return diff


def _build_gatekeeper_rollback_preview(
    *,
    project_id: str,
    snapshot_id: UUID,
    lookback_days: int,
    limit: int,
    sample_size: int,
) -> dict[str, Any]:
    snapshot = _load_gatekeeper_snapshot(project_id, snapshot_id)
    target_config = snapshot.get("config") if isinstance(snapshot.get("config"), dict) else {}
    current_config = (get_gatekeeper_config(project_id).get("config") or {})
    if not isinstance(current_config, dict):
        current_config = {}

    since = datetime.now(UTC) - timedelta(days=max(1, int(lookback_days)))
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT claim_id::text, tier, score, features, updated_at
                FROM gatekeeper_decisions
                WHERE project_id = %s
                  AND updated_at >= %s
                ORDER BY updated_at DESC
                LIMIT %s
                """,
                (project_id, since, max(100, int(limit))),
            )
            rows = cur.fetchall()

    current_counts = {"operational_memory": 0, "insight_candidate": 0, "golden_candidate": 0}
    target_counts = {"operational_memory": 0, "insight_candidate": 0, "golden_candidate": 0}
    transitions: dict[str, int] = {}
    changed_samples: list[dict[str, Any]] = []
    changed_total = 0

    for row in rows:
        claim_id = row[0]
        current_tier = str(row[1] or "insight_candidate")
        current_score = _coerce_float(row[2], 0.0)
        features = row[3] if isinstance(row[3], dict) else {}
        updated_at = row[4]

        estimate = _estimate_gatekeeper_tier_from_features(
            features=features,
            current_score=current_score,
            target_config=target_config,
        )
        target_tier = str(estimate["estimated_tier"])
        current_counts[current_tier] = current_counts.get(current_tier, 0) + 1
        target_counts[target_tier] = target_counts.get(target_tier, 0) + 1
        transition_key = f"{current_tier}->{target_tier}"
        transitions[transition_key] = transitions.get(transition_key, 0) + 1

        if target_tier != current_tier:
            changed_total += 1
            if len(changed_samples) < max(1, int(sample_size)):
                changed_samples.append(
                    {
                        "claim_id": claim_id,
                        "from_tier": current_tier,
                        "to_tier": target_tier,
                        "score_current": round(current_score, 4),
                        "score_estimated": round(_coerce_float(estimate.get("estimated_score"), current_score), 4),
                        "updated_at": updated_at.isoformat() if hasattr(updated_at, "isoformat") else str(updated_at),
                        "reason": estimate.get("estimated_rationale"),
                    }
                )

    total = len(rows)
    changed_ratio = round((changed_total / total), 4) if total > 0 else 0.0
    from_golden = transitions.get("golden_candidate->insight_candidate", 0) + transitions.get(
        "golden_candidate->operational_memory", 0
    )
    to_golden = transitions.get("insight_candidate->golden_candidate", 0) + transitions.get(
        "operational_memory->golden_candidate", 0
    )
    risk_level = "low"
    if from_golden >= 25 or changed_ratio >= 0.35:
        risk_level = "high"
    elif from_golden >= 8 or changed_ratio >= 0.18:
        risk_level = "medium"

    return {
        "project_id": project_id,
        "snapshot_id": str(snapshot_id),
        "snapshot": snapshot,
        "lookback_days": int(lookback_days),
        "limit": int(limit),
        "config_diff": _build_gatekeeper_config_diff(current_config, target_config),
        "impact": {
            "decisions_scanned": total,
            "changed_total": changed_total,
            "changed_ratio": changed_ratio,
            "changed_from_golden": int(from_golden),
            "changed_to_golden": int(to_golden),
            "risk_level": risk_level,
            "tier_counts_current": current_counts,
            "tier_counts_target_estimated": target_counts,
            "transitions": transitions,
        },
        "changed_samples": changed_samples,
        "generated_at": datetime.now(UTC).isoformat(),
    }


def _apply_gatekeeper_rollback_from_snapshot(*, project_id: str, snapshot: dict[str, Any], updated_by: str, note: str | None) -> dict[str, Any]:
    source_snapshot_id = str(snapshot.get("id"))
    source_snapshot_kind = str(snapshot.get("source") or "unknown")
    source_config = snapshot.get("config") if isinstance(snapshot.get("config"), dict) else {}
    source_guardrails_met = snapshot.get("guardrails_met")
    source_holdout_meta = snapshot.get("holdout_meta") if isinstance(snapshot.get("holdout_meta"), dict) else {}
    source_calibration_report = (
        snapshot.get("calibration_report") if isinstance(snapshot.get("calibration_report"), dict) else {}
    )
    source_artifact_refs = snapshot.get("artifact_refs") if isinstance(snapshot.get("artifact_refs"), dict) else {}

    gatekeeper_payload = _normalize_gatekeeper_config_for_apply(project_id, source_config, updated_by=updated_by)
    upsert_result = upsert_gatekeeper_config(gatekeeper_payload)
    applied_config = upsert_result.get("config") if isinstance(upsert_result, dict) else {}
    if not isinstance(applied_config, dict):
        applied_config = {}

    rollback_note = note or f"Rollback to snapshot {source_snapshot_id} (source={source_snapshot_kind})"
    rollback_artifact_refs = dict(source_artifact_refs)
    rollback_artifact_refs["rollback_from_snapshot_id"] = source_snapshot_id
    rollback_artifact_refs["rollback_from_source"] = source_snapshot_kind
    rollback_artifact_refs["rollback_at"] = datetime.now(UTC).isoformat()
    snapshot_payload = GatekeeperConfigSnapshotCreateRequest(
        project_id=project_id,
        approved_by=updated_by,
        source="rollback",
        note=rollback_note,
        config=applied_config,
        guardrails_met=source_guardrails_met,
        holdout_meta=source_holdout_meta,
        calibration_report=source_calibration_report,
        artifact_refs=rollback_artifact_refs,
    )
    snapshot_result = create_gatekeeper_config_snapshot(snapshot_payload)
    rollback_snapshot = snapshot_result.get("snapshot") if isinstance(snapshot_result, dict) else None

    return {
        "status": "ok",
        "project_id": project_id,
        "rolled_back_to_snapshot_id": source_snapshot_id,
        "config": applied_config,
        "snapshot": rollback_snapshot,
    }


def _parse_iso_datetime(value: Any) -> datetime | None:
    if value is None:
        return None
    if isinstance(value, datetime):
        if value.tzinfo is None:
            return value.replace(tzinfo=UTC)
        return value.astimezone(UTC)
    if not isinstance(value, str):
        return None
    text = value.strip()
    if not text:
        return None
    if text.endswith("Z"):
        text = f"{text[:-1]}+00:00"
    try:
        parsed = datetime.fromisoformat(text)
    except ValueError:
        return None
    if parsed.tzinfo is None:
        return parsed.replace(tzinfo=UTC)
    return parsed.astimezone(UTC)


def _quantile(values: list[float], q: float) -> float | None:
    if not values:
        return None
    points = sorted(values)
    if len(points) == 1:
        return round(points[0], 3)
    rank = (len(points) - 1) * max(0.0, min(1.0, q))
    low = int(math.floor(rank))
    high = int(math.ceil(rank))
    if low == high:
        return round(points[low], 3)
    weight = rank - low
    return round(points[low] * (1.0 - weight) + points[high] * weight, 3)


def _latency_stats(values: list[float]) -> dict[str, Any]:
    if not values:
        return {"count": 0, "avg": None, "p50": None, "p90": None}
    avg = round(sum(values) / len(values), 3)
    return {
        "count": len(values),
        "avg": avg,
        "p50": _quantile(values, 0.5),
        "p90": _quantile(values, 0.9),
    }


def _safe_ratio(numerator: int, denominator: int) -> float:
    if denominator <= 0:
        return 0.0
    return round(float(numerator) / float(denominator), 4)


_INTELLIGENCE_DIGEST_KIND_DAILY = "daily"
_INTELLIGENCE_DIGEST_KIND_WEEKLY = "weekly"
_INTELLIGENCE_DIGEST_KIND_INCIDENT_ESCALATION_DAILY = "incident_escalation_daily"
_INTELLIGENCE_DIGEST_KINDS = {
    _INTELLIGENCE_DIGEST_KIND_DAILY,
    _INTELLIGENCE_DIGEST_KIND_WEEKLY,
    _INTELLIGENCE_DIGEST_KIND_INCIDENT_ESCALATION_DAILY,
}
_INTELLIGENCE_ESCALATION_SEVERITIES = {"info", "warning", "critical"}
_INTELLIGENCE_WEEKDAY_ALIASES = {
    "mon": "mon",
    "monday": "mon",
    "tue": "tue",
    "tues": "tue",
    "tuesday": "tue",
    "wed": "wed",
    "weds": "wed",
    "wednesday": "wed",
    "thu": "thu",
    "thur": "thu",
    "thurs": "thu",
    "thursday": "thu",
    "fri": "fri",
    "friday": "fri",
    "sat": "sat",
    "saturday": "sat",
    "sun": "sun",
    "sunday": "sun",
    "0": "mon",
    "1": "tue",
    "2": "wed",
    "3": "thu",
    "4": "fri",
    "5": "sat",
    "6": "sun",
}
_INTELLIGENCE_ESCALATION_OWNER_FIELDS = {
    "owner_name",
    "owner_contact",
    "oncall_channel",
    "escalation_channel",
}
_INTELLIGENCE_ESCALATION_OWNER_FIELD_DEFAULTS = {
    "critical": "escalation_channel",
    "warning": "oncall_channel",
    "info": "oncall_channel",
}
_INCIDENT_SYNC_PREFLIGHT_ENFORCEMENT_MODES = {"off", "block", "pause"}
_INCIDENT_SYNC_SCHEDULE_PREFLIGHT_ENFORCEMENT_MODES = {"inherit", "off", "block", "pause"}
_INCIDENT_SYNC_SCHEDULE_PRESET_INTERVAL_MINUTES = {
    "hourly": 60,
    "every_4h": 240,
    "daily": 1440,
    "weekly": 10080,
}


def _normalize_intelligence_escalation_severity(value: Any, *, default: str = "warning") -> str:
    text = str(value or default).strip().lower() or default
    if text not in _INTELLIGENCE_ESCALATION_SEVERITIES:
        raise HTTPException(
            status_code=422,
            detail={
                "code": "intelligence_escalation_severity_invalid",
                "allowed": sorted(_INTELLIGENCE_ESCALATION_SEVERITIES),
            },
        )
    return text


def _normalize_intelligence_quiet_hour_time(value: Any, *, field: str) -> str:
    text = str(value or "").strip()
    if not re.fullmatch(r"(?:[01]\d|2[0-3]):[0-5]\d", text):
        raise HTTPException(status_code=422, detail={"code": "intelligence_quiet_hours_time_invalid", "field": field})
    return text


def _normalize_intelligence_quiet_hour_days(value: Any) -> list[str]:
    if not isinstance(value, list):
        raise HTTPException(status_code=422, detail={"code": "intelligence_quiet_hours_days_invalid"})
    out: list[str] = []
    for item in value:
        key = str(item or "").strip().lower()
        normalized = _INTELLIGENCE_WEEKDAY_ALIASES.get(key)
        if normalized is None:
            raise HTTPException(
                status_code=422,
                detail={"code": "intelligence_quiet_hours_day_invalid", "value": item},
            )
        if normalized not in out:
            out.append(normalized)
    if not out:
        raise HTTPException(status_code=422, detail={"code": "intelligence_quiet_hours_days_required"})
    return out


def _normalize_intelligence_delivery_playbook(raw: Any) -> dict[str, Any]:
    if not isinstance(raw, dict):
        return {}

    playbook: dict[str, Any] = {}
    playbook["enabled"] = bool(raw.get("enabled", False))
    playbook["owner_tier_enabled"] = bool(raw.get("owner_tier_enabled", True))
    playbook["owner_tier_max_candidates"] = max(1, min(20, int(raw.get("owner_tier_max_candidates") or 5)))

    owner_fields = dict(_INTELLIGENCE_ESCALATION_OWNER_FIELD_DEFAULTS)
    custom_owner_fields = raw.get("owner_tier_channels_by_severity")
    if custom_owner_fields is not None:
        if not isinstance(custom_owner_fields, dict):
            raise HTTPException(status_code=422, detail={"code": "intelligence_owner_tier_channels_invalid"})
        for severity in sorted(_INTELLIGENCE_ESCALATION_SEVERITIES):
            if severity not in custom_owner_fields:
                continue
            field = str(custom_owner_fields.get(severity) or "").strip().lower()
            if field not in _INTELLIGENCE_ESCALATION_OWNER_FIELDS:
                raise HTTPException(
                    status_code=422,
                    detail={
                        "code": "intelligence_owner_tier_channel_field_invalid",
                        "severity": severity,
                        "allowed": sorted(_INTELLIGENCE_ESCALATION_OWNER_FIELDS),
                    },
                )
            owner_fields[severity] = field
    playbook["owner_tier_channels_by_severity"] = owner_fields

    fallback_recipients_raw = raw.get("owner_tier_fallback_recipients")
    fallback_recipients: list[str] = []
    if fallback_recipients_raw is not None:
        if not isinstance(fallback_recipients_raw, list):
            raise HTTPException(status_code=422, detail={"code": "intelligence_owner_tier_fallback_invalid"})
        for item in fallback_recipients_raw:
            text = str(item or "").strip()
            if not text or text in fallback_recipients:
                continue
            fallback_recipients.append(text[:512])
            if len(fallback_recipients) >= 20:
                break
    playbook["owner_tier_fallback_recipients"] = fallback_recipients

    fanout_map: dict[str, list[str]] = {severity: [] for severity in sorted(_INTELLIGENCE_ESCALATION_SEVERITIES)}
    fanout_raw = raw.get("severity_fanout")
    if fanout_raw is not None:
        if not isinstance(fanout_raw, dict):
            raise HTTPException(status_code=422, detail={"code": "intelligence_severity_fanout_invalid"})
        for severity in sorted(_INTELLIGENCE_ESCALATION_SEVERITIES):
            rows = fanout_raw.get(severity)
            if rows is None:
                continue
            if not isinstance(rows, list):
                raise HTTPException(
                    status_code=422,
                    detail={"code": "intelligence_severity_fanout_row_invalid", "severity": severity},
                )
            normalized_rows: list[str] = []
            for item in rows:
                text = str(item or "").strip()
                if not text or text in normalized_rows:
                    continue
                normalized_rows.append(text[:512])
                if len(normalized_rows) >= 40:
                    break
            fanout_map[severity] = normalized_rows
    playbook["severity_fanout"] = fanout_map

    quiet_hours_out: dict[str, Any] = {
        "enabled": False,
        "timezone": "UTC",
        "allow_severity_at_or_above": "critical",
        "windows": [],
    }
    quiet_raw = raw.get("quiet_hours")
    if quiet_raw is not None:
        if not isinstance(quiet_raw, dict):
            raise HTTPException(status_code=422, detail={"code": "intelligence_quiet_hours_invalid"})
        quiet_hours_out["enabled"] = bool(quiet_raw.get("enabled", False))
        quiet_hours_out["timezone"] = str(quiet_raw.get("timezone") or "UTC").strip()[:64] or "UTC"
        quiet_hours_out["allow_severity_at_or_above"] = _normalize_intelligence_escalation_severity(
            quiet_raw.get("allow_severity_at_or_above"),
            default="critical",
        )
        windows_raw = quiet_raw.get("windows")
        if windows_raw is not None:
            if not isinstance(windows_raw, list):
                raise HTTPException(status_code=422, detail={"code": "intelligence_quiet_hours_windows_invalid"})
            windows: list[dict[str, Any]] = []
            for index, item in enumerate(windows_raw):
                if not isinstance(item, dict):
                    raise HTTPException(
                        status_code=422,
                        detail={"code": "intelligence_quiet_hours_window_invalid", "index": index},
                    )
                windows.append(
                    {
                        "days": _normalize_intelligence_quiet_hour_days(item.get("days")),
                        "start": _normalize_intelligence_quiet_hour_time(item.get("start"), field=f"windows[{index}].start"),
                        "end": _normalize_intelligence_quiet_hour_time(item.get("end"), field=f"windows[{index}].end"),
                    }
                )
                if len(windows) >= 24:
                    break
            quiet_hours_out["windows"] = windows
    playbook["quiet_hours"] = quiet_hours_out

    return playbook


def _normalize_intelligence_delivery_target_config(channel: str, raw: Any) -> dict[str, Any]:
    config = dict(raw) if isinstance(raw, dict) else {}
    if "timeout_seconds" in config:
        config["timeout_seconds"] = max(1.0, min(60.0, float(config.get("timeout_seconds") or 8)))

    digest_kinds_raw = config.get("digest_kinds")
    if digest_kinds_raw is not None:
        if not isinstance(digest_kinds_raw, list):
            raise HTTPException(status_code=422, detail={"code": "intelligence_delivery_digest_kinds_invalid"})
        normalized_kinds: list[str] = []
        for item in digest_kinds_raw:
            kind = _normalize_intelligence_digest_kind(str(item or "").strip() or None)
            if kind not in normalized_kinds:
                normalized_kinds.append(kind)
        config["digest_kinds"] = normalized_kinds

    if "incident_escalation_require_over_sla" in config:
        config["incident_escalation_require_over_sla"] = bool(config.get("incident_escalation_require_over_sla", True))

    if "incident_escalation_playbook" in config:
        config["incident_escalation_playbook"] = _normalize_intelligence_delivery_playbook(
            config.get("incident_escalation_playbook")
        )

    if channel == "email_smtp":
        host = str(config.get("host") or "").strip()
        if host:
            config["host"] = host[:512]
        for key in ("username", "from_email"):
            value = str(config.get(key) or "").strip()
            if value:
                config[key] = value[:512]
        if "port" in config:
            config["port"] = max(1, min(65535, int(config.get("port") or 587)))
        if "use_tls" in config:
            config["use_tls"] = bool(config.get("use_tls", True))
        if "use_ssl" in config:
            config["use_ssl"] = bool(config.get("use_ssl", False))

    return config


def _normalize_intelligence_digest_kind(value: str | None, *, default: str = _INTELLIGENCE_DIGEST_KIND_DAILY) -> str:
    text = str(value or default).strip().lower() or default
    if text not in _INTELLIGENCE_DIGEST_KINDS:
        raise HTTPException(
            status_code=422,
            detail={
                "code": "intelligence_digest_kind_unsupported",
                "allowed": sorted(_INTELLIGENCE_DIGEST_KINDS),
            },
        )
    return text


def _normalize_rejection_reason(value: str | None) -> str:
    text = (value or "").strip()
    if not text:
        return "unspecified"
    normalized = " ".join(text.split())
    if len(normalized) > 120:
        return f"{normalized[:117]}..."
    return normalized


def _counter_to_ranked_items(
    counter: dict[str, int],
    *,
    item_key: str,
    total: int,
    top: int = 5,
) -> list[dict[str, Any]]:
    rows = sorted(counter.items(), key=lambda item: (-int(item[1]), str(item[0])))[: max(1, int(top))]
    return [
        {
            item_key: key,
            "count": int(count),
            "share": _safe_ratio(int(count), max(1, total)),
        }
        for key, count in rows
    ]


def _parse_csv_tokens(raw: str | None) -> list[str]:
    if raw is None:
        return []
    out: list[str] = []
    seen: set[str] = set()
    for token in str(raw).split(","):
        normalized = token.strip()
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        out.append(normalized)
    return out


def _reviewer_cohort_key(actor: str) -> str:
    text = actor.strip()
    if not text:
        return "unknown"
    for sep in ("@", ":", "/", "_", "-"):
        if sep in text:
            head = text.split(sep, 1)[0].strip()
            if head:
                return head.lower()
    return text.lower()


def _rollback_attribution_group_key(*, actor: str, group_by: str) -> str:
    normalized_actor = actor.strip()
    if group_by == "cohort":
        return _reviewer_cohort_key(normalized_actor)
    return normalized_actor


def _extract_json_payload(raw: str) -> dict[str, Any]:
    text = (raw or "").strip()
    if not text:
        return {}
    try:
        payload = json.loads(text)
        if isinstance(payload, dict):
            return payload
    except Exception:
        pass
    lines = [line.strip() for line in text.splitlines() if line.strip()]
    for line in reversed(lines):
        if not (line.startswith("{") and line.endswith("}")):
            continue
        try:
            payload = json.loads(line)
        except Exception:
            continue
        if isinstance(payload, dict):
            return payload
    return {"raw_output": text}


def _build_scheduler_command_preview(
    *,
    project_id: str,
    api_url: str,
    dry_run: bool,
    force_run: bool,
    skip_due_check: bool,
) -> str:
    parts: list[str] = [
        "python",
        "scripts/run_gatekeeper_calibration_scheduler.py",
        "--use-api-schedules",
        "--project-id",
        project_id,
        "--api-url",
        api_url,
    ]
    if dry_run:
        parts.append("--dry-run")
    if force_run:
        parts.append("--force-run")
    if skip_due_check:
        parts.append("--skip-due-check")
    return " ".join(shlex.quote(item) for item in parts)


def _load_enabled_gatekeeper_schedules(project_id: str, *, limit: int = 500) -> list[dict[str, Any]]:
    payload = list_gatekeeper_calibration_schedules(project_id=project_id, enabled=True, limit=limit)
    schedules = payload.get("schedules") if isinstance(payload, dict) else None
    if not isinstance(schedules, list):
        return []
    return [item for item in schedules if isinstance(item, dict)]


def _gatekeeper_operation_lock_key(project_id: str) -> int:
    digest = hashlib.sha256(f"gatekeeper_operation:{project_id}".encode("utf-8")).digest()
    return int.from_bytes(digest[:8], byteorder="big", signed=False) & 0x7FFF_FFFF_FFFF_FFFF


def _with_gatekeeper_operation_lock(project_id: str):
    class _LockCtx:
        def __enter__(self_nonlocal):
            self_nonlocal._conn_ctx = get_conn()
            self_nonlocal._conn = self_nonlocal._conn_ctx.__enter__()
            self_nonlocal._key = _gatekeeper_operation_lock_key(project_id)
            with self_nonlocal._conn.cursor() as cur:
                cur.execute("SELECT pg_try_advisory_lock(%s)", (self_nonlocal._key,))
                row = cur.fetchone()
            acquired = bool(row[0]) if row else False
            if not acquired:
                self_nonlocal._conn_ctx.__exit__(None, None, None)
                raise HTTPException(status_code=409, detail="calibration_operation_locked")
            return self_nonlocal

        def __exit__(self_nonlocal, exc_type, exc, tb):
            try:
                with self_nonlocal._conn.cursor() as cur:
                    cur.execute("SELECT pg_advisory_unlock(%s)", (self_nonlocal._key,))
                    cur.fetchone()
            finally:
                self_nonlocal._conn_ctx.__exit__(exc_type, exc, tb)
            return False

    return _LockCtx()


def _create_operation_run_record(
    *,
    project_id: str,
    operation_token: str,
    requested_by: str | None,
    dry_run: bool,
    request_payload: dict[str, Any],
    mode: str = "sync",
    status: str = "running",
    max_attempts: int = 3,
    retry_of: str | None = None,
    attempt_no: int = 1,
) -> tuple[str, str | None, dict[str, Any] | None]:
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT id::text, status, result_payload
                FROM gatekeeper_calibration_operation_runs
                WHERE project_id = %s
                  AND operation_token = %s
                LIMIT 1
                """,
                (project_id, operation_token),
            )
            existing = cur.fetchone()
            if existing is not None:
                payload = existing[2] if isinstance(existing[2], dict) else {}
                return str(existing[0]), str(existing[1] or "unknown"), payload

            run_id = uuid4()
            cur.execute(
                """
                INSERT INTO gatekeeper_calibration_operation_runs (
                  id,
                  project_id,
                  operation_token,
                  requested_by,
                  dry_run,
                  status,
                  mode,
                  progress_percent,
                  progress_phase,
                  attempt_no,
                  max_attempts,
                  retry_of,
                  request_payload,
                  result_payload
                )
                VALUES (
                  %s, %s, %s, %s, %s, %s, %s,
                  %s, %s, %s, %s, %s, %s, '{}'::jsonb
                )
                RETURNING id::text
                """,
                (
                    run_id,
                    project_id,
                    operation_token,
                    requested_by,
                    dry_run,
                    status,
                    mode,
                    5.0 if status == "running" else 0.0,
                    "queued" if status == "queued" else "running",
                    max(1, int(attempt_no)),
                    max(1, min(20, int(max_attempts))),
                    retry_of,
                    Jsonb(request_payload),
                ),
            )
            row = cur.fetchone()
    return str(row[0]), None, None


def _update_operation_run_record(
    record_id: str,
    *,
    status: str | None = None,
    result_payload: dict[str, Any] | None = None,
    error_message: str | None = None,
    progress_percent: float | None = None,
    progress_phase: str | None = None,
    cancel_requested: bool | None = None,
    cancel_requested_by: str | None = None,
    set_started_at: bool = False,
    set_finished_at: bool = False,
    worker_id: str | None = None,
) -> None:
    updates: list[str] = ["updated_at = NOW()"]
    params: list[Any] = []
    if status is not None:
        updates.append("status = %s")
        params.append(status)
    if result_payload is not None:
        updates.append("result_payload = %s")
        params.append(Jsonb(result_payload))
    if error_message is not None:
        updates.append("error_message = %s")
        params.append(error_message[:4000])
    if progress_percent is not None:
        updates.append("progress_percent = %s")
        params.append(float(max(0.0, min(100.0, progress_percent))))
    if progress_phase is not None:
        updates.append("progress_phase = %s")
        params.append(progress_phase[:256])
    if cancel_requested is not None:
        updates.append("cancel_requested = %s")
        params.append(bool(cancel_requested))
        if cancel_requested:
            updates.append("cancel_requested_at = NOW()")
    if cancel_requested_by is not None:
        updates.append("cancel_requested_by = %s")
        params.append(cancel_requested_by[:256])
    if set_started_at:
        updates.append("started_at = COALESCE(started_at, NOW())")
    if set_finished_at:
        updates.append("finished_at = NOW()")
    if worker_id is not None:
        updates.append("worker_id = %s")
        params.append(worker_id[:256])
    updates.append("heartbeat_at = NOW()")

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                UPDATE gatekeeper_calibration_operation_runs
                SET {set_clause}
                WHERE id = %s
                """.format(set_clause=", ".join(updates)),
                (*params, record_id),
            )


def _append_operation_event(
    *,
    run_id: str,
    project_id: str,
    event_type: str,
    message: str,
    phase: str | None = None,
    progress_percent: float | None = None,
    payload: dict[str, Any] | None = None,
) -> int:
    normalized_progress = None
    if progress_percent is not None:
        normalized_progress = float(max(0.0, min(100.0, progress_percent)))
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                INSERT INTO gatekeeper_calibration_operation_events (
                  operation_run_id,
                  project_id,
                  event_type,
                  phase,
                  message,
                  progress_percent,
                  payload
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s)
                RETURNING id
                """,
                (
                    run_id,
                    project_id,
                    event_type[:128],
                    (phase or "")[:128] or None,
                    message[:2000],
                    normalized_progress,
                    Jsonb(payload or {}),
                ),
            )
            row = cur.fetchone()

            update_parts = ["updated_at = NOW()", "heartbeat_at = NOW()"]
            update_params: list[Any] = []
            if phase is not None:
                update_parts.append("progress_phase = %s")
                update_params.append(phase[:256])
            if normalized_progress is not None:
                update_parts.append("progress_percent = %s")
                update_params.append(normalized_progress)
            cur.execute(
                f"""
                UPDATE gatekeeper_calibration_operation_runs
                SET {", ".join(update_parts)}
                WHERE id = %s
                """,
                (*update_params, run_id),
            )
    return int(row[0]) if row else 0


def _validate_live_operation_controls(
    *,
    project_id: str,
    dry_run: bool,
    confirm: bool,
    confirmation_phrase: str | None,
    operation_token: str | None,
) -> None:
    required_phrase = f"RUN {project_id}"
    if dry_run:
        return
    if not confirm:
        raise HTTPException(status_code=422, detail="calibration_operation_confirmation_required")
    if (confirmation_phrase or "").strip() != required_phrase:
        raise HTTPException(status_code=422, detail="calibration_operation_confirmation_phrase_mismatch")
    if not (operation_token and operation_token.strip()):
        raise HTTPException(status_code=422, detail="calibration_operation_token_required")


def _operation_terminal(status: str | None) -> bool:
    return str(status or "").strip().lower() in {"succeeded", "failed", "canceled"}


def _default_operation_queue_control(*, project_id: str) -> dict[str, Any]:
    return {
        "project_id": project_id,
        "paused_until": None,
        "pause_reason": None,
        "pause_active": False,
        "worker_lag_sla_minutes": 20,
        "queue_depth_warn": 12,
        "incident_preflight_enforcement_mode": "off",
        "incident_preflight_pause_hours": 4,
        "incident_preflight_critical_fail_threshold": 1,
        "updated_by": "system",
        "created_at": None,
        "updated_at": None,
    }


def _serialize_operation_queue_control_row(row: tuple[Any, ...], *, project_id: str) -> dict[str, Any]:
    paused_until = _parse_iso_datetime(row[1]) if row[1] is not None else None
    return {
        "project_id": row[0] or project_id,
        "paused_until": None if paused_until is None else paused_until.isoformat(),
        "pause_reason": row[2] if isinstance(row[2], str) else None,
        "pause_active": paused_until is not None and paused_until > datetime.now(UTC),
        "worker_lag_sla_minutes": max(1, int(row[3] or 20)),
        "queue_depth_warn": max(1, int(row[4] or 12)),
        "incident_preflight_enforcement_mode": _normalize_incident_sync_preflight_enforcement_mode(row[5], default="off"),
        "incident_preflight_pause_hours": max(1, min(168, int(row[6] or 4))),
        "incident_preflight_critical_fail_threshold": max(1, min(100, int(row[7] or 1))),
        "updated_by": str(row[8] or "system"),
        "created_at": None if row[9] is None else row[9].isoformat(),
        "updated_at": None if row[10] is None else row[10].isoformat(),
    }


def _fetch_operation_queue_control(project_id: str) -> dict[str, Any]:
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  project_id,
                  paused_until,
                  pause_reason,
                  worker_lag_sla_minutes,
                  queue_depth_warn,
                  incident_preflight_enforcement_mode,
                  incident_preflight_pause_hours,
                  incident_preflight_critical_fail_threshold,
                  updated_by,
                  created_at,
                  updated_at
                FROM gatekeeper_calibration_queue_controls
                WHERE project_id = %s
                LIMIT 1
                """,
                (project_id,),
            )
            row = cur.fetchone()
    if row is None:
        return _default_operation_queue_control(project_id=project_id)
    return _serialize_operation_queue_control_row(row, project_id=project_id)


def _upsert_operation_queue_control(
    *,
    project_id: str,
    worker_lag_sla_minutes: int,
    queue_depth_warn: int,
    incident_preflight_enforcement_mode: str,
    incident_preflight_pause_hours: int,
    incident_preflight_critical_fail_threshold: int,
    updated_by: str,
    paused_until: datetime | None,
    pause_reason: str | None,
) -> dict[str, Any]:
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                INSERT INTO gatekeeper_calibration_queue_controls (
                  project_id,
                  paused_until,
                  pause_reason,
                  worker_lag_sla_minutes,
                  queue_depth_warn,
                  incident_preflight_enforcement_mode,
                  incident_preflight_pause_hours,
                  incident_preflight_critical_fail_threshold,
                  updated_by,
                  created_at,
                  updated_at
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, NOW(), NOW())
                ON CONFLICT (project_id) DO UPDATE
                SET paused_until = EXCLUDED.paused_until,
                    pause_reason = EXCLUDED.pause_reason,
                    worker_lag_sla_minutes = EXCLUDED.worker_lag_sla_minutes,
                    queue_depth_warn = EXCLUDED.queue_depth_warn,
                    incident_preflight_enforcement_mode = EXCLUDED.incident_preflight_enforcement_mode,
                    incident_preflight_pause_hours = EXCLUDED.incident_preflight_pause_hours,
                    incident_preflight_critical_fail_threshold = EXCLUDED.incident_preflight_critical_fail_threshold,
                    updated_by = EXCLUDED.updated_by,
                    updated_at = NOW()
                RETURNING
                  project_id,
                  paused_until,
                  pause_reason,
                  worker_lag_sla_minutes,
                  queue_depth_warn,
                  incident_preflight_enforcement_mode,
                  incident_preflight_pause_hours,
                  incident_preflight_critical_fail_threshold,
                  updated_by,
                  created_at,
                  updated_at
                """,
                (
                    project_id,
                    paused_until,
                    pause_reason,
                    max(1, min(1440, int(worker_lag_sla_minutes))),
                    max(1, min(50000, int(queue_depth_warn))),
                    _normalize_incident_sync_preflight_enforcement_mode(incident_preflight_enforcement_mode, default="off"),
                    max(1, min(168, int(incident_preflight_pause_hours))),
                    max(1, min(100, int(incident_preflight_critical_fail_threshold))),
                    updated_by[:256],
                ),
            )
            row = cur.fetchone()
    if row is None:
        return _default_operation_queue_control(project_id=project_id)
    return _serialize_operation_queue_control_row(row, project_id=project_id)


