@app.post("/v1/events", response_model=None)
def ingest_events(
    batch: EventBatch,
    request: Request,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    inserted = 0
    response: dict[str, int]
    source_ownership_advisories = 0
    with get_conn() as conn:
        if _source_ownership_table_exists(conn):
            header_source = _resolve_request_source_system(request, fallback=None)
            policy_cache: dict[str, dict[str, dict[str, Any]]] = {}
            for event in batch.events:
                project_id = str(event.project_id or "").strip()
                if not project_id:
                    continue
                project_policies = policy_cache.get(project_id)
                if project_policies is None:
                    project_policies = _load_source_ownership_policies(conn, project_id)
                    policy_cache[project_id] = project_policies
                check = _enforce_source_ownership_write(
                    policies_by_domain=project_policies,
                    project_id=project_id,
                    domain="runtime_memory",
                    source_system=_extract_source_system_from_payload(event.payload, fallback=header_source),
                    endpoint="/v1/events",
                )
                if check.get("status") == "advisory":
                    source_ownership_advisories += 1
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint="/v1/events",
            idempotency_key=idempotency_key,
            request_payload=batch.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )

        with conn.cursor() as cur:
            try:
                for event in batch.events:
                    payload = dict(event.payload)
                    if event.trace_id or event.span_id or event.parent_span_id:
                        synapse_meta = payload.get("_synapse")
                        synapse_meta_dict = dict(synapse_meta) if isinstance(synapse_meta, dict) else {}
                        if event.trace_id:
                            synapse_meta_dict["trace_id"] = event.trace_id
                        if event.span_id:
                            synapse_meta_dict["span_id"] = event.span_id
                        if event.parent_span_id:
                            synapse_meta_dict["parent_span_id"] = event.parent_span_id
                        payload["_synapse"] = synapse_meta_dict
                    if event.tags:
                        payload["_tags"] = event.tags
                    if idempotency_key:
                        payload["_idempotency_key"] = idempotency_key

                    cur.execute(
                        """
                        INSERT INTO events (
                          id, project_id, agent_id, session_id, event_type, payload, observed_at
                        )
                        VALUES (%s, %s, %s, %s, %s, %s, %s)
                        ON CONFLICT (id) DO NOTHING
                        """,
                        (
                            event.id,
                            event.project_id,
                            event.agent_id,
                            event.session_id,
                            event.event_type,
                            Jsonb(payload),
                            event.observed_at,
                        ),
                    )
                    inserted += cur.rowcount
                response = {"accepted": len(batch.events), "inserted": inserted, "deduplicated": len(batch.events) - inserted}
                if source_ownership_advisories > 0:
                    response["source_ownership_advisories"] = source_ownership_advisories
                mark_request_completed(
                    conn,
                    endpoint="/v1/events",
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint="/v1/events",
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise

    return response


@app.get("/v1/events/throughput")
def get_event_ingest_throughput(
    project_id: str,
    window_hours: int = Query(default=24, ge=1, le=24 * 30),
    event_type: str | None = Query(default=None),
    top_event_types: int = Query(default=8, ge=1, le=30),
) -> dict[str, Any]:
    now = datetime.now(UTC)
    cutoff = now - timedelta(hours=window_hours)
    params: list[Any] = [project_id, cutoff]
    filters = ["project_id = %s", "received_at >= %s"]
    if event_type is not None and event_type.strip():
        filters.append("event_type = %s")
        params.append(event_type.strip())
    where_clause = " AND ".join(filters)

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                f"""
                SELECT
                  COUNT(*)::int AS events_ingested,
                  COUNT(DISTINCT session_id)::int AS sessions_active,
                  COUNT(DISTINCT agent_id)::int AS agents_active,
                  COUNT(DISTINCT event_type)::int AS event_types_active
                FROM events
                WHERE {where_clause}
                """,
                tuple(params),
            )
            summary_row = cur.fetchone()

            cur.execute(
                f"""
                SELECT
                  AVG(EXTRACT(EPOCH FROM (received_at - observed_at)) * 1000.0) AS avg_ms,
                  percentile_cont(0.5) WITHIN GROUP (
                    ORDER BY EXTRACT(EPOCH FROM (received_at - observed_at)) * 1000.0
                  ) AS p50_ms,
                  percentile_cont(0.95) WITHIN GROUP (
                    ORDER BY EXTRACT(EPOCH FROM (received_at - observed_at)) * 1000.0
                  ) AS p95_ms,
                  percentile_cont(0.99) WITHIN GROUP (
                    ORDER BY EXTRACT(EPOCH FROM (received_at - observed_at)) * 1000.0
                  ) AS p99_ms
                FROM events
                WHERE {where_clause}
                  AND received_at >= observed_at
                """,
                tuple(params),
            )
            latency_row = cur.fetchone()

            cur.execute(
                f"""
                SELECT event_type, COUNT(*)::int AS events_total
                FROM events
                WHERE {where_clause}
                GROUP BY event_type
                ORDER BY events_total DESC, event_type ASC
                LIMIT %s
                """,
                tuple([*params, int(top_event_types)]),
            )
            type_rows = cur.fetchall()

    events_ingested = int((summary_row[0] if summary_row else 0) or 0)
    sessions_active = int((summary_row[1] if summary_row else 0) or 0)
    agents_active = int((summary_row[2] if summary_row else 0) or 0)
    event_types_active = int((summary_row[3] if summary_row else 0) or 0)

    avg_ms = float(latency_row[0]) if latency_row and latency_row[0] is not None else None
    p50_ms = float(latency_row[1]) if latency_row and latency_row[1] is not None else None
    p95_ms = float(latency_row[2]) if latency_row and latency_row[2] is not None else None
    p99_ms = float(latency_row[3]) if latency_row and latency_row[3] is not None else None

    ingest_rate_per_second = round(events_ingested / max(float(window_hours) * 3600.0, 1.0), 6)
    alerts: list[str] = []
    health = "healthy"

    if events_ingested == 0:
        alerts.append("No events ingested in selected window.")
    if p95_ms is not None and p95_ms >= 2000.0:
        alerts.append("Ingest p95 latency is above 2000ms.")
    if p99_ms is not None and p99_ms >= 5000.0:
        alerts.append("Ingest p99 latency is above 5000ms.")

    if events_ingested == 0 or (p99_ms is not None and p99_ms >= 5000.0):
        health = "critical"
    elif (p95_ms is not None and p95_ms >= 2000.0) or (p99_ms is not None and p99_ms >= 3000.0):
        health = "watch"

    return {
        "project_id": project_id,
        "event_type_filter": event_type.strip() if isinstance(event_type, str) and event_type.strip() else None,
        "window_hours": int(window_hours),
        "since": cutoff.isoformat(),
        "generated_at": now.isoformat(),
        "health": health,
        "alerts": alerts,
        "metrics": {
            "events_ingested": events_ingested,
            "sessions_active": sessions_active,
            "agents_active": agents_active,
            "event_types_active": event_types_active,
            "ingest_rate_per_second": ingest_rate_per_second,
            "latency_ms": {
                "avg": round(avg_ms, 3) if avg_ms is not None else None,
                "p50": round(p50_ms, 3) if p50_ms is not None else None,
                "p95": round(p95_ms, 3) if p95_ms is not None else None,
                "p99": round(p99_ms, 3) if p99_ms is not None else None,
            },
        },
        "top_event_types": [
            {
                "event_type": str(row[0] or ""),
                "events_total": int(row[1] or 0),
            }
            for row in type_rows
        ],
    }


@app.post("/v1/facts/proposals", response_model=None)
def propose_fact(
    payload: ClaimProposal,
    request: Request,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    response = {"status": "queued"}
    source_ownership_advisories = 0
    with get_conn() as conn:
        if _source_ownership_table_exists(conn):
            project_id = str(payload.claim.project_id or "").strip()
            if project_id:
                source_hint = _resolve_request_source_system(request, fallback=None)
                for evidence in payload.claim.evidence:
                    source_candidate = _extract_source_system_from_payload(evidence, fallback=None)
                    if source_candidate != "unknown":
                        source_hint = source_candidate
                        break
                policies = _load_source_ownership_policies(conn, project_id)
                check = _enforce_source_ownership_write(
                    policies_by_domain=policies,
                    project_id=project_id,
                    domain="runtime_memory",
                    source_system=source_hint,
                    endpoint="/v1/facts/proposals",
                )
                if check.get("status") == "advisory":
                    source_ownership_advisories += 1
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint="/v1/facts/proposals",
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )

        with conn.cursor() as cur:
            try:
                cur.execute(
                    """
                    INSERT INTO claim_proposals (claim_id, project_id, claim_payload, status)
                    VALUES (%s, %s, %s, 'queued')
                    ON CONFLICT (claim_id) DO UPDATE
                    SET claim_payload = EXCLUDED.claim_payload,
                        status = 'queued',
                        updated_at = NOW()
                    """,
                    (
                        payload.claim.id,
                        payload.claim.project_id,
                        Jsonb(payload.claim.model_dump(mode="json")),
                    ),
                )
                mark_request_completed(
                    conn,
                    endpoint="/v1/facts/proposals",
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=(
                        {**response, "source_ownership_advisories": source_ownership_advisories}
                        if source_ownership_advisories > 0
                        else response
                    ),
                )
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint="/v1/facts/proposals",
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise
    if source_ownership_advisories > 0:
        return {**response, "source_ownership_advisories": source_ownership_advisories}
    return response


def _ingest_memory_backfill(
    payload: MemoryBackfillRequest,
    request: Request,
    *,
    endpoint: str,
    source_ownership_domain: str,
    default_ingest_lane: str,
    idempotency_key: str | None = None,
) -> Any:
    batch = payload.batch
    batch_id = batch.batch_id or uuid4()
    ingest_lane = _normalize_backfill_ingest_lane(batch.ingest_lane, default=default_ingest_lane)
    inserted = 0
    accepted = len(batch.records)
    source_ownership_advisories = 0

    with get_conn() as conn:
        if _source_ownership_table_exists(conn):
            project_id = str(batch.project_id or "").strip()
            if project_id:
                source_hint = _normalize_source_system(
                    batch.source_system or _resolve_request_source_system(request, fallback=None)
                )
                policies = _load_source_ownership_policies(conn, project_id)
                check = _enforce_source_ownership_write(
                    policies_by_domain=policies,
                    project_id=project_id,
                    domain=source_ownership_domain,
                    source_system=source_hint,
                    endpoint=endpoint,
                )
                if check.get("status") == "advisory":
                    source_ownership_advisories += 1
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )

        with conn.cursor() as cur:
            try:
                cur.execute(
                    """
                    INSERT INTO memory_backfill_batches (
                      id, project_id, source_system, agent_id, session_id, status, cursor, created_by
                    )
                    VALUES (%s, %s, %s, %s, %s, 'collecting', %s, %s)
                    ON CONFLICT (id) DO UPDATE
                    SET source_system = EXCLUDED.source_system,
                        agent_id = COALESCE(EXCLUDED.agent_id, memory_backfill_batches.agent_id),
                        session_id = COALESCE(EXCLUDED.session_id, memory_backfill_batches.session_id),
                        cursor = COALESCE(EXCLUDED.cursor, memory_backfill_batches.cursor),
                        created_by = COALESCE(EXCLUDED.created_by, memory_backfill_batches.created_by),
                        updated_at = NOW()
                    RETURNING project_id, status
                    """,
                    (
                        batch_id,
                        batch.project_id,
                        batch.source_system,
                        batch.agent_id,
                        batch.session_id,
                        batch.cursor,
                        batch.created_by,
                    ),
                )
                existing_project_id, existing_status = cur.fetchone()
                if existing_project_id != batch.project_id:
                    response = {"error": "batch_id_project_mismatch"}
                    mark_request_failed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        error_message="batch_id_project_mismatch",
                    )
                    return JSONResponse(status_code=409, content=response)
                if existing_status == "completed":
                    response = {
                        "batch_id": str(batch_id),
                        "ingest_lane": ingest_lane,
                        "status": "completed",
                        "accepted": accepted,
                        "inserted": 0,
                        "deduplicated": accepted,
                    }
                    if source_ownership_advisories > 0:
                        response["source_ownership_advisories"] = source_ownership_advisories
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=200,
                        response_body=response,
                    )
                    return response

                for record in batch.records:
                    event_payload = {
                        "source_id": record.source_id,
                        "content": record.content,
                        "valid_from": record.valid_from.isoformat() if record.valid_from else None,
                        "valid_to": record.valid_to.isoformat() if record.valid_to else None,
                        "entity_key": record.entity_key,
                        "category": record.category,
                        "metadata": record.metadata or {},
                        "_tags": record.tags or [],
                        "backfill": {
                            "batch_id": str(batch_id),
                            "source_system": batch.source_system,
                            "ingest_lane": ingest_lane,
                            "cursor": batch.cursor,
                            "ingested_at": datetime.now(UTC).isoformat(),
                        },
                    }
                    if idempotency_key:
                        event_payload["_idempotency_key"] = idempotency_key

                    cur.execute(
                        """
                        INSERT INTO events (
                          id, project_id, agent_id, session_id, event_type, payload, observed_at
                        )
                        VALUES (%s, %s, %s, %s, 'memory_backfill', %s, %s)
                        ON CONFLICT (id) DO NOTHING
                        """,
                        (
                            _backfill_event_id(batch_id, record.source_id),
                            batch.project_id,
                            batch.agent_id,
                            batch.session_id,
                            Jsonb(event_payload),
                            record.observed_at or datetime.now(UTC),
                        ),
                    )
                    inserted += cur.rowcount

                next_status = "ready" if batch.finalize else "collecting"
                cur.execute(
                    """
                    UPDATE memory_backfill_batches
                    SET total_items = total_items + %s,
                        inserted_events = inserted_events + %s,
                        status = CASE
                          WHEN status = 'completed' THEN status
                          WHEN %s THEN 'ready'
                          ELSE 'collecting'
                        END,
                        cursor = COALESCE(%s, cursor),
                        updated_at = NOW()
                    WHERE id = %s
                    RETURNING total_items, inserted_events, status
                    """,
                    (inserted, inserted, batch.finalize, batch.cursor, batch_id),
                )
                total_items, inserted_events, saved_status = cur.fetchone()
                response = {
                    "batch_id": str(batch_id),
                    "ingest_lane": ingest_lane,
                    "status": saved_status,
                    "accepted": accepted,
                    "inserted": inserted,
                    "deduplicated": accepted - inserted,
                    "total_items": int(total_items),
                    "inserted_events": int(inserted_events),
                    "next_action": "run_worker" if next_status == "ready" else "continue_upload",
                }
                if source_ownership_advisories > 0:
                    response["source_ownership_advisories"] = source_ownership_advisories
                mark_request_completed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


