@app.get("/v1/wiki/onboarding-pack")
def get_wiki_onboarding_pack(
    project_id: str,
    role: str | None = Query(default=None),
    max_items_per_section: int = Query(default=5, ge=1, le=20),
    freshness_days: int = Query(default=14, ge=1, le=90),
) -> dict[str, Any]:
    normalized_project = project_id.strip()
    if not normalized_project:
        raise HTTPException(status_code=422, detail={"code": "project_id_required"})
    with get_conn() as conn:
        return _build_wiki_onboarding_pack(
            conn,
            project_id=normalized_project,
            role=role,
            max_items_per_section=max_items_per_section,
            freshness_days=freshness_days,
        )


@app.get("/v1/wiki/pages/{slug}")
def get_wiki_page(slug: str, project_id: str) -> Any:
    normalized_slug = _normalize_wiki_slug(slug, slug)
    with get_conn() as conn:
        with conn.cursor() as cur:
            page_row = _resolve_wiki_page_row_by_slug_or_alias(
                cur,
                project_id=project_id,
                slug_or_alias=normalized_slug,
                for_update=False,
            )
            page = None
            resolution_mode = "slug"
            canonical_slug = normalized_slug
            if page_row is not None:
                page = (
                    page_row[0],
                    page_row[1],
                    page_row[3],
                    page_row[4],
                    page_row[5],
                    page_row[6],
                )
                canonical_slug = str(page_row[2])
                resolution_mode = str(page_row[7] or "slug")
            if page is None:
                return JSONResponse(status_code=404, content={"error": "page_not_found"})

            cur.execute(
                """
                SELECT version, markdown, source, created_by, created_at
                FROM wiki_page_versions
                WHERE page_id = %s
                ORDER BY version DESC
                LIMIT 1
                """,
                (page[0],),
            )
            latest_version = cur.fetchone()

            cur.execute(
                """
                SELECT section_key, heading, order_index, statement_count
                FROM wiki_sections
                WHERE page_id = %s
                ORDER BY order_index ASC, section_key ASC
                """,
                (page[0],),
            )
            sections = cur.fetchall()

            cur.execute(
                """
                SELECT id::text, section_key, statement_text, claim_fingerprint, valid_from, valid_to, created_at
                FROM wiki_statements
                WHERE page_id = %s
                  AND status = 'active'
                  AND (valid_from IS NULL OR valid_from <= NOW())
                  AND (valid_to IS NULL OR valid_to >= NOW())
                ORDER BY created_at DESC
                LIMIT 200
                """,
                (page[0],),
            )
            statements = cur.fetchall()

    return {
        "page": {
            "id": str(page[0]),
            "title": page[1],
            "slug": canonical_slug,
            "entity_key": page[2],
            "page_type": page[3],
            "status": page[4],
            "current_version": page[5],
        },
        "resolved_from": {
            "requested_slug": normalized_slug,
            "resolution_mode": resolution_mode,
        },
        "latest_version": None
        if latest_version is None
        else {
            "version": latest_version[0],
            "markdown": latest_version[1],
            "source": latest_version[2],
            "created_by": latest_version[3],
            "created_at": latest_version[4].isoformat(),
        },
        "sections": [
            {
                "section_key": row[0],
                "heading": row[1],
                "order_index": row[2],
                "statement_count": row[3],
            }
            for row in sections
        ],
        "statements": [
            {
                "id": row[0],
                "section_key": row[1],
                "statement_text": row[2],
                "claim_fingerprint": row[3],
                "valid_from": row[4].isoformat() if row[4] is not None else None,
                "valid_to": row[5].isoformat() if row[5] is not None else None,
                "created_at": row[6].isoformat(),
            }
            for row in statements
        ],
    }


@app.get("/v1/wiki/pages/{slug}/history")
def get_wiki_page_history(
    slug: str,
    project_id: str,
    limit: int = Query(default=20, ge=1, le=100),
    include_markdown: bool = Query(default=True),
) -> Any:
    normalized_slug = _normalize_wiki_slug(slug, slug)
    with get_conn() as conn:
        with conn.cursor() as cur:
            page_row = _resolve_wiki_page_row_by_slug_or_alias(
                cur,
                project_id=project_id,
                slug_or_alias=normalized_slug,
                for_update=False,
            )
            page = None
            resolution_mode = "slug"
            canonical_slug = normalized_slug
            if page_row is not None:
                page = (
                    page_row[0],
                    page_row[1],
                    page_row[3],
                    page_row[4],
                    page_row[5],
                    page_row[6],
                )
                canonical_slug = str(page_row[2])
                resolution_mode = str(page_row[7] or "slug")
            if page is None:
                return JSONResponse(status_code=404, content={"error": "page_not_found"})

            cur.execute(
                """
                SELECT version, markdown, source, created_by, change_summary, created_at
                FROM wiki_page_versions
                WHERE page_id = %s
                ORDER BY version DESC
                LIMIT %s
                """,
                (page[0], limit),
            )
            rows = cur.fetchall()

    versions = []
    for row in rows:
        item = {
            "version": int(row[0]),
            "source": row[2],
            "created_by": row[3],
            "change_summary": row[4],
            "created_at": row[5].isoformat(),
            "markdown_length": len(str(row[1] or "")),
        }
        if include_markdown:
            item["markdown"] = str(row[1] or "")
        versions.append(item)

    return {
        "page": {
            "id": str(page[0]),
            "title": page[1],
            "slug": canonical_slug,
            "entity_key": page[2],
            "page_type": page[3],
            "status": page[4],
            "current_version": int(page[5]) if page[5] is not None else None,
        },
        "resolved_from": {
            "requested_slug": normalized_slug,
            "resolution_mode": resolution_mode,
        },
        "versions": versions,
    }


@app.put("/v1/wiki/pages/{slug}/rollback", response_model=None)
def rollback_wiki_page(
    slug: str,
    payload: WikiPageRollbackRequest,
    request: Request,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    normalized_slug = _normalize_wiki_slug(slug, slug)
    with get_conn() as conn:
        with conn.cursor() as cur:
            page_row = _resolve_wiki_page_row_by_slug_or_alias(
                cur,
                project_id=payload.project_id,
                slug_or_alias=normalized_slug,
                for_update=False,
            )
            if page_row is None:
                return JSONResponse(
                    status_code=404,
                    content={
                        "error": "wiki_page_not_found",
                        "project_id": payload.project_id,
                        "slug": normalized_slug,
                    },
                )
            page_id = page_row[0]
            canonical_slug = str(page_row[2] or normalized_slug).strip() or normalized_slug
            page_status = str(page_row[5] or "published").strip() or "published"
            cur.execute(
                """
                SELECT markdown
                FROM wiki_page_versions
                WHERE page_id = %s
                  AND version = %s
                LIMIT 1
                """,
                (page_id, int(payload.target_version)),
            )
            target_row = cur.fetchone()
            if target_row is None:
                return JSONResponse(
                    status_code=404,
                    content={
                        "error": "wiki_page_version_not_found",
                        "project_id": payload.project_id,
                        "slug": canonical_slug,
                        "target_version": int(payload.target_version),
                    },
                )
            rollback_markdown = str(target_row[0] or "")

    rollback_summary = (
        payload.change_summary.strip()
        if isinstance(payload.change_summary, str) and payload.change_summary.strip()
        else None
    ) or f"Rolled back to v{int(payload.target_version)} by {payload.rolled_back_by}"

    rollback_payload = WikiPageUpdateRequest(
        project_id=payload.project_id,
        updated_by=payload.rolled_back_by,
        markdown=rollback_markdown,
        status=payload.status or page_status,
        change_summary=rollback_summary,
    )
    rollback_idempotency_key = (
        f"{idempotency_key}:rollback:v{int(payload.target_version)}"
        if isinstance(idempotency_key, str) and idempotency_key.strip()
        else None
    )
    result = update_wiki_page(
        slug=canonical_slug,
        payload=rollback_payload,
        request=request,
        idempotency_key=rollback_idempotency_key,
    )
    if isinstance(result, JSONResponse):
        return result
    if isinstance(result, dict):
        result["rollback"] = {
            "target_version": int(payload.target_version),
            "rolled_back_by": payload.rolled_back_by,
        }
    return result


