def _derive_gatekeeper_llm_reason_code(features: dict[str, Any], *, tier: str | None) -> str | None:
    if not isinstance(features, dict):
        return None
    explicit_reason = str(features.get("llm_reason_code") or "").strip()
    if explicit_reason:
        return explicit_reason

    llm_error = str(features.get("llm_error") or "").strip()
    if llm_error:
        return llm_error

    status = str(features.get("llm_status") or "").strip().lower()
    if status in {"disabled", "skipped", "error", "timeout"}:
        return f"llm_{status}"
    if status and status != "ok":
        return f"llm_{status}"

    llm_confidence_raw = features.get("llm_confidence")
    llm_min_confidence_raw = features.get("gatekeeper_llm_min_confidence")
    llm_confidence = float(llm_confidence_raw) if isinstance(llm_confidence_raw, (int, float)) else None
    llm_min_confidence = float(llm_min_confidence_raw) if isinstance(llm_min_confidence_raw, (int, float)) else None
    if llm_confidence is not None and llm_min_confidence is not None and llm_confidence < llm_min_confidence:
        return "below_confidence_threshold"

    llm_applied = bool(features.get("llm_applied"))
    suggested_tier = str(features.get("llm_suggested_tier") or "").strip().lower()
    if llm_applied:
        if suggested_tier == "operational_memory":
            return "override_skip_event"
        if suggested_tier == "golden_candidate":
            return "override_keep_knowledge"
        if suggested_tier == "insight_candidate":
            return "override_route_to_insight"
        return "assist_blended_score"

    if bool(features.get("routing_hard_block")):
        return "routing_policy_hard_block"
    if bool(features.get("blocked_by_source_id")):
        return "blocked_source_id"
    if bool(features.get("blocked_by_source_system")):
        return "blocked_source_system"
    if bool(features.get("blocked_by_source_type")):
        return "blocked_source_type"
    if bool(features.get("blocked_by_entity")):
        return "blocked_entity"
    if bool(features.get("blocked_by_category")):
        return "blocked_category"
    if tier and str(tier).strip().lower() == "operational_memory":
        return "heuristic_operational_memory"
    return "no_override_needed"


@app.get("/v1/wiki/drafts/{draft_id}")
def get_wiki_draft(draft_id: UUID, project_id: str) -> Any:
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  d.id::text,
                  d.claim_id,
                  d.page_id,
                  d.section_key,
                  d.decision,
                  d.confidence,
                  d.rationale,
                  d.status,
                  d.created_at,
                  d.updated_at,
                  d.markdown_patch,
                  d.semantic_diff,
                  d.evidence,
                  p.title,
                  p.slug,
                  p.page_type,
                  p.entity_key,
                  c.claim_text,
                  c.category,
                  c.entity_key,
                  c.status,
                  c.valid_from,
                  c.valid_to,
                  c.created_at,
                  g.tier,
                  g.score,
                  g.rationale,
                  g.features
                FROM wiki_draft_changes d
                LEFT JOIN wiki_pages p ON p.id = d.page_id
                LEFT JOIN claims c ON c.id = d.claim_id
                LEFT JOIN gatekeeper_decisions g ON g.claim_id = d.claim_id
                WHERE d.id = %s
                  AND d.project_id = %s
                LIMIT 1
                """,
                (draft_id, project_id),
            )
            row = cur.fetchone()
            if row is None:
                return JSONResponse(status_code=404, content={"error": "draft_not_found"})

            (
                draft_id_text,
                claim_id_value,
                page_id_value,
                section_key,
                decision_value,
                confidence_value,
                rationale_text,
                draft_status,
                draft_created_at,
                draft_updated_at,
                markdown_patch,
                semantic_diff,
                evidence,
                page_title,
                page_slug,
                page_type,
                page_entity_key,
                claim_text,
                claim_category,
                claim_entity_key,
                claim_status,
                claim_valid_from,
                claim_valid_to,
                claim_created_at,
                gatekeeper_tier,
                gatekeeper_score,
                gatekeeper_rationale,
                gatekeeper_features,
            ) = row

            cur.execute(
                """
                SELECT
                  id::text,
                  conflict_type,
                  resolution_status,
                  details,
                  resolved_by,
                  resolved_at,
                  created_at
                FROM wiki_conflicts
                WHERE project_id = %s
                  AND claim_id = %s
                ORDER BY created_at DESC
                LIMIT 50
                """,
                (project_id, claim_id_value),
            )
            conflict_rows = cur.fetchall()

            cur.execute(
                """
                SELECT
                  id::text,
                  action_type,
                  reviewed_by,
                  decision_before,
                  decision_after,
                  draft_status_before,
                  draft_status_after,
                  note,
                  reason,
                  payload,
                  result,
                  created_at
                FROM moderation_actions
                WHERE project_id = %s
                  AND draft_id = %s
                ORDER BY created_at DESC
                LIMIT 50
                """,
                (project_id, draft_id),
            )
            action_rows = cur.fetchall()

    conflicts = [
        {
            "id": item[0],
            "conflict_type": item[1],
            "resolution_status": item[2],
            "details": item[3],
            "resolved_by": item[4],
            "resolved_at": item[5].isoformat() if item[5] is not None else None,
            "created_at": item[6].isoformat(),
        }
        for item in conflict_rows
    ]

    moderation_actions = [
        {
            "id": item[0],
            "action_type": item[1],
            "reviewed_by": item[2],
            "decision_before": item[3],
            "decision_after": item[4],
            "draft_status_before": item[5],
            "draft_status_after": item[6],
            "note": item[7],
            "reason": item[8],
            "payload": item[9],
            "result": item[10],
            "created_at": item[11].isoformat(),
        }
        for item in action_rows
    ]

    gatekeeper_features_dict = gatekeeper_features if isinstance(gatekeeper_features, dict) else {}
    llm_status = gatekeeper_features_dict.get("llm_status")
    llm_error = gatekeeper_features_dict.get("llm_error")
    llm_reason_code = _derive_gatekeeper_llm_reason_code(gatekeeper_features_dict, tier=gatekeeper_tier)
    llm_confidence_raw = gatekeeper_features_dict.get("llm_confidence")
    llm_confidence = float(llm_confidence_raw) if isinstance(llm_confidence_raw, (int, float)) else None
    llm_applied = bool(gatekeeper_features_dict.get("llm_applied"))

    return {
        "draft": {
            "id": draft_id_text,
            "claim_id": str(claim_id_value),
            "page_id": str(page_id_value) if page_id_value is not None else None,
            "section_key": section_key,
            "decision": decision_value,
            "confidence": float(confidence_value),
            "rationale": rationale_text,
            "status": draft_status,
            "created_at": draft_created_at.isoformat(),
            "updated_at": draft_updated_at.isoformat(),
            "markdown_patch": markdown_patch,
            "semantic_diff": semantic_diff,
            "evidence": evidence,
            "page": {
                "title": page_title,
                "slug": page_slug,
                "page_type": page_type,
                "entity_key": page_entity_key,
            },
            "claim": {
                "claim_text": claim_text,
                "category": claim_category,
                "entity_key": claim_entity_key,
                "status": claim_status,
                "valid_from": claim_valid_from.isoformat() if claim_valid_from is not None else None,
                "valid_to": claim_valid_to.isoformat() if claim_valid_to is not None else None,
                "created_at": claim_created_at.isoformat() if claim_created_at is not None else None,
            },
        },
        "gatekeeper": {
            "tier": gatekeeper_tier,
            "score": float(gatekeeper_score) if isinstance(gatekeeper_score, (int, float)) else None,
            "rationale": gatekeeper_rationale,
            "llm": {
                "status": str(llm_status) if llm_status is not None else None,
                "applied": llm_applied,
                "suggested_tier": (
                    str(gatekeeper_features_dict.get("llm_suggested_tier"))
                    if gatekeeper_features_dict.get("llm_suggested_tier") is not None
                    else None
                ),
                "confidence": llm_confidence,
                "reason_code": llm_reason_code,
                "provider": str(gatekeeper_features_dict.get("llm_provider")) if gatekeeper_features_dict.get("llm_provider") else None,
                "model": str(gatekeeper_features_dict.get("llm_model")) if gatekeeper_features_dict.get("llm_model") else None,
            },
            "routing": {
                "hard_block": bool(gatekeeper_features_dict.get("routing_hard_block")),
                "blocked_by_category": bool(gatekeeper_features_dict.get("blocked_by_category")),
                "blocked_by_source_system": bool(gatekeeper_features_dict.get("blocked_by_source_system")),
                "blocked_by_source_type": bool(gatekeeper_features_dict.get("blocked_by_source_type")),
                "blocked_by_entity": bool(gatekeeper_features_dict.get("blocked_by_entity")),
                "blocked_by_source_id": bool(gatekeeper_features_dict.get("blocked_by_source_id")),
            },
        },
        "conflicts": conflicts,
        "moderation_actions": moderation_actions,
    }


def _conflict_recommendation(conflict_type: str, details: dict[str, Any]) -> str:
    normalized = (conflict_type or "").strip().lower()
    if normalized == "predicate_polarity_mismatch":
        return "Validate temporal overlap and choose authoritative polarity, then force-approve or reject draft."
    if normalized == "semantic_contradiction":
        return "Review source evidence; keep only one active statement for the same operational condition."
    if normalized == "policy_override":
        return "Escalate to policy owner and ensure old policy statement is superseded before approval."
    if details.get("similarity") is not None:
        return "High similarity detected; confirm whether this is reinforcement or true contradiction."
    return "Review evidence context and resolve conflict using approve/reject workflow."


def _conflict_root_cause(conflict_type: str, details: dict[str, Any]) -> str:
    normalized = (conflict_type or "").strip().lower()
    if normalized == "predicate_polarity_mismatch":
        return "Incoming claim polarity conflicts with existing active statement in overlapping time window."
    if normalized == "semantic_contradiction":
        return "Semantically opposite statements detected for the same entity/section."
    if normalized == "policy_override":
        return "New policy candidate conflicts with current published policy."
    similarity = details.get("similarity")
    if similarity is not None:
        return f"Conflict flagged by synthesis heuristics (similarity={similarity})."
    return "Conflict flagged by synthesis heuristics."


@app.get("/v1/wiki/drafts/{draft_id}/conflicts/explain")
def explain_wiki_draft_conflicts(
    draft_id: UUID,
    project_id: str,
    limit: int = Query(default=20, ge=1, le=200),
    resolution_status: str | None = Query(default="open"),
    include_entity_neighbors: bool = Query(default=True),
) -> dict[str, Any]:
    status_filter = (resolution_status or "").strip().lower() or None
    if status_filter not in {None, "open", "resolved", "dismissed"}:
        status_filter = "open"

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  d.claim_id::text,
                  COALESCE(c.entity_key, p.entity_key) AS scope_entity_key,
                  c.claim_text
                FROM wiki_draft_changes d
                LEFT JOIN claims c ON c.id = d.claim_id
                LEFT JOIN wiki_pages p ON p.id = d.page_id
                WHERE d.id = %s
                  AND d.project_id = %s
                LIMIT 1
                """,
                (draft_id, project_id),
            )
            scope_row = cur.fetchone()
            if scope_row is None:
                return JSONResponse(status_code=404, content={"error": "draft_not_found"})

            scope_claim_id = str(scope_row[0])
            scope_entity_key = str(scope_row[1]) if scope_row[1] is not None else None

            if include_entity_neighbors and scope_entity_key:
                cur.execute(
                    """
                    SELECT
                      wc.id::text,
                      wc.conflict_type,
                      wc.resolution_status,
                      wc.created_at,
                      wc.resolved_at,
                      wc.resolved_by,
                      COALESCE(wc.details, '{}'::jsonb),
                      p.id::text,
                      p.title,
                      p.slug,
                      p.entity_key,
                      c.id::text,
                      c.entity_key,
                      c.category,
                      c.claim_text,
                      c.valid_from,
                      c.valid_to,
                      ws.id::text,
                      ws.section_key,
                      ws.statement_text,
                      ws.valid_from,
                      ws.valid_to,
                      CASE
                        WHEN wc.claim_id::text = %s THEN 0
                        WHEN lower(COALESCE(c.entity_key, '')) = lower(%s) THEN 1
                        ELSE 2
                      END AS rank_score
                    FROM wiki_conflicts wc
                    LEFT JOIN wiki_pages p ON p.id = wc.page_id
                    LEFT JOIN claims c ON c.id = wc.claim_id
                    LEFT JOIN wiki_statements ws ON ws.id = wc.conflicting_statement_id
                    WHERE wc.project_id = %s
                      AND (%s::text IS NULL OR wc.resolution_status = %s)
                      AND (
                        wc.claim_id::text = %s
                        OR lower(COALESCE(c.entity_key, '')) = lower(%s)
                        OR lower(COALESCE(p.entity_key, '')) = lower(%s)
                      )
                    ORDER BY rank_score ASC, wc.created_at DESC
                    LIMIT %s
                    """,
                    (
                        scope_claim_id,
                        scope_entity_key,
                        project_id,
                        status_filter,
                        status_filter,
                        scope_claim_id,
                        scope_entity_key,
                        scope_entity_key,
                        limit,
                    ),
                )
            else:
                cur.execute(
                    """
                    SELECT
                      wc.id::text,
                      wc.conflict_type,
                      wc.resolution_status,
                      wc.created_at,
                      wc.resolved_at,
                      wc.resolved_by,
                      COALESCE(wc.details, '{}'::jsonb),
                      p.id::text,
                      p.title,
                      p.slug,
                      p.entity_key,
                      c.id::text,
                      c.entity_key,
                      c.category,
                      c.claim_text,
                      c.valid_from,
                      c.valid_to,
                      ws.id::text,
                      ws.section_key,
                      ws.statement_text,
                      ws.valid_from,
                      ws.valid_to,
                      0 AS rank_score
                    FROM wiki_conflicts wc
                    LEFT JOIN wiki_pages p ON p.id = wc.page_id
                    LEFT JOIN claims c ON c.id = wc.claim_id
                    LEFT JOIN wiki_statements ws ON ws.id = wc.conflicting_statement_id
                    WHERE wc.project_id = %s
                      AND (%s::text IS NULL OR wc.resolution_status = %s)
                      AND wc.claim_id::text = %s
                    ORDER BY wc.created_at DESC
                    LIMIT %s
                    """,
                    (
                        project_id,
                        status_filter,
                        status_filter,
                        scope_claim_id,
                        limit,
                    ),
                )
            rows = cur.fetchall()

    conflicts = []
    for row in rows:
        details_obj = row[6] if isinstance(row[6], dict) else {}
        conflict_type = str(row[1] or "")
        conflicts.append(
            {
                "conflict_id": row[0],
                "conflict_type": conflict_type,
                "resolution_status": row[2],
                "created_at": row[3].isoformat() if row[3] is not None else None,
                "resolved_at": row[4].isoformat() if row[4] is not None else None,
                "resolved_by": row[5],
                "details": details_obj,
                "root_cause": _conflict_root_cause(conflict_type, details_obj),
                "recommendation": _conflict_recommendation(conflict_type, details_obj),
                "page": {
                    "id": row[7],
                    "title": row[8],
                    "slug": row[9],
                    "entity_key": row[10],
                },
                "incoming_claim": {
                    "id": row[11],
                    "entity_key": row[12],
                    "category": row[13],
                    "claim_text": row[14],
                    "valid_from": row[15].isoformat() if row[15] is not None else None,
                    "valid_to": row[16].isoformat() if row[16] is not None else None,
                },
                "conflicting_statement": {
                    "id": row[17],
                    "section_key": row[18],
                    "statement_text": row[19],
                    "valid_from": row[20].isoformat() if row[20] is not None else None,
                    "valid_to": row[21].isoformat() if row[21] is not None else None,
                },
                "rank_score": int(row[22]),
            }
        )

    return {
        "project_id": project_id,
        "draft_id": str(draft_id),
        "source": "api_conflict_explain_mcp_compatible",
        "scope": {
            "claim_id": scope_claim_id,
            "entity_key": scope_entity_key,
        },
        "resolution_status": status_filter,
        "conflicts": conflicts,
    }


@app.post("/v1/wiki/drafts/{draft_id}/approve", response_model=None)
def approve_wiki_draft(
    draft_id: UUID,
    payload: DraftApproveRequest,
    source_system: str | None = Header(default=None, alias="X-Synapse-Source-System"),
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    endpoint = f"/v1/wiki/drafts/{draft_id}/approve"
    source_ownership_advisories = 0
    with get_conn() as conn:
        if _source_ownership_table_exists(conn):
            policies = _load_source_ownership_policies(conn, payload.project_id)
            check = _enforce_source_ownership_write(
                policies_by_domain=policies,
                project_id=payload.project_id,
                domain="synapse_wiki",
                source_system=_normalize_source_system(source_system or payload.reviewed_by or "human_moderation"),
                endpoint=endpoint,
            )
            if check.get("status") == "advisory":
                source_ownership_advisories += 1
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )

        try:
            with conn.transaction():
                with conn.cursor() as cur:
                    cur.execute(
                        """
                        SELECT
                          d.id,
                          d.project_id,
                          d.claim_id,
                          d.page_id,
                          d.section_key,
                          d.decision,
                          d.status,
                          d.evidence,
                          d.rationale,
                          p.title,
                          p.slug,
                          p.page_type,
                          p.status,
                          p.current_version,
                          c.claim_text,
                          c.claim_fingerprint,
                          c.entity_key,
                          c.category,
                          c.status,
                          c.valid_from,
                          c.valid_to
                        FROM wiki_draft_changes d
                        JOIN wiki_pages p ON p.id = d.page_id
                        LEFT JOIN claims c ON c.id = d.claim_id
                        WHERE d.id = %s
                          AND d.project_id = %s
                        FOR UPDATE OF d, p
                        """,
                        (draft_id, payload.project_id),
                    )
                    row = cur.fetchone()
                    if row is None:
                        raise HTTPException(status_code=404, detail="draft_not_found")

                    (
                        _draft_id,
                        project_id,
                        claim_id,
                        page_id,
                        section_key,
                        decision_value,
                        draft_status,
                        evidence_json,
                        draft_rationale,
                        page_title,
                        page_slug,
                        page_type,
                        page_status,
                        current_version,
                        claim_text,
                        claim_fingerprint,
                        entity_key,
                        category,
                        claim_status,
                        claim_valid_from,
                        claim_valid_to,
                    ) = row

                    if draft_status == "approved":
                        response = {
                            "status": "approved",
                            "draft_id": str(draft_id),
                            "project_id": project_id,
                            "page_slug": page_slug,
                            "idempotent": True,
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=200,
                            response_body=response,
                        )
                        return response
                    if draft_status == "rejected":
                        raise HTTPException(status_code=409, detail="draft_already_rejected")
                    if draft_status not in {"pending_review", "blocked_conflict"}:
                        raise HTTPException(status_code=409, detail=f"draft_status_not_approvable:{draft_status}")

                    effective_section_key = section_key or "facts"
                    statement_text = (payload.edited_statement_text or claim_text or "").strip()
                    structured_section_edits = [
                        {
                            "section_key": edit.section_key.strip(),
                            "heading": (edit.heading or "").strip() or None,
                            "mode": edit.mode,
                            "statements": [item.strip() for item in edit.statements if item.strip()],
                        }
                        for edit in (payload.section_edits or [])
                    ]
                    structured_section_edits = [edit for edit in structured_section_edits if edit["section_key"] and edit["statements"]]
                    has_structured_edits = bool(structured_section_edits)

                    final_decision = str(decision_value)
                    apply_statement = final_decision in {"new_page", "new_section", "new_statement"}
                    if final_decision == "conflict":
                        if not payload.force:
                            raise HTTPException(status_code=409, detail="draft_has_conflict_use_force_true")
                        final_decision = "new_statement"
                        apply_statement = True
                        cur.execute(
                            """
                            UPDATE wiki_conflicts
                            SET resolution_status = 'resolved',
                                resolved_by = %s,
                                resolved_at = NOW()
                            WHERE claim_id = %s
                              AND resolution_status = 'open'
                            """,
                            (payload.reviewed_by, claim_id),
                        )
                    elif final_decision in {"reinforcement", "duplicate_ignored"}:
                        apply_statement = False

                    if has_structured_edits and not apply_statement and final_decision in {"reinforcement", "duplicate_ignored"}:
                        final_decision = "new_statement"

                    if apply_statement and not statement_text:
                        if has_structured_edits:
                            apply_statement = False
                        else:
                            raise HTTPException(status_code=409, detail="missing_statement_text_for_approval")

                    section_heading = _section_heading_from_key(effective_section_key)
                    if apply_statement:
                        cur.execute(
                            """
                            SELECT heading
                            FROM wiki_sections
                            WHERE page_id = %s
                              AND section_key = %s
                            LIMIT 1
                            """,
                            (page_id, effective_section_key),
                        )
                        section_row = cur.fetchone()
                        if section_row is None:
                            cur.execute(
                                """
                                SELECT COALESCE(MAX(order_index), -1) + 1
                                FROM wiki_sections
                                WHERE page_id = %s
                                """,
                                (page_id,),
                            )
                            next_order = int(cur.fetchone()[0])
                            cur.execute(
                                """
                                INSERT INTO wiki_sections (page_id, section_key, heading, order_index, statement_count)
                                VALUES (%s, %s, %s, %s, 0)
                                ON CONFLICT (page_id, section_key) DO NOTHING
                                """,
                                (page_id, effective_section_key, section_heading, next_order),
                            )
                        else:
                            section_heading = str(section_row[0])

                    statement_inserted = False
                    statement_id: UUID | None = None
                    inserted_statement_ids: list[str] = []
                    touched_section_keys: set[str] = set()
                    effective_claim_fingerprint = claim_fingerprint or _compute_claim_fingerprint(
                        project_id,
                        entity_key or page_slug,
                        category or page_type,
                        statement_text or str(claim_text or ""),
                    )
                    if apply_statement:
                        touched_section_keys.add(effective_section_key)
                        cur.execute(
                            """
                            SELECT id
                            FROM wiki_statements
                            WHERE page_id = %s
                              AND section_key = %s
                              AND claim_fingerprint = %s
                              AND status = 'active'
                              AND tstzrange(COALESCE(valid_from, '-infinity'::timestamptz), COALESCE(valid_to, 'infinity'::timestamptz), '[]')
                                  && tstzrange(COALESCE(%s::timestamptz, '-infinity'::timestamptz), COALESCE(%s::timestamptz, 'infinity'::timestamptz), '[]')
                            LIMIT 1
                            """,
                            (
                                page_id,
                                effective_section_key,
                                effective_claim_fingerprint,
                                claim_valid_from,
                                claim_valid_to,
                            ),
                        )
                        existing_statement = cur.fetchone()
                        if existing_statement is None:
                            statement_id = uuid4()
                            statement_metadata = {
                                "source": "human_moderation",
                                "reviewed_by": payload.reviewed_by,
                                "draft_id": str(draft_id),
                                "claim_id": str(claim_id),
                                "note": payload.note,
                            }
                            cur.execute(
                                """
                                INSERT INTO wiki_statements (
                                  id, project_id, page_id, section_key, statement_text, normalized_text,
                                  claim_fingerprint, status, metadata, valid_from, valid_to
                                )
                                VALUES (%s, %s, %s, %s, %s, %s, %s, 'active', %s, %s, %s)
                                """,
                                (
                                    statement_id,
                                    project_id,
                                    page_id,
                                    effective_section_key,
                                    statement_text,
                                    _normalize_statement_text(statement_text),
                                    effective_claim_fingerprint,
                                    Jsonb(statement_metadata),
                                    claim_valid_from or datetime.now(UTC),
                                    claim_valid_to,
                                ),
                            )
                            statement_inserted = True
                            inserted_statement_ids.append(str(statement_id))
                        else:
                            statement_id = existing_statement[0]

                    cur.execute(
                        """
                        SELECT version, markdown
                        FROM wiki_page_versions
                        WHERE page_id = %s
                        ORDER BY version DESC
                        LIMIT 1
                        """,
                        (page_id,),
                    )
                    latest_version = cur.fetchone()
                    previous_version = int(latest_version[0]) if latest_version is not None else int(current_version or 0)
                    previous_markdown = str(latest_version[1]) if latest_version is not None else f"# {page_title}\n"
                    next_markdown = previous_markdown
                    if apply_statement:
                        next_markdown = _inject_statement_into_markdown(previous_markdown, section_heading, statement_text)

                    for edit in structured_section_edits:
                        edit_section_key = str(edit["section_key"])
                        edit_heading = str(edit["heading"] or _section_heading_from_key(edit_section_key))
                        edit_mode = str(edit["mode"])
                        edit_statements = [str(item) for item in edit["statements"]]
                        touched_section_keys.add(edit_section_key)

                        cur.execute(
                            """
                            SELECT heading
                            FROM wiki_sections
                            WHERE page_id = %s
                              AND section_key = %s
                            LIMIT 1
                            """,
                            (page_id, edit_section_key),
                        )
                        existing_section = cur.fetchone()
                        if existing_section is None:
                            cur.execute(
                                """
                                SELECT COALESCE(MAX(order_index), -1) + 1
                                FROM wiki_sections
                                WHERE page_id = %s
                                """,
                                (page_id,),
                            )
                            edit_order = int(cur.fetchone()[0])
                            cur.execute(
                                """
                                INSERT INTO wiki_sections (page_id, section_key, heading, order_index, statement_count)
                                VALUES (%s, %s, %s, %s, 0)
                                ON CONFLICT (page_id, section_key) DO NOTHING
                                """,
                                (page_id, edit_section_key, edit_heading, edit_order),
                            )
                        elif edit.get("heading"):
                            cur.execute(
                                """
                                UPDATE wiki_sections
                                SET heading = %s
                                WHERE page_id = %s
                                  AND section_key = %s
                                """,
                                (edit_heading, page_id, edit_section_key),
                            )
                        else:
                            edit_heading = str(existing_section[0])

                        if edit_mode == "replace":
                            cur.execute(
                                """
                                UPDATE wiki_statements
                                SET status = 'superseded',
                                    valid_to = NOW(),
                                    updated_at = NOW()
                                WHERE page_id = %s
                                  AND section_key = %s
                                  AND status = 'active'
                                """,
                                (page_id, edit_section_key),
                            )

                        for item in edit_statements:
                            item_fp = _compute_claim_fingerprint(
                                project_id,
                                entity_key or page_slug,
                                category or page_type,
                                item,
                            )
                            cur.execute(
                                """
                                SELECT id
                                FROM wiki_statements
                                WHERE page_id = %s
                                  AND section_key = %s
                                  AND claim_fingerprint = %s
                                  AND status = 'active'
                                LIMIT 1
                                """,
                                (page_id, edit_section_key, item_fp),
                            )
                            existing_item = cur.fetchone()
                            if existing_item is not None:
                                continue
                            structured_statement_id = uuid4()
                            cur.execute(
                                """
                                INSERT INTO wiki_statements (
                                  id, project_id, page_id, section_key, statement_text, normalized_text,
                                  claim_fingerprint, status, metadata, valid_from
                                )
                                VALUES (%s, %s, %s, %s, %s, %s, %s, 'active', %s, NOW())
                                """,
                                (
                                    structured_statement_id,
                                    project_id,
                                    page_id,
                                    edit_section_key,
                                    item,
                                    _normalize_statement_text(item),
                                    item_fp,
                                    Jsonb(
                                        {
                                            "source": "human_moderation_structured",
                                            "reviewed_by": payload.reviewed_by,
                                            "draft_id": str(draft_id),
                                            "claim_id": str(claim_id),
                                            "note": payload.note,
                                        }
                                    ),
                                ),
                            )
                            inserted_statement_ids.append(str(structured_statement_id))

                        next_markdown = _apply_section_statements_to_markdown(
                            next_markdown,
                            section_heading=edit_heading,
                            statements=edit_statements,
                            mode=edit_mode,
                        )

                    for touched_key in touched_section_keys:
                        cur.execute(
                            """
                            UPDATE wiki_sections ws
                            SET statement_count = (
                              SELECT COUNT(*)
                              FROM wiki_statements st
                              WHERE st.page_id = ws.page_id
                                AND st.section_key = ws.section_key
                                AND st.status = 'active'
                            )
                            WHERE ws.page_id = %s
                              AND ws.section_key = %s
                            """,
                            (page_id, touched_key),
                        )
                    statement_inserted = statement_inserted or bool(inserted_statement_ids)
                    next_version = previous_version + 1
                    change_summary = f"Draft {draft_id} approved by {payload.reviewed_by}; decision={final_decision}"

                    cur.execute(
                        """
                        INSERT INTO wiki_page_versions (
                          id, page_id, version, markdown, ast_json, source, created_by, change_summary
                        )
                        VALUES (%s, %s, %s, %s, %s, 'human', %s, %s)
                        """,
                        (
                            uuid4(),
                            page_id,
                            next_version,
                            next_markdown,
                            Jsonb([]),
                            payload.reviewed_by,
                            change_summary,
                        ),
                    )
                    cur.execute(
                        """
                        UPDATE wiki_pages
                        SET status = 'published',
                            current_version = %s,
                            updated_at = NOW()
                        WHERE id = %s
                        """,
                        (next_version, page_id),
                    )
                    cur.execute(
                        """
                        UPDATE wiki_draft_changes
                        SET status = 'approved',
                            decision = %s,
                            rationale = %s,
                            updated_at = NOW()
                        WHERE id = %s
                        """,
                        (
                            final_decision,
                            f"{draft_rationale}; approved_by={payload.reviewed_by}",
                            draft_id,
                        ),
                    )
                    moderation_metadata = {"moderated_by": payload.reviewed_by, "moderation_note": payload.note}
                    cur.execute(
                        """
                        UPDATE claims
                        SET status = 'approved',
                            metadata = COALESCE(metadata, '{}'::jsonb) || %s,
                            updated_at = NOW()
                        WHERE id = %s
                        """,
                        (Jsonb(moderation_metadata), claim_id),
                    )
                    cur.execute(
                        """
                        INSERT INTO wiki_claim_links (claim_id, page_id, section_key, insertion_status)
                        VALUES (%s, %s, %s, %s)
                        ON CONFLICT (claim_id, page_id, section_key) DO UPDATE
                        SET insertion_status = EXCLUDED.insertion_status,
                            created_at = NOW()
                        """,
                        (claim_id, page_id, effective_section_key, final_decision),
                    )
                    snapshot_id = uuid4()
                    snapshot_note = payload.note or change_summary
                    cur.execute(
                        """
                        INSERT INTO knowledge_snapshots (id, project_id, created_by, note)
                        VALUES (%s, %s, %s, %s)
                        """,
                        (snapshot_id, project_id, payload.reviewed_by, snapshot_note),
                    )
                    cur.execute(
                        """
                        INSERT INTO knowledge_snapshot_pages (snapshot_id, page_id, page_version)
                        VALUES (%s, %s, %s)
                        """,
                        (snapshot_id, page_id, next_version),
                    )
                    cur.execute(
                        """
                        INSERT INTO moderation_actions (
                          id, project_id, draft_id, claim_id, page_id, action_type, reviewed_by,
                          decision_before, decision_after, draft_status_before, draft_status_after,
                          note, payload, result
                        )
                        VALUES (%s, %s, %s, %s, %s, 'approve', %s, %s, %s, %s, 'approved', %s, %s, %s)
                        """,
                        (
                            uuid4(),
                            project_id,
                            draft_id,
                            claim_id,
                            page_id,
                            payload.reviewed_by,
                            str(decision_value),
                            final_decision,
                            str(draft_status),
                            payload.note,
                            Jsonb(payload.model_dump(mode="json")),
                            Jsonb(
                                {
                                    "status": "approved",
                                    "page_version": next_version,
                                    "snapshot_id": str(snapshot_id),
                                    "statement_inserted": statement_inserted,
                                    "inserted_statement_ids": inserted_statement_ids,
                                }
                            ),
                        ),
                    )

                response = {
                    "status": "approved",
                    "draft_id": str(draft_id),
                    "project_id": project_id,
                    "page_slug": page_slug,
                    "page_version": next_version,
                    "snapshot_id": str(snapshot_id),
                    "statement_inserted": statement_inserted,
                    "statement_id": str(statement_id) if statement_id is not None else None,
                    "statement_ids": inserted_statement_ids,
                    "structured_edits_applied": len(structured_section_edits),
                    "decision": final_decision,
                }
                if source_ownership_advisories > 0:
                    response["source_ownership_advisories"] = source_ownership_advisories
            mark_request_completed(
                conn,
                endpoint=endpoint,
                idempotency_key=idempotency_key,
                status_code=200,
                response_body=response,
            )
            return response
        except HTTPException as exc:
            mark_request_failed(
                conn,
                endpoint=endpoint,
                idempotency_key=idempotency_key,
                error_message=f"http_{exc.status_code}:{exc.detail}",
            )
            raise
        except Exception as exc:
            mark_request_failed(
                conn,
                endpoint=endpoint,
                idempotency_key=idempotency_key,
                error_message=str(exc),
            )
            raise


@app.post("/v1/wiki/drafts/{draft_id}/reject", response_model=None)
def reject_wiki_draft(
    draft_id: UUID,
    payload: DraftRejectRequest,
    source_system: str | None = Header(default=None, alias="X-Synapse-Source-System"),
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    endpoint = f"/v1/wiki/drafts/{draft_id}/reject"
    source_ownership_advisories = 0
    with get_conn() as conn:
        if _source_ownership_table_exists(conn):
            policies = _load_source_ownership_policies(conn, payload.project_id)
            check = _enforce_source_ownership_write(
                policies_by_domain=policies,
                project_id=payload.project_id,
                domain="synapse_wiki",
                source_system=_normalize_source_system(source_system or payload.reviewed_by or "human_moderation"),
                endpoint=endpoint,
            )
            if check.get("status") == "advisory":
                source_ownership_advisories += 1
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )

        try:
            with conn.transaction():
                with conn.cursor() as cur:
                    cur.execute(
                        """
                        SELECT d.claim_id, d.page_id, d.section_key, d.status, d.project_id, p.slug, d.decision
                        FROM wiki_draft_changes d
                        JOIN wiki_pages p ON p.id = d.page_id
                        WHERE d.id = %s
                          AND d.project_id = %s
                        FOR UPDATE OF d, p
                        """,
                        (draft_id, payload.project_id),
                    )
                    row = cur.fetchone()
                    if row is None:
                        raise HTTPException(status_code=404, detail="draft_not_found")
                    claim_id, page_id, section_key, draft_status, project_id, page_slug, decision_value = row
                    if draft_status == "rejected":
                        response = {
                            "status": "rejected",
                            "draft_id": str(draft_id),
                            "project_id": project_id,
                            "page_slug": page_slug,
                            "idempotent": True,
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=200,
                            response_body=response,
                        )
                        return response
                    if draft_status == "approved":
                        raise HTTPException(status_code=409, detail="draft_already_approved")

                    cur.execute(
                        """
                        UPDATE wiki_draft_changes
                        SET status = 'rejected',
                            rationale = rationale || %s,
                            updated_at = NOW()
                        WHERE id = %s
                        """,
                        (f"; rejected_by={payload.reviewed_by}", draft_id),
                    )
                    reject_meta = {"rejected_by": payload.reviewed_by, "reject_reason": payload.reason}
                    cur.execute(
                        """
                        UPDATE claims
                        SET status = 'rejected',
                            metadata = COALESCE(metadata, '{}'::jsonb) || %s,
                            updated_at = NOW()
                        WHERE id = %s
                        """,
                        (Jsonb(reject_meta), claim_id),
                    )
                    cur.execute(
                        """
                        INSERT INTO wiki_claim_links (claim_id, page_id, section_key, insertion_status)
                        VALUES (%s, %s, %s, 'rejected')
                        ON CONFLICT (claim_id, page_id, section_key) DO UPDATE
                        SET insertion_status = 'rejected',
                            created_at = NOW()
                        """,
                        (claim_id, page_id, section_key or "facts"),
                    )
                    if payload.dismiss_conflicts:
                        cur.execute(
                            """
                            UPDATE wiki_conflicts
                            SET resolution_status = 'dismissed',
                                resolved_by = %s,
                                resolved_at = NOW()
                            WHERE claim_id = %s
                              AND resolution_status = 'open'
                            """,
                            (payload.reviewed_by, claim_id),
                        )
                    cur.execute(
                        """
                        INSERT INTO moderation_actions (
                          id, project_id, draft_id, claim_id, page_id, action_type, reviewed_by,
                          decision_before, decision_after, draft_status_before, draft_status_after,
                          reason, payload, result
                        )
                        VALUES (%s, %s, %s, %s, %s, 'reject', %s, %s, 'rejected', %s, 'rejected', %s, %s, %s)
                        """,
                        (
                            uuid4(),
                            project_id,
                            draft_id,
                            claim_id,
                            page_id,
                            payload.reviewed_by,
                            str(decision_value),
                            str(draft_status),
                            payload.reason,
                            Jsonb(payload.model_dump(mode="json")),
                            Jsonb({"status": "rejected", "dismiss_conflicts": payload.dismiss_conflicts}),
                        ),
                    )
                response = {
                    "status": "rejected",
                    "draft_id": str(draft_id),
                    "project_id": project_id,
                    "page_slug": page_slug,
                }
                if source_ownership_advisories > 0:
                    response["source_ownership_advisories"] = source_ownership_advisories
            mark_request_completed(
                conn,
                endpoint=endpoint,
                idempotency_key=idempotency_key,
                status_code=200,
                response_body=response,
            )
            return response
        except HTTPException as exc:
            mark_request_failed(
                conn,
                endpoint=endpoint,
                idempotency_key=idempotency_key,
                error_message=f"http_{exc.status_code}:{exc.detail}",
            )
            raise
        except Exception as exc:
            mark_request_failed(
                conn,
                endpoint=endpoint,
                idempotency_key=idempotency_key,
                error_message=str(exc),
            )
            raise


@app.post("/v1/wiki/auto-publish/run")
def run_wiki_auto_publish(payload: WikiAutoPublishRunRequest) -> dict[str, Any]:
    requested_projects: list[str] = []
    if payload.project_id and payload.project_id.strip():
        requested_projects.append(payload.project_id.strip())
    for item in payload.project_ids or []:
        value = str(item or "").strip()
        if value:
            requested_projects.append(value)

    dedup_projects: list[str] = []
    seen_projects: set[str] = set()
    for item in requested_projects:
        if item in seen_projects:
            continue
        seen_projects.add(item)
        dedup_projects.append(item)

    if not dedup_projects:
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute(
                    """
                    SELECT project_id
                    FROM wiki_draft_changes
                    WHERE status = 'pending_review'
                    GROUP BY project_id
                    ORDER BY MAX(created_at) DESC
                    LIMIT 200
                    """
                )
                dedup_projects = [str(row[0]) for row in (cur.fetchall() or []) if str(row[0]).strip()]

    project_results: list[dict[str, Any]] = []
    total_scanned = 0
    total_eligible = 0
    total_approved = 0
    total_failed = 0
    total_source_ownership_advisories = 0

    for project_id in dedup_projects:
        feedback_by_claim: dict[str, dict[str, int | float]] = {}
        with get_conn() as conn:
            source_ownership_advisories = 0
            if _source_ownership_table_exists(conn):
                ownership_policies = _load_source_ownership_policies(conn, project_id)
                ownership_check = _enforce_source_ownership_write(
                    policies_by_domain=ownership_policies,
                    project_id=project_id,
                    domain="synapse_wiki",
                    source_system=_normalize_source_system(payload.reviewed_by or "synapse_autopublisher"),
                    endpoint="/v1/wiki/auto-publish/run",
                )
                if ownership_check.get("status") == "advisory":
                    source_ownership_advisories += 1
            has_publish_columns = _gatekeeper_config_has_publish_columns(conn)
            has_routing_policy_column = _gatekeeper_config_has_routing_policy_column(conn)
            policy = {
                "publish_mode_default": "auto_publish",
                "publish_mode_by_category": {},
                "auto_publish_min_score": 0.9,
                "auto_publish_min_sources": 3,
                "auto_publish_require_golden": True,
                "auto_publish_allow_conflicts": False,
                "routing_policy": _normalize_gatekeeper_routing_policy(None),
            }
            with conn.cursor() as cur:
                if has_publish_columns and has_routing_policy_column:
                    cur.execute(
                        """
                        SELECT
                          publish_mode_default,
                          publish_mode_by_category,
                          auto_publish_min_score,
                          auto_publish_min_sources,
                          auto_publish_require_golden,
                          auto_publish_allow_conflicts,
                          routing_policy
                        FROM gatekeeper_project_configs
                        WHERE project_id = %s
                        LIMIT 1
                        """,
                        (project_id,),
                    )
                    policy_row = cur.fetchone()
                    if policy_row is not None:
                        policy = {
                            "publish_mode_default": _normalize_publish_mode(policy_row[0]),
                            "publish_mode_by_category": _normalize_publish_mode_map(policy_row[1]),
                            "auto_publish_min_score": float(policy_row[2]),
                            "auto_publish_min_sources": int(policy_row[3]),
                            "auto_publish_require_golden": bool(policy_row[4]),
                            "auto_publish_allow_conflicts": bool(policy_row[5]),
                            "routing_policy": _normalize_gatekeeper_routing_policy(policy_row[6]),
                        }
                elif has_publish_columns:
                    cur.execute(
                        """
                        SELECT
                          publish_mode_default,
                          publish_mode_by_category,
                          auto_publish_min_score,
                          auto_publish_min_sources,
                          auto_publish_require_golden,
                          auto_publish_allow_conflicts
                        FROM gatekeeper_project_configs
                        WHERE project_id = %s
                        LIMIT 1
                        """,
                        (project_id,),
                    )
                    policy_row = cur.fetchone()
                    if policy_row is not None:
                        policy = {
                            "publish_mode_default": _normalize_publish_mode(policy_row[0]),
                            "publish_mode_by_category": _normalize_publish_mode_map(policy_row[1]),
                            "auto_publish_min_score": float(policy_row[2]),
                            "auto_publish_min_sources": int(policy_row[3]),
                            "auto_publish_require_golden": bool(policy_row[4]),
                            "auto_publish_allow_conflicts": bool(policy_row[5]),
                            "routing_policy": _normalize_gatekeeper_routing_policy(None),
                        }

                cur.execute(
                    """
                    SELECT
                      d.id::text,
                      d.claim_id::text,
                      d.decision,
                      d.status,
                      d.created_at,
                      c.category,
                      c.claim_text,
                      COALESCE(c.metadata, '{}'::jsonb),
                      p.page_type,
                      g.tier,
                      g.score,
                      g.features,
                      EXISTS (
                        SELECT 1
                        FROM wiki_conflicts wc
                        WHERE wc.claim_id = d.claim_id
                          AND wc.resolution_status = 'open'
                      ) AS has_open_conflict
                    FROM wiki_draft_changes d
                    JOIN wiki_pages p ON p.id = d.page_id
                    LEFT JOIN claims c ON c.id = d.claim_id
                    LEFT JOIN gatekeeper_decisions g ON g.claim_id = d.claim_id
                    WHERE d.project_id = %s
                      AND d.status = 'pending_review'
                    ORDER BY
                      CASE
                        WHEN lower(COALESCE(c.metadata->>'resolution_outcome', c.metadata->>'outcome', c.metadata->'operator_decision'->>'outcome', ''))
                          IN ('resolved', 'fixed', 'completed', 'success', 'mitigated', 'restored')
                        THEN 1
                        ELSE 0
                      END DESC,
                      d.created_at ASC
                    LIMIT %s
                    """,
                    (project_id, payload.limit_per_project),
                )
                rows = cur.fetchall() or []
                feedback_policy = policy["routing_policy"] if isinstance(policy.get("routing_policy"), dict) else {}
                claim_ids = [
                    str(row[1])
                    for row in rows
                    if row[1] is not None and str(row[1]).strip()
                ]
                feedback_by_claim = _load_retrieval_feedback_summary(
                    conn,
                    project_id=project_id,
                    claim_ids=claim_ids,
                    window_days=int(feedback_policy.get("retrieval_feedback_window_days", 30)),
                )

        scanned = len(rows)
        eligible = 0
        approved = 0
        failed = 0
        items: list[dict[str, Any]] = []

        for row in rows:
            draft_id_text = str(row[0])
            claim_id_text = str(row[1])
            decision = str(row[2] or "")
            category = str(row[5] or "")
            claim_text = str(row[6] or "")
            claim_metadata = row[7] if isinstance(row[7], dict) else {}
            page_type = str(row[8] or "")
            tier = str(row[9] or "")
            score = float(row[10] or 0.0)
            features = row[11] if isinstance(row[11], dict) else {}
            has_open_conflict = bool(row[12])
            source_diversity = _extract_source_diversity(features)
            assertion_class = _extract_assertion_class(features, category=category, page_type=page_type)
            routing_policy = policy["routing_policy"] if isinstance(policy.get("routing_policy"), dict) else {}
            ticket_outcome_signal = _extract_ticket_outcome_signal(claim_metadata)
            score_bonus = float(ticket_outcome_signal.get("score_bonus") or 0.0)
            effective_score = float(score) + score_bonus
            effective_min_sources = int(policy["auto_publish_min_sources"])
            if bool(ticket_outcome_signal.get("positive_outcome")) and int(ticket_outcome_signal.get("ticket_count") or 0) > 0:
                effective_min_sources = max(1, effective_min_sources - 1)
            risk = _classify_auto_publish_risk(
                assertion_class=assertion_class,
                category=category,
                page_type=page_type,
                claim_text=claim_text,
                routing_policy=routing_policy,
            )

            mode = _resolve_publish_mode_for_category(
                default_mode=str(policy["publish_mode_default"]),
                category_map=policy["publish_mode_by_category"] if isinstance(policy["publish_mode_by_category"], dict) else {},
                assertion_class_map=(
                    policy.get("routing_policy", {}).get("publish_mode_by_assertion_class")
                    if isinstance(policy.get("routing_policy"), dict)
                    else None
                ),
                assertion_class=assertion_class,
                category=category,
                page_type=page_type,
            )
            if bool(risk.get("force_human_required")):
                mode = "human_required"

            outcome = "skipped"
            reason = "human_required"
            eligible_for_auto = False

            if decision not in {"new_page", "new_section", "new_statement"}:
                reason = f"decision_not_auto_publishable:{decision or 'unknown'}"
            elif mode == "human_required":
                if bool(risk.get("force_human_required")):
                    reason = (
                        "human_required_by_risk_tier:"
                        f"{risk.get('level')}:{','.join((risk.get('high_hits') or [])[:3])}"
                    )
                else:
                    reason = "human_required_by_policy"
            else:
                eligible_for_auto = True
                if has_open_conflict and not bool(policy["auto_publish_allow_conflicts"]):
                    eligible_for_auto = False
                    reason = "open_conflict_blocked"
                elif mode == "conditional":
                    if bool(policy["auto_publish_require_golden"]) and tier != "golden_candidate":
                        eligible_for_auto = False
                        reason = f"tier_below_policy:{tier or 'unknown'}"
                    elif effective_score < float(policy["auto_publish_min_score"]):
                        eligible_for_auto = False
                        reason = (
                            f"score_below_policy:{effective_score:.4f}<{float(policy['auto_publish_min_score']):.4f}"
                        )
                    elif source_diversity < int(effective_min_sources):
                        eligible_for_auto = False
                        reason = (
                            f"source_diversity_below_policy:{source_diversity}<"
                            f"{int(effective_min_sources)}"
                        )
                    else:
                        reason = "conditional_policy_matched"
                else:
                    reason = "auto_publish_policy_matched"

                if eligible_for_auto:
                    feedback_policy = routing_policy
                    feedback = feedback_by_claim.get(claim_id_text) or {}
                    feedback_total = int(feedback.get("total", 0))
                    feedback_negative_ratio = float(feedback.get("negative_ratio", 0.0))
                    feedback_negative_balance = int(feedback.get("negative_balance", 0))
                    feedback_min_events = int(feedback_policy.get("retrieval_feedback_min_events", 3))
                    feedback_ratio_limit = float(feedback_policy.get("retrieval_feedback_block_negative_ratio", 0.7))
                    feedback_balance_limit = int(feedback_policy.get("retrieval_feedback_block_balance", 2))
                    if (
                        feedback_total >= feedback_min_events
                        and (
                            feedback_negative_ratio >= feedback_ratio_limit
                            or feedback_negative_balance >= feedback_balance_limit
                        )
                    ):
                        eligible_for_auto = False
                        reason = (
                            "retrieval_feedback_negative_bias:"
                            f"ratio={feedback_negative_ratio:.3f},balance={feedback_negative_balance},total={feedback_total}"
                        )

            if eligible_for_auto:
                eligible += 1
                if payload.dry_run:
                    outcome = "eligible_dry_run"
                else:
                    try:
                        response = approve_wiki_draft(
                            UUID(draft_id_text),
                            DraftApproveRequest(
                                project_id=project_id,
                                reviewed_by=payload.reviewed_by,
                                edited_statement_text=None,
                                section_edits=None,
                                note=(
                                    f"Auto-published by policy mode={mode}; "
                                    f"tier={tier or 'unknown'}; score={effective_score:.3f}; sources={source_diversity}"
                                ),
                                force=False,
                            ),
                            idempotency_key=f"auto-publish:{draft_id_text}",
                        )
                        outcome = "approved"
                        approved += 1
                        reason = "approved"
                    except HTTPException as exc:
                        outcome = "failed"
                        failed += 1
                        reason = f"http_{exc.status_code}:{exc.detail}"
                    except Exception as exc:  # pragma: no cover
                        outcome = "failed"
                        failed += 1
                        reason = f"error:{exc}"

            items.append(
                {
                    "draft_id": draft_id_text,
                    "claim_id": claim_id_text,
                    "category": category,
                    "page_type": page_type,
                    "assertion_class": assertion_class,
                    "decision": decision,
                    "tier": tier or None,
                    "score": score,
                    "effective_score": round(effective_score, 4),
                    "source_diversity": source_diversity,
                    "effective_min_sources": effective_min_sources,
                    "mode": mode,
                    "has_open_conflict": has_open_conflict,
                    "ticket_outcome_signal": ticket_outcome_signal,
                    "risk_tier": risk,
                    "outcome": outcome,
                    "reason": reason,
                    "retrieval_feedback": feedback_by_claim.get(claim_id_text) or None,
                }
            )

        project_results.append(
            {
                "project_id": project_id,
                "policy": policy,
                "source_ownership_advisories": source_ownership_advisories,
                "scanned": scanned,
                "eligible": eligible,
                "approved": approved,
                "failed": failed,
                "items": items,
            }
        )
        total_scanned += scanned
        total_eligible += eligible
        total_approved += approved
        total_failed += failed
        total_source_ownership_advisories += source_ownership_advisories

    return {
        "status": "ok",
        "dry_run": bool(payload.dry_run),
        "reviewed_by": payload.reviewed_by,
        "requested_projects": dedup_projects,
        "summary": {
            "projects": len(project_results),
            "scanned": total_scanned,
            "eligible": total_eligible,
            "approved": total_approved,
            "failed": total_failed,
            "source_ownership_advisories": total_source_ownership_advisories,
        },
        "projects": project_results,
        "generated_at": datetime.now(UTC).isoformat(),
    }


@app.post("/v1/wiki/drafts/bootstrap-approve/run")
def run_wiki_bootstrap_approve(payload: WikiBootstrapApproveRunRequest) -> dict[str, Any]:
    trusted_sources = _normalize_source_system_list(payload.trusted_source_systems or [])
    apply_limit_soft_cap = 200
    if int(payload.sample_size) > int(payload.limit):
        raise HTTPException(status_code=422, detail="bootstrap_sample_size_exceeds_limit")
    if not payload.dry_run:
        if bool(payload.require_trusted_sources_on_apply) and not trusted_sources:
            raise HTTPException(status_code=409, detail="bootstrap_trusted_sources_required_for_apply")
        if int(payload.limit) > apply_limit_soft_cap and not bool(payload.allow_large_batch):
            raise HTTPException(
                status_code=409,
                detail=f"bootstrap_apply_limit_exceeded:{int(payload.limit)}>{apply_limit_soft_cap}",
            )
    with get_conn() as conn:
        source_ownership_advisories = 0
        if _source_ownership_table_exists(conn):
            ownership_policies = _load_source_ownership_policies(conn, payload.project_id)
            ownership_check = _enforce_source_ownership_write(
                policies_by_domain=ownership_policies,
                project_id=payload.project_id,
                domain="synapse_wiki",
                source_system=_normalize_source_system(payload.source_system),
                endpoint="/v1/wiki/drafts/bootstrap-approve/run",
            )
            if ownership_check.get("status") == "advisory":
                source_ownership_advisories += 1

        with conn.cursor() as cur:
            if trusted_sources:
                cur.execute(
                    """
                    SELECT
                      d.id::text,
                      d.claim_id::text,
                      d.page_id::text,
                      d.section_key,
                      d.decision,
                      d.confidence,
                      d.created_at
                    FROM wiki_draft_changes d
                    WHERE d.project_id = %s
                      AND d.status = 'pending_review'
                      AND d.decision IN ('new_page', 'new_section', 'new_statement')
                      AND d.confidence >= %s
                      AND (
                        %s::bool = FALSE
                        OR NOT EXISTS (
                          SELECT 1
                          FROM wiki_conflicts wc
                          WHERE wc.claim_id = d.claim_id
                            AND wc.resolution_status = 'open'
                        )
                      )
                      AND EXISTS (
                        SELECT 1
                        FROM jsonb_array_elements(COALESCE(d.evidence, '[]'::jsonb)) ev
                        WHERE lower(
                          COALESCE(
                            NULLIF(ev->>'source_system', ''),
                            NULLIF(ev->'metadata'->>'source_system', ''),
                            NULLIF(ev->'metadata'->>'source', '')
                          )
                        ) = ANY(%s::text[])
                      )
                    ORDER BY d.confidence DESC, d.created_at ASC
                    LIMIT %s
                    """,
                    (
                        payload.project_id,
                        float(payload.min_confidence),
                        bool(payload.require_conflict_free),
                        trusted_sources,
                        int(payload.limit),
                    ),
                )
            else:
                cur.execute(
                    """
                    SELECT
                      d.id::text,
                      d.claim_id::text,
                      d.page_id::text,
                      d.section_key,
                      d.decision,
                      d.confidence,
                      d.created_at
                    FROM wiki_draft_changes d
                    WHERE d.project_id = %s
                      AND d.status = 'pending_review'
                      AND d.decision IN ('new_page', 'new_section', 'new_statement')
                      AND d.confidence >= %s
                      AND (
                        %s::bool = FALSE
                        OR NOT EXISTS (
                          SELECT 1
                          FROM wiki_conflicts wc
                          WHERE wc.claim_id = d.claim_id
                            AND wc.resolution_status = 'open'
                        )
                      )
                    ORDER BY d.confidence DESC, d.created_at ASC
                    LIMIT %s
                    """,
                    (
                        payload.project_id,
                        float(payload.min_confidence),
                        bool(payload.require_conflict_free),
                        int(payload.limit),
                    ),
                )
            rows = cur.fetchall() or []

    candidates = [
        {
            "draft_id": row[0],
            "claim_id": row[1],
            "page_id": row[2],
            "section_key": row[3],
            "decision": row[4],
            "confidence": float(row[5]),
            "created_at": row[6].isoformat() if row[6] is not None else None,
        }
        for row in rows
    ]
    sample = candidates[: max(1, int(payload.sample_size))]
    if payload.dry_run:
        response: dict[str, Any] = {
            "status": "ok",
            "dry_run": True,
            "project_id": payload.project_id,
            "reviewed_by": payload.reviewed_by,
            "source_system": _normalize_source_system(payload.source_system),
            "selection": {
                "limit": int(payload.limit),
                "min_confidence": float(payload.min_confidence),
                "require_conflict_free": bool(payload.require_conflict_free),
                "trusted_source_systems": trusted_sources,
                "allow_large_batch": bool(payload.allow_large_batch),
                "require_trusted_sources_on_apply": bool(payload.require_trusted_sources_on_apply),
            },
            "safety": {
                "apply_limit_soft_cap": apply_limit_soft_cap,
                "trusted_sources_required_on_apply": bool(payload.require_trusted_sources_on_apply),
                "next_step": "Run apply only after validating sample quality from dry-run.",
            },
            "summary": {
                "candidates": len(candidates),
                "sample_size": len(sample),
                "source_ownership_advisories": source_ownership_advisories,
            },
            "sample": sample,
            "generated_at": datetime.now(UTC).isoformat(),
        }
        if source_ownership_advisories > 0:
            response["source_ownership_advisories"] = source_ownership_advisories
        return response

    approved = 0
    failed = 0
    items: list[dict[str, Any]] = []
    for item in candidates:
        draft_id_text = str(item["draft_id"])
        try:
            approve_wiki_draft(
                UUID(draft_id_text),
                DraftApproveRequest(
                    project_id=payload.project_id,
                    reviewed_by=payload.reviewed_by,
                    note=(
                        "Bootstrap migration approval (trusted source flow). "
                        f"min_confidence={float(payload.min_confidence):.2f}; "
                        f"require_conflict_free={bool(payload.require_conflict_free)}"
                    ),
                ),
                source_system=payload.source_system,
                idempotency_key=f"bootstrap-approve:{draft_id_text}",
            )
            approved += 1
            items.append({**item, "outcome": "approved"})
        except HTTPException as exc:
            failed += 1
            items.append({**item, "outcome": "failed", "reason": f"http_{exc.status_code}:{exc.detail}"})
        except Exception as exc:  # pragma: no cover
            failed += 1
            items.append({**item, "outcome": "failed", "reason": f"error:{exc}"})

    response = {
        "status": "ok",
        "dry_run": False,
        "project_id": payload.project_id,
        "reviewed_by": payload.reviewed_by,
        "source_system": _normalize_source_system(payload.source_system),
        "selection": {
            "limit": int(payload.limit),
            "min_confidence": float(payload.min_confidence),
            "require_conflict_free": bool(payload.require_conflict_free),
            "trusted_source_systems": trusted_sources,
            "allow_large_batch": bool(payload.allow_large_batch),
            "require_trusted_sources_on_apply": bool(payload.require_trusted_sources_on_apply),
        },
        "safety": {
            "apply_limit_soft_cap": apply_limit_soft_cap,
            "trusted_sources_required_on_apply": bool(payload.require_trusted_sources_on_apply),
            "rollback_hint": {
                "moderation_actions_endpoint": f"/v1/wiki/moderation/actions?project_id={quote(payload.project_id)}",
                "note": "Use moderation audit feed and page history to revert unintended bootstrap approvals.",
            },
        },
        "summary": {
            "candidates": len(candidates),
            "approved": approved,
            "failed": failed,
            "source_ownership_advisories": source_ownership_advisories,
        },
        "items": items,
        "generated_at": datetime.now(UTC).isoformat(),
    }
    if source_ownership_advisories > 0:
        response["source_ownership_advisories"] = source_ownership_advisories
    return response


@app.get("/v1/wiki/drafts/bootstrap-approve/recommendation")
def get_wiki_bootstrap_approve_recommendation(project_id: str) -> dict[str, Any]:
    fallback_trusted_sources = ["legacy_import", "postgres_sql"]
    trusted_sources: set[str] = set()
    ownership_sources: set[str] = set()
    legacy_source_types: set[str] = set()
    legacy_declared_source_systems: set[str] = set()
    used_fallback_sources = False
    open_queue_count = 0
    blocked_conflict_count = 0
    open_conflicts = 0
    batches_recent = 0
    processed_events = 0
    generated_claims = 0
    dropped_event_like = 0
    kept_durable = 0
    trusted_bypass = 0

    with get_conn() as conn:
        if _source_ownership_table_exists(conn):
            policies = _load_source_ownership_policies(conn, project_id)
            for domain_key in ("runtime_memory", "ops_kb_static"):
                policy = policies.get(domain_key)
                if not isinstance(policy, dict):
                    continue
                write_master = _normalize_source_system(policy.get("write_master"), default="")
                if write_master:
                    trusted_sources.add(write_master)
                    ownership_sources.add(write_master)
                for item in _normalize_source_system_list(policy.get("allowed_source_systems") or []):
                    trusted_sources.add(item)
                    ownership_sources.add(item)

        if _legacy_import_sources_table_exists(conn):
            with conn.cursor() as cur:
                cur.execute(
                    """
                    SELECT source_type, config
                    FROM legacy_import_sources
                    WHERE project_id = %s
                      AND enabled = TRUE
                    ORDER BY updated_at DESC
                    LIMIT 200
                    """,
                    (project_id,),
                )
                rows = cur.fetchall() or []
            for row in rows:
                source_type = _normalize_source_system(row[0], default="")
                if source_type:
                    trusted_sources.add(source_type)
                    legacy_source_types.add(source_type)
                config = row[1] if isinstance(row[1], dict) else {}
                for key in ("source_system", "sql_source_id_prefix", "wal_source_id_prefix"):
                    value = _normalize_source_system(config.get(key), default="")
                    if value:
                        trusted_sources.add(value)
                        legacy_declared_source_systems.add(value)

        if not trusted_sources:
            used_fallback_sources = True
            trusted_sources = set(fallback_trusted_sources)

        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  COUNT(*) FILTER (
                    WHERE status = 'pending_review'
                      AND decision IN ('new_page', 'new_section', 'new_statement')
                  ),
                  COUNT(*) FILTER (
                    WHERE status = 'blocked_conflict'
                  )
                FROM wiki_draft_changes
                WHERE project_id = %s
                """,
                (project_id,),
            )
            queue_row = cur.fetchone() or (0, 0)
            open_queue_count = int(queue_row[0] or 0)
            blocked_conflict_count = int(queue_row[1] or 0)

            cur.execute(
                """
                SELECT COUNT(*)
                FROM wiki_conflicts
                WHERE project_id = %s
                  AND resolution_status = 'open'
                """,
                (project_id,),
            )
            conflict_row = cur.fetchone()
            open_conflicts = int(conflict_row[0] or 0) if conflict_row else 0

            if _memory_backfill_batches_table_exists(conn):
                if _backfill_batch_has_decision_counters(conn):
                    cur.execute(
                        """
                        SELECT
                          COUNT(*),
                          COALESCE(SUM(processed_events), 0),
                          COALESCE(SUM(generated_claims), 0),
                          COALESCE(SUM(dropped_event_like), 0),
                          COALESCE(SUM(kept_durable), 0),
                          COALESCE(SUM(trusted_bypass), 0)
                        FROM memory_backfill_batches
                        WHERE project_id = %s
                          AND updated_at >= NOW() - INTERVAL '30 days'
                        """,
                        (project_id,),
                    )
                    batch_row = cur.fetchone() or (0, 0, 0, 0, 0, 0)
                    batches_recent = int(batch_row[0] or 0)
                    processed_events = int(batch_row[1] or 0)
                    generated_claims = int(batch_row[2] or 0)
                    dropped_event_like = int(batch_row[3] or 0)
                    kept_durable = int(batch_row[4] or 0)
                    trusted_bypass = int(batch_row[5] or 0)
                else:
                    cur.execute(
                        """
                        SELECT
                          COUNT(*),
                          COALESCE(SUM(processed_events), 0),
                          COALESCE(SUM(generated_claims), 0)
                        FROM memory_backfill_batches
                        WHERE project_id = %s
                          AND updated_at >= NOW() - INTERVAL '30 days'
                        """,
                        (project_id,),
                    )
                    batch_row = cur.fetchone() or (0, 0, 0)
                    batches_recent = int(batch_row[0] or 0)
                    processed_events = int(batch_row[1] or 0)
                    generated_claims = int(batch_row[2] or 0)

    queue_total = open_queue_count + blocked_conflict_count
    if queue_total >= 300:
        limit = 25
    elif queue_total >= 100:
        limit = 40
    else:
        limit = 50
    if open_conflicts >= 20:
        limit = min(limit, 25)
    elif open_conflicts >= 5:
        limit = min(limit, 40)
    limit = max(10, min(200, int(limit)))

    event_drop_ratio = float(dropped_event_like) / float(max(processed_events, 1))
    durable_keep_ratio = float(kept_durable + trusted_bypass) / float(max(processed_events, 1))
    min_confidence = 0.90
    if processed_events > 0:
        if event_drop_ratio >= 0.7:
            min_confidence = 0.95
        elif event_drop_ratio >= 0.5:
            min_confidence = 0.93
        elif durable_keep_ratio >= 0.55 and event_drop_ratio <= 0.35:
            min_confidence = 0.85
        elif durable_keep_ratio >= 0.4:
            min_confidence = 0.88
    require_conflict_free = open_conflicts > 0 or blocked_conflict_count > 0 or event_drop_ratio >= 0.45
    sample_size = max(10, min(20, int(round(limit / 2))))

    notes: list[str] = []
    if used_fallback_sources:
        notes.append("No configured legacy/source-ownership systems found; fallback trusted sources were applied.")
    if open_conflicts > 0:
        notes.append(f"Open conflicts detected ({open_conflicts}); conflict-free filter stays enabled.")
    if processed_events == 0:
        notes.append("Backfill quality counters are not available yet; conservative confidence default is used.")
    elif event_drop_ratio >= 0.5:
        notes.append("High event-like drop ratio observed; confidence threshold was raised.")
    elif durable_keep_ratio >= 0.55:
        notes.append("Durable-signal ratio is healthy; confidence threshold was relaxed for faster migration.")

    return {
        "status": "ok",
        "project_id": project_id,
        "recommended": {
            "limit": limit,
            "sample_size": sample_size,
            "min_confidence": round(float(min_confidence), 2),
            "require_conflict_free": bool(require_conflict_free),
            "trusted_source_systems": sorted(trusted_sources),
            "require_trusted_sources_on_apply": True,
            "allow_large_batch": False,
            "dry_run": True,
        },
        "diagnostics": {
            "queue": {
                "open_pending_review": open_queue_count,
                "blocked_conflict": blocked_conflict_count,
                "open_conflicts": open_conflicts,
            },
            "backfill_quality": {
                "batches_recent": batches_recent,
                "processed_events": processed_events,
                "generated_claims": generated_claims,
                "dropped_event_like": dropped_event_like,
                "kept_durable": kept_durable,
                "trusted_bypass": trusted_bypass,
                "event_drop_ratio": round(float(event_drop_ratio), 4),
                "durable_keep_ratio": round(float(durable_keep_ratio), 4),
            },
            "sources": {
                "ownership_sources": sorted(ownership_sources),
                "legacy_source_types": sorted(legacy_source_types),
                "legacy_declared_source_systems": sorted(legacy_declared_source_systems),
                "fallback_used": used_fallback_sources,
            },
            "notes": notes,
        },
        "safety": {
            "apply_limit_soft_cap": 200,
            "rollback_hint": {
                "moderation_actions_endpoint": f"/v1/wiki/moderation/actions?project_id={quote(project_id)}",
                "note": "Use moderation audit feed and page history to revert unintended bootstrap approvals.",
            },
        },
        "generated_at": datetime.now(UTC).isoformat(),
    }


@app.get("/v1/wiki/moderation/actions")
def list_moderation_actions(
    project_id: str,
    action_type: str | None = Query(default=None, pattern="^(approve|reject)$"),
    reviewed_by: str | None = Query(default=None),
    draft_id: UUID | None = Query(default=None),
    limit: int = Query(default=100, ge=1, le=500),
) -> dict[str, Any]:
    filters = ["project_id = %s"]
    params: list[Any] = [project_id]
    if action_type is not None:
        filters.append("action_type = %s")
        params.append(action_type)
    if reviewed_by is not None:
        filters.append("reviewed_by = %s")
        params.append(reviewed_by)
    if draft_id is not None:
        filters.append("draft_id = %s")
        params.append(draft_id)
    params.append(limit)
    where_clause = " AND ".join(filters)

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                f"""
                SELECT
                  id::text,
                  draft_id::text,
                  claim_id::text,
                  page_id::text,
                  action_type,
                  reviewed_by,
                  decision_before,
                  decision_after,
                  draft_status_before,
                  draft_status_after,
                  note,
                  reason,
                  payload,
                  result,
                  created_at
                FROM moderation_actions
                WHERE {where_clause}
                ORDER BY created_at DESC
                LIMIT %s
                """,
                tuple(params),
            )
            rows = cur.fetchall()

    actions = [
        {
            "id": row[0],
            "draft_id": row[1],
            "claim_id": row[2],
            "page_id": row[3],
            "action_type": row[4],
            "reviewed_by": row[5],
            "decision_before": row[6],
            "decision_after": row[7],
            "draft_status_before": row[8],
            "draft_status_after": row[9],
            "note": row[10],
            "reason": row[11],
            "payload": row[12],
            "result": row[13],
            "created_at": row[14].isoformat(),
        }
        for row in rows
    ]
    return {"actions": actions}


@app.get("/v1/wiki/moderation/throughput")
def get_wiki_moderation_throughput(
    project_id: str,
    window_hours: int = Query(default=24, ge=1, le=24 * 30),
    top_reviewers: int = Query(default=5, ge=1, le=20),
) -> dict[str, Any]:
    cutoff = datetime.now(UTC) - timedelta(hours=window_hours)

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  COUNT(*) FILTER (WHERE ma.action_type = 'approve')::int AS approvals,
                  COUNT(*) FILTER (WHERE ma.action_type = 'reject')::int AS rejections,
                  COUNT(*)::int AS actions_total,
                  COUNT(DISTINCT ma.reviewed_by)::int AS reviewers_active,
                  COUNT(*) FILTER (
                    WHERE ma.draft_status_before = 'blocked_conflict'
                  )::int AS conflict_unblocks
                FROM moderation_actions ma
                WHERE ma.project_id = %s
                  AND ma.created_at >= %s
                """,
                (project_id, cutoff),
            )
            summary_row = cur.fetchone()

            cur.execute(
                """
                SELECT
                  AVG(EXTRACT(EPOCH FROM (ma.created_at - d.created_at)) / 60.0) AS avg_minutes,
                  percentile_cont(0.5) WITHIN GROUP (
                    ORDER BY EXTRACT(EPOCH FROM (ma.created_at - d.created_at)) / 60.0
                  ) AS p50_minutes,
                  percentile_cont(0.9) WITHIN GROUP (
                    ORDER BY EXTRACT(EPOCH FROM (ma.created_at - d.created_at)) / 60.0
                  ) AS p90_minutes
                FROM moderation_actions ma
                JOIN wiki_draft_changes d ON d.id = ma.draft_id
                WHERE ma.project_id = %s
                  AND ma.created_at >= %s
                  AND ma.action_type IN ('approve', 'reject')
                  AND ma.created_at >= d.created_at
                """,
                (project_id, cutoff),
            )
            latency_row = cur.fetchone()

            cur.execute(
                """
                SELECT
                  COUNT(*) FILTER (WHERE status = 'pending_review')::int AS pending_review,
                  COUNT(*) FILTER (WHERE status = 'blocked_conflict')::int AS blocked_conflict,
                  COUNT(*) FILTER (WHERE status IN ('pending_review', 'blocked_conflict'))::int AS open_total
                FROM wiki_draft_changes
                WHERE project_id = %s
                """,
                (project_id,),
            )
            backlog_row = cur.fetchone()

            cur.execute(
                """
                SELECT COUNT(*)::int
                FROM wiki_draft_changes
                WHERE project_id = %s
                  AND created_at >= %s
                """,
                (project_id, cutoff),
            )
            created_row = cur.fetchone()

            cur.execute(
                """
                SELECT
                  reviewed_by,
                  COUNT(*)::int AS actions_total,
                  COUNT(*) FILTER (WHERE action_type = 'approve')::int AS approvals,
                  COUNT(*) FILTER (WHERE action_type = 'reject')::int AS rejections
                FROM moderation_actions
                WHERE project_id = %s
                  AND created_at >= %s
                GROUP BY reviewed_by
                ORDER BY actions_total DESC, reviewed_by ASC
                LIMIT %s
                """,
                (project_id, cutoff, top_reviewers),
            )
            reviewer_rows = cur.fetchall()

    approvals = int((summary_row[0] if summary_row else 0) or 0)
    rejections = int((summary_row[1] if summary_row else 0) or 0)
    actions_total = int((summary_row[2] if summary_row else 0) or 0)
    reviewers_active = int((summary_row[3] if summary_row else 0) or 0)
    conflict_unblocks = int((summary_row[4] if summary_row else 0) or 0)

    avg_minutes = float(latency_row[0]) if latency_row and latency_row[0] is not None else None
    p50_minutes = float(latency_row[1]) if latency_row and latency_row[1] is not None else None
    p90_minutes = float(latency_row[2]) if latency_row and latency_row[2] is not None else None

    pending_review = int((backlog_row[0] if backlog_row else 0) or 0)
    blocked_conflict = int((backlog_row[1] if backlog_row else 0) or 0)
    open_total = int((backlog_row[2] if backlog_row else 0) or 0)
    drafts_created = int((created_row[0] if created_row else 0) or 0)

    approval_rate = round(approvals / actions_total, 4) if actions_total > 0 else None
    processed_per_hour = round(actions_total / max(1, window_hours), 3)
    net_backlog_delta = int(drafts_created - actions_total)

    alerts: list[str] = []
    health = "healthy"
    if actions_total == 0 and open_total >= 10:
        alerts.append("No moderation actions in selected window while backlog remains open.")
    if blocked_conflict >= 8:
        alerts.append("Blocked conflicts are high; prioritize conflict resolution queue.")
    if p90_minutes is not None and p90_minutes >= 24 * 60:
        alerts.append("p90 moderation latency is above 24 hours.")

    if (actions_total == 0 and open_total >= 10) or open_total >= 40:
        health = "critical"
    elif blocked_conflict >= 8 or open_total >= 15 or (p90_minutes is not None and p90_minutes >= 12 * 60):
        health = "watch"

    return {
        "project_id": project_id,
        "window_hours": int(window_hours),
        "since": cutoff.isoformat(),
        "generated_at": datetime.now(UTC).isoformat(),
        "health": health,
        "alerts": alerts,
        "metrics": {
            "actions_total": actions_total,
            "approvals": approvals,
            "rejections": rejections,
            "approval_rate": approval_rate,
            "reviewers_active": reviewers_active,
            "processed_per_hour": processed_per_hour,
            "drafts_created": drafts_created,
            "net_backlog_delta": net_backlog_delta,
            "conflict_unblocks": conflict_unblocks,
            "latency_minutes": {
                "avg": round(float(avg_minutes), 2) if avg_minutes is not None else None,
                "p50": round(float(p50_minutes), 2) if p50_minutes is not None else None,
                "p90": round(float(p90_minutes), 2) if p90_minutes is not None else None,
            },
        },
        "backlog": {
            "open_total": open_total,
            "pending_review": pending_review,
            "blocked_conflict": blocked_conflict,
        },
        "top_reviewers": [
            {
                "reviewed_by": row[0],
                "actions_total": int(row[1] or 0),
                "approvals": int(row[2] or 0),
                "rejections": int(row[3] or 0),
            }
            for row in reviewer_rows
        ],
    }


@app.get("/v1/gatekeeper/decisions")
def list_gatekeeper_decisions(
    project_id: str,
    tier: str | None = Query(default=None),
    limit: int = Query(default=50, ge=1, le=200),
) -> dict[str, Any]:
    with get_conn() as conn:
        with conn.cursor() as cur:
            if tier is None:
                cur.execute(
                    """
                    SELECT claim_id::text, tier, score, rationale, features, updated_at
                    FROM gatekeeper_decisions
                    WHERE project_id = %s
                    ORDER BY updated_at DESC
                    LIMIT %s
                    """,
                    (project_id, limit),
                )
            else:
                cur.execute(
                    """
                    SELECT claim_id::text, tier, score, rationale, features, updated_at
                    FROM gatekeeper_decisions
                    WHERE project_id = %s
                      AND tier = %s
                    ORDER BY updated_at DESC
                    LIMIT %s
                    """,
                    (project_id, tier, limit),
                )
            rows = cur.fetchall()
    decisions = [
        {
            "claim_id": row[0],
            "tier": row[1],
            "score": float(row[2]),
            "rationale": row[3],
            "features": row[4],
            "updated_at": row[5].isoformat(),
        }
        for row in rows
    ]
    return {"decisions": decisions}


@app.get("/v1/adoption/rejections/diagnostics")
def get_adoption_rejection_diagnostics(
    project_id: str,
    days: int = Query(default=14, ge=1, le=90),
    sample_limit: int = Query(default=5, ge=1, le=25),
) -> dict[str, Any]:
    cutoff = datetime.now(UTC) - timedelta(days=days)

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  d.claim_id::text,
                  d.rationale,
                  d.features,
                  d.updated_at,
                  c.entity_key,
                  c.category,
                  c.claim_text
                FROM gatekeeper_decisions d
                LEFT JOIN claims c ON c.id = d.claim_id AND c.project_id = d.project_id
                WHERE d.project_id = %s
                  AND d.tier = 'operational_memory'
                  AND d.updated_at >= %s
                ORDER BY d.updated_at DESC
                LIMIT 2000
                """,
                (project_id, cutoff),
            )
            rows = cur.fetchall() or []

    reason_counts: dict[str, int] = {}
    blocked_source_type_counts: dict[str, int] = {}
    blocked_source_system_counts: dict[str, int] = {}
    blocked_tool_counts: dict[str, int] = {}
    examples: list[dict[str, Any]] = []

    def _bump(counter: dict[str, int], key: str | None) -> None:
        text = str(key or "").strip().lower()
        if not text:
            return
        counter[text] = int(counter.get(text, 0)) + 1

    def _bump_many(counter: dict[str, int], values: Any) -> None:
        if not isinstance(values, list):
            return
        for value in values:
            _bump(counter, str(value or ""))

    def _reason_tags(features: dict[str, Any], rationale: str) -> list[str]:
        tags: list[str] = []
        if bool(features.get("blocked_by_source_id")):
            tags.append("blocked_source_id")
        if bool(features.get("blocked_by_source_type")):
            tags.append("blocked_source_type")
        if bool(features.get("blocked_by_source_system")):
            tags.append("blocked_source_system")
        if bool(features.get("blocked_by_category")):
            tags.append("blocked_category")
        if bool(features.get("blocked_by_entity")):
            tags.append("blocked_entity")
        if bool(features.get("has_event_stream_shape")):
            tags.append("event_stream_shape")
        if bool(features.get("backfill_without_durable_signal")):
            tags.append("backfill_without_durable_signal")
        if bool(features.get("insufficient_support")):
            tags.append("insufficient_support")
        if bool(features.get("looks_like_runtime_noise")):
            tags.append("runtime_noise")
        if not tags and bool(features.get("routing_hard_block")):
            tags.append("routing_hard_block")
        if not tags and rationale:
            tags.append("rationale_only")
        return tags

    for row in rows:
        claim_id = str(row[0] or "")
        rationale = str(row[1] or "").strip()
        features = row[2] if isinstance(row[2], dict) else {}
        updated_at = row[3]
        entity_key = str(row[4] or "")
        category = str(row[5] or "")
        claim_text = str(row[6] or "")

        tags = _reason_tags(features, rationale)
        for tag in tags:
            _bump(reason_counts, tag)

        _bump_many(blocked_source_type_counts, features.get("incoming_source_types"))
        _bump_many(blocked_source_system_counts, features.get("incoming_source_systems"))
        _bump_many(blocked_tool_counts, features.get("incoming_tool_names"))

        if len(examples) < sample_limit:
            examples.append(
                {
                    "claim_id": claim_id,
                    "entity_key": entity_key,
                    "category": category,
                    "reason_tags": tags,
                    "rationale": rationale,
                    "updated_at": updated_at.isoformat() if updated_at is not None else None,
                    "claim_text_snippet": claim_text[:240],
                }
            )

    def _top(counter: dict[str, int], *, limit: int = 8) -> list[dict[str, Any]]:
        return [
            {"key": key, "count": int(count)}
            for key, count in sorted(counter.items(), key=lambda item: (-item[1], item[0]))[:limit]
        ]

    top_reasons = _top(reason_counts, limit=10)
    top_source_types = _top(blocked_source_type_counts, limit=10)
    top_source_systems = _top(blocked_source_system_counts, limit=10)
    top_tool_names = _top(blocked_tool_counts, limit=10)

    suggestions: list[dict[str, str]] = []
    reason_top_keys = {item["key"] for item in top_reasons[:5]}
    if "blocked_source_type" in reason_top_keys or "blocked_source_system" in reason_top_keys:
        suggestions.append(
            {
                "knob": "routing_policy.blocked_source_type_keywords / blocked_source_system_keywords",
                "hint": "Use `/v1/backfill/knowledge` for curated memory imports instead of event lane defaults.",
            }
        )
    if "event_stream_shape" in reason_top_keys:
        suggestions.append(
            {
                "knob": "routing_policy.event_stream_min_*",
                "hint": "Snapshot-like payloads dominate; pre-filter order/telemetry events before backfill.",
            }
        )
    if "backfill_without_durable_signal" in reason_top_keys:
        suggestions.append(
            {
                "knob": "routing_policy.min_durable_signal_hits_for_backfill / backfill_requires_policy_signal",
                "hint": "For first migration, use bootstrap profile with softer durable-signal thresholds.",
            }
        )
    if "insufficient_support" in reason_top_keys:
        suggestions.append(
            {
                "knob": "routing_policy.min_sources_for_wiki_candidate / min_evidence_for_wiki_candidate",
                "hint": "Many records are single-source; bootstrap import should apply curated auto-approve sampling.",
            }
        )
    if not suggestions:
        suggestions.append(
            {
                "knob": "routing_policy",
                "hint": "No dominant reject pattern detected; inspect sample rejections and adjust policy by reason tags.",
            }
        )

    return {
        "project_id": project_id,
        "window_days": int(days),
        "since": cutoff.isoformat(),
        "generated_at": datetime.now(UTC).isoformat(),
        "summary": {
            "rejected_total": len(rows),
            "sampled_examples": len(examples),
        },
        "top_reject_reasons": top_reasons,
        "top_blocked_patterns": {
            "source_types": top_source_types,
            "source_systems": top_source_systems,
            "tool_names": top_tool_names,
        },
        "examples": examples,
        "suggested_policy_knobs": suggestions,
    }


@app.get("/v1/adoption/pipeline/visibility")
def get_adoption_pipeline_visibility(
    project_id: str,
    days: int = Query(default=14, ge=1, le=90),
    source_systems: str | None = Query(default=None),
    namespaces: str | None = Query(default=None),
) -> dict[str, Any]:
    source_filters = _normalize_source_system_csv(source_systems)
    namespace_filters = _normalize_namespace_csv(namespaces)
    cutoff = datetime.now(UTC) - timedelta(days=days)

    accepted_records = 0
    events_total = 0
    claims_total = 0
    drafts_total = 0
    pages_total = 0
    queue_pending_review = 0
    queue_blocked_conflict = 0
    rejected_event_like = 0
    accepted_source = "events_estimated"

    with get_conn() as conn:
        with conn.cursor() as cur:
            if _memory_backfill_batches_table_exists(conn):
                params: list[Any] = [project_id, cutoff]
                where_sql = ["project_id = %s", "updated_at >= %s"]
                if source_filters:
                    where_sql.append("LOWER(source_system) = ANY(%s::text[])")
                    params.append(source_filters)
                if _backfill_batch_has_decision_counters(conn):
                    cur.execute(
                        f"""
                        SELECT
                          COALESCE(SUM(total_items), 0)::bigint,
                          COALESCE(SUM(inserted_events), 0)::bigint,
                          COALESCE(SUM(generated_claims), 0)::bigint,
                          COALESCE(SUM(dropped_event_like), 0)::bigint
                        FROM memory_backfill_batches
                        WHERE {' AND '.join(where_sql)}
                        """,
                        tuple(params),
                    )
                    row = cur.fetchone() or (0, 0, 0, 0)
                else:
                    cur.execute(
                        f"""
                        SELECT
                          COALESCE(SUM(total_items), 0)::bigint,
                          COALESCE(SUM(inserted_events), 0)::bigint,
                          COALESCE(SUM(generated_claims), 0)::bigint
                        FROM memory_backfill_batches
                        WHERE {' AND '.join(where_sql)}
                        """,
                        tuple(params),
                    )
                    batch_row = cur.fetchone() or (0, 0, 0)
                    row = (batch_row[0], batch_row[1], batch_row[2], 0)
                batch_total_items = int(row[0] or 0)
                rejected_event_like = int(row[3] or 0)
                if not namespace_filters:
                    accepted_records = batch_total_items
                    accepted_source = "memory_backfill_batches"

            event_filters = ["e.project_id = %s", "e.event_type = 'memory_backfill'", "e.observed_at >= %s"]
            event_params: list[Any] = [project_id, cutoff]
            if source_filters:
                event_filters.append(
                    """
                    LOWER(
                      COALESCE(
                        NULLIF(e.payload->'backfill'->>'source_system', ''),
                        NULLIF(e.payload->>'source_system', ''),
                        NULLIF(e.payload->'metadata'->>'source_system', ''),
                        NULLIF(e.payload->'metadata'->>'source', '')
                      )
                    ) = ANY(%s::text[])
                    """.strip()
                )
                event_params.append(source_filters)
            if namespace_filters:
                event_filters.append(
                    """
                    LOWER(
                      COALESCE(
                        NULLIF(e.payload->'metadata'->>'namespace', ''),
                        NULLIF(e.payload->>'namespace', ''),
                        NULLIF(e.payload->'metadata'->>'source_namespace', '')
                      )
                    ) = ANY(%s::text[])
                    """.strip()
                )
                event_params.append(namespace_filters)
            cur.execute(
                f"""
                SELECT COUNT(*)::bigint
                FROM events e
                WHERE {' AND '.join(event_filters)}
                """,
                tuple(event_params),
            )
            event_row = cur.fetchone()
            events_total = int((event_row[0] if event_row else 0) or 0)
            if accepted_records <= 0:
                accepted_records = events_total
                accepted_source = "events_estimated"

            if _public_table_exists(conn, "claims"):
                claim_filters = ["c.project_id = %s", "c.created_at >= %s"]
                claim_params: list[Any] = [project_id, cutoff]
                if source_filters or namespace_filters:
                    evidence_filters: list[str] = []
                    if source_filters:
                        evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        claim_params.append(source_filters)
                    if namespace_filters:
                        evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->'metadata'->>'namespace', ''),
                                NULLIF(ev->>'namespace', ''),
                                NULLIF(ev->'metadata'->>'source_namespace', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        claim_params.append(namespace_filters)
                    claim_filters.append(
                        f"""
                        EXISTS (
                          SELECT 1
                          FROM jsonb_array_elements(COALESCE(c.evidence, '[]'::jsonb)) ev
                          WHERE {' AND '.join(evidence_filters)}
                        )
                        """.strip()
                    )
                cur.execute(
                    f"""
                    SELECT COUNT(*)::bigint
                    FROM claims c
                    WHERE {' AND '.join(claim_filters)}
                    """,
                    tuple(claim_params),
                )
                claim_row = cur.fetchone()
                claims_total = int((claim_row[0] if claim_row else 0) or 0)

            if _public_table_exists(conn, "wiki_draft_changes"):
                draft_filters = ["d.project_id = %s", "d.created_at >= %s"]
                draft_params: list[Any] = [project_id, cutoff]
                if source_filters or namespace_filters:
                    draft_evidence_filters: list[str] = []
                    if source_filters:
                        draft_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        draft_params.append(source_filters)
                    if namespace_filters:
                        draft_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->'metadata'->>'namespace', ''),
                                NULLIF(ev->>'namespace', ''),
                                NULLIF(ev->'metadata'->>'source_namespace', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        draft_params.append(namespace_filters)
                    draft_filters.append(
                        f"""
                        EXISTS (
                          SELECT 1
                          FROM jsonb_array_elements(COALESCE(d.evidence, '[]'::jsonb)) ev
                          WHERE {' AND '.join(draft_evidence_filters)}
                        )
                        """.strip()
                    )
                cur.execute(
                    f"""
                    SELECT COUNT(*)::bigint
                    FROM wiki_draft_changes d
                    WHERE {' AND '.join(draft_filters)}
                    """,
                    tuple(draft_params),
                )
                draft_row = cur.fetchone()
                drafts_total = int((draft_row[0] if draft_row else 0) or 0)

            if _public_table_exists(conn, "moderation_actions") and _public_table_exists(conn, "wiki_draft_changes"):
                page_filters = [
                    "ma.project_id = %s",
                    "ma.action_type = 'approve'",
                    "ma.created_at >= %s",
                    "d.page_id IS NOT NULL",
                ]
                page_params: list[Any] = [project_id, cutoff]
                if source_filters or namespace_filters:
                    page_evidence_filters: list[str] = []
                    if source_filters:
                        page_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        page_params.append(source_filters)
                    if namespace_filters:
                        page_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->'metadata'->>'namespace', ''),
                                NULLIF(ev->>'namespace', ''),
                                NULLIF(ev->'metadata'->>'source_namespace', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        page_params.append(namespace_filters)
                    page_filters.append(
                        f"""
                        EXISTS (
                          SELECT 1
                          FROM jsonb_array_elements(COALESCE(d.evidence, '[]'::jsonb)) ev
                          WHERE {' AND '.join(page_evidence_filters)}
                        )
                        """.strip()
                    )
                cur.execute(
                    f"""
                    SELECT COUNT(DISTINCT d.page_id)::bigint
                    FROM moderation_actions ma
                    JOIN wiki_draft_changes d ON d.id = ma.draft_id
                    WHERE {' AND '.join(page_filters)}
                    """,
                    tuple(page_params),
                )
                page_row = cur.fetchone()
                pages_total = int((page_row[0] if page_row else 0) or 0)

            if _public_table_exists(conn, "wiki_draft_changes"):
                queue_filters = ["project_id = %s", "status IN ('pending_review', 'blocked_conflict')"]
                queue_params: list[Any] = [project_id]
                if source_filters or namespace_filters:
                    queue_evidence_filters: list[str] = []
                    if source_filters:
                        queue_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        queue_params.append(source_filters)
                    if namespace_filters:
                        queue_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->'metadata'->>'namespace', ''),
                                NULLIF(ev->>'namespace', ''),
                                NULLIF(ev->'metadata'->>'source_namespace', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        queue_params.append(namespace_filters)
                    queue_filters.append(
                        f"""
                        EXISTS (
                          SELECT 1
                          FROM jsonb_array_elements(COALESCE(evidence, '[]'::jsonb)) ev
                          WHERE {' AND '.join(queue_evidence_filters)}
                        )
                        """.strip()
                    )
                cur.execute(
                    f"""
                    SELECT
                      COUNT(*) FILTER (WHERE status = 'pending_review')::bigint,
                      COUNT(*) FILTER (WHERE status = 'blocked_conflict')::bigint
                    FROM wiki_draft_changes
                    WHERE {' AND '.join(queue_filters)}
                    """,
                    tuple(queue_params),
                )
                queue_row = cur.fetchone() or (0, 0)
                queue_pending_review = int(queue_row[0] or 0)
                queue_blocked_conflict = int(queue_row[1] or 0)

    def _stage_ratio(prev_value: int, next_value: int) -> float | None:
        if prev_value <= 0:
            return None
        return round(float(next_value) / float(prev_value), 4)

    stages = [
        {"key": "accepted", "label": "Accepted", "count": int(max(0, accepted_records))},
        {"key": "events", "label": "Events", "count": int(max(0, events_total))},
        {"key": "claims", "label": "Claims", "count": int(max(0, claims_total))},
        {"key": "drafts", "label": "Drafts", "count": int(max(0, drafts_total))},
        {"key": "pages", "label": "Pages", "count": int(max(0, pages_total))},
    ]
    transitions: list[dict[str, Any]] = []
    for index in range(len(stages) - 1):
        left = stages[index]
        right = stages[index + 1]
        drop_count = max(0, int(left["count"]) - int(right["count"]))
        drop_ratio = round(float(drop_count) / float(max(int(left["count"]), 1)), 4)
        transitions.append(
            {
                "from_stage": str(left["key"]),
                "to_stage": str(right["key"]),
                "from_count": int(left["count"]),
                "to_count": int(right["count"]),
                "drop_count": int(drop_count),
                "drop_ratio": float(drop_ratio),
                "conversion_ratio": _stage_ratio(int(left["count"]), int(right["count"])),
            }
        )

    bottleneck: dict[str, Any] | None = None
    if transitions:
        top = max(transitions, key=lambda item: (float(item["drop_ratio"]), int(item["drop_count"])))
        if int(top["drop_count"]) > 0:
            hint_by_stage = {
                ("accepted", "events"): "High dedup/noise at ingestion edge. Review source IDs and event-shape suppression.",
                ("events", "claims"): "Events are not turning into claims. Inspect worker extraction rules and record quality.",
                ("claims", "drafts"): "Claims are blocked before draft stage. Review gatekeeper thresholds and rejection diagnostics.",
                ("drafts", "pages"): "Moderation/publish is bottlenecked. Use bootstrap sampling or auto-publish policy tuning.",
            }
            ratio_value = float(top["drop_ratio"])
            level = "healthy"
            if ratio_value >= 0.5:
                level = "critical"
            elif ratio_value >= 0.25:
                level = "watch"
            bottleneck = {
                **top,
                "status": level,
                "hint": hint_by_stage.get((str(top["from_stage"]), str(top["to_stage"])), "Inspect stage diagnostics."),
            }

    return {
        "project_id": project_id,
        "window_days": int(days),
        "since": cutoff.isoformat(),
        "generated_at": datetime.now(UTC).isoformat(),
        "filters_applied": {
            "source_systems": source_filters,
            "namespaces": namespace_filters,
        },
        "pipeline": {
            "accepted": int(stages[0]["count"]),
            "events": int(stages[1]["count"]),
            "claims": int(stages[2]["count"]),
            "drafts": int(stages[3]["count"]),
            "pages": int(stages[4]["count"]),
        },
        "accepted_source": accepted_source,
        "rejected_event_like": int(max(0, rejected_event_like)),
        "conversions": {
            "accepted_to_events": _stage_ratio(int(stages[0]["count"]), int(stages[1]["count"])),
            "events_to_claims": _stage_ratio(int(stages[1]["count"]), int(stages[2]["count"])),
            "claims_to_drafts": _stage_ratio(int(stages[2]["count"]), int(stages[3]["count"])),
            "drafts_to_pages": _stage_ratio(int(stages[3]["count"]), int(stages[4]["count"])),
        },
        "draft_queue": {
            "pending_review": queue_pending_review,
            "blocked_conflict": queue_blocked_conflict,
            "open_total": int(queue_pending_review + queue_blocked_conflict),
        },
        "stages": stages,
        "transitions": transitions,
        "bottleneck": bottleneck,
    }


@app.post("/v1/adoption/project-reset", response_model=None)
def run_adoption_project_reset(
    payload: AdoptionProjectResetRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    scopes = _normalize_adoption_project_reset_scopes(payload.scopes)
    requested_by = _normalize_source_system(payload.requested_by, default="ops_admin")
    reason = str(payload.reason or "").strip() or None
    reset_id = uuid4()

    if not payload.dry_run:
        confirm_value = str(payload.confirm_project_id or "").strip()
        if not confirm_value or confirm_value != payload.project_id:
            raise HTTPException(
                status_code=422,
                detail={
                    "error": "project_reset_confirmation_required",
                    "message": "For non-dry-run reset, `confirm_project_id` must exactly match `project_id`.",
                    "project_id": payload.project_id,
                },
            )

    with get_conn() as conn:
        if not _adoption_project_resets_table_exists(conn):
            raise HTTPException(
                status_code=503,
                detail={
                    "error": "adoption_project_reset_unavailable",
                    "message": "adoption_project_resets table is not available. Apply migration 056_adoption_project_resets.sql.",
                },
            )
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint="/v1/adoption/project-reset",
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )

        preview: dict[str, Any] = {}
        deleted_tables: dict[str, int] = {}
        try:
            preview = _collect_adoption_project_reset_preview(conn, project_id=payload.project_id, scopes=scopes)
            if payload.dry_run:
                _insert_adoption_project_reset_audit(
                    conn,
                    reset_id=reset_id,
                    project_id=payload.project_id,
                    requested_by=requested_by,
                    reason=reason,
                    scopes=scopes,
                    dry_run=True,
                    status="dry_run",
                    rows_preview=preview,
                    rows_deleted={},
                )
                response = {
                    "status": "dry_run",
                    "reset_id": str(reset_id),
                    "project_id": payload.project_id,
                    "requested_by": requested_by,
                    "scopes": scopes,
                    "preview": preview,
                    "next_action": "rerun_with_dry_run=false_and_confirm_project_id",
                }
                mark_request_completed(
                    conn,
                    endpoint="/v1/adoption/project-reset",
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response

            deleted_tables = _apply_adoption_project_reset(conn, project_id=payload.project_id, scopes=scopes)
            deleted_total = int(sum(int(value) for value in deleted_tables.values()))
            _insert_adoption_project_reset_audit(
                conn,
                reset_id=reset_id,
                project_id=payload.project_id,
                requested_by=requested_by,
                reason=reason,
                scopes=scopes,
                dry_run=False,
                status="completed",
                rows_preview=preview,
                rows_deleted={"rows_total": deleted_total, "tables": deleted_tables},
            )
            response = {
                "status": "completed",
                "reset_id": str(reset_id),
                "project_id": payload.project_id,
                "requested_by": requested_by,
                "scopes": scopes,
                "preview": preview,
                "deleted": {"rows_total": deleted_total, "tables": deleted_tables},
            }
            mark_request_completed(
                conn,
                endpoint="/v1/adoption/project-reset",
                idempotency_key=idempotency_key,
                status_code=200,
                response_body=response,
            )
            return response
        except Exception as exc:
            try:
                _insert_adoption_project_reset_audit(
                    conn,
                    reset_id=reset_id,
                    project_id=payload.project_id,
                    requested_by=requested_by,
                    reason=reason,
                    scopes=scopes,
                    dry_run=bool(payload.dry_run),
                    status="failed",
                    rows_preview=preview,
                    rows_deleted={"tables": deleted_tables},
                    error_message=str(exc)[:2000],
                )
            except Exception:
                pass
            mark_request_failed(
                conn,
                endpoint="/v1/adoption/project-reset",
                idempotency_key=idempotency_key,
                error_message=str(exc),
            )
            raise


@app.post("/v1/adoption/bootstrap-profile/apply", response_model=None)
def apply_adoption_bootstrap_profile(
    payload: AdoptionBootstrapProfileApplyRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    project_id = str(payload.project_id or "").strip()
    if not project_id:
        raise HTTPException(status_code=422, detail="project_id_required")

    profile = _normalize_adoption_bootstrap_profile(payload.profile)
    updated_by = str(payload.updated_by or "").strip() or "ops_admin"
    note = str(payload.note or "").strip() or None
    dry_run = bool(payload.dry_run)

    if not dry_run:
        confirm_value = str(payload.confirm_project_id or "").strip()
        if not confirm_value or confirm_value != project_id:
            raise HTTPException(
                status_code=422,
                detail={
                    "error": "bootstrap_profile_confirmation_required",
                    "message": "For non-dry-run apply, `confirm_project_id` must exactly match `project_id`.",
                    "project_id": project_id,
                },
            )

    with get_conn() as conn:
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint="/v1/adoption/bootstrap-profile/apply",
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        try:
            current_payload = get_gatekeeper_config(project_id=project_id)
            current_config = current_payload.get("config") if isinstance(current_payload, dict) else {}
            if not isinstance(current_config, dict):
                current_config = {}
            recommendation_payload = get_wiki_bootstrap_approve_recommendation(project_id=project_id)
            recommendation = (
                recommendation_payload.get("recommended") if isinstance(recommendation_payload, dict) else {}
            )
            recommendation_diagnostics = (
                recommendation_payload.get("diagnostics") if isinstance(recommendation_payload, dict) else {}
            )
            if not isinstance(recommendation, dict):
                recommendation = {}
            if not isinstance(recommendation_diagnostics, dict):
                recommendation_diagnostics = {}

            target_config = _build_adoption_bootstrap_profile_target_config(
                profile=profile,
                current_config=current_config,
            )
            config_diff = _build_adoption_bootstrap_profile_diff(
                current_config=current_config,
                target_config=target_config,
            )
            response_base: dict[str, Any] = {
                "project_id": project_id,
                "profile": profile,
                "updated_by": updated_by,
                "dry_run": dry_run,
                "gatekeeper": {
                    "current": _adoption_bootstrap_profile_gatekeeper_excerpt(current_config),
                    "target": _adoption_bootstrap_profile_gatekeeper_excerpt(target_config),
                    "diff": config_diff,
                },
                "bootstrap_recommendation": recommendation,
                "diagnostics": recommendation_diagnostics,
                "safety": {
                    "confirm_required_for_apply": True,
                    "rollback_hint": {
                        "gatekeeper_snapshots_endpoint": (
                            f"/v1/gatekeeper/config/snapshots?project_id={quote(project_id)}&source=manual"
                        ),
                        "rollback_preview_endpoint": "/v1/gatekeeper/config/rollback/preview",
                        "bootstrap_approve_endpoint": "/v1/wiki/drafts/bootstrap-approve/run",
                    },
                },
                "generated_at": datetime.now(UTC).isoformat(),
            }

            if dry_run:
                response = {
                    "status": "dry_run",
                    **response_base,
                    "next_action": "rerun_with_dry_run=false_and_confirm_project_id",
                }
                mark_request_completed(
                    conn,
                    endpoint="/v1/adoption/bootstrap-profile/apply",
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response

            upsert_payload = _normalize_gatekeeper_config_for_apply(
                project_id=project_id,
                config=target_config,
                updated_by=updated_by,
            )
            upsert_result = upsert_gatekeeper_config(upsert_payload)
            applied_config = upsert_result.get("config") if isinstance(upsert_result, dict) else {}
            if not isinstance(applied_config, dict):
                applied_config = target_config

            snapshot_id: str | None = None
            snapshot_warning: str | None = None
            if _public_table_exists(conn, "gatekeeper_config_snapshots"):
                try:
                    snapshot_result = create_gatekeeper_config_snapshot(
                        GatekeeperConfigSnapshotCreateRequest(
                            project_id=project_id,
                            approved_by=updated_by,
                            source="manual",
                            note=note or f"Adoption bootstrap profile '{profile}' applied.",
                            config=applied_config,
                            artifact_refs={
                                "adoption": {
                                    "profile": profile,
                                    "recommended_bootstrap": recommendation,
                                }
                            },
                        )
                    )
                    snapshot_id = (
                        snapshot_result.get("snapshot", {}).get("id")
                        if isinstance(snapshot_result, dict)
                        else None
                    )
                except Exception as exc:  # pragma: no cover
                    snapshot_warning = str(exc)
            else:
                snapshot_warning = "gatekeeper_config_snapshots table is unavailable; snapshot skipped."

            response = {
                "status": "applied",
                **response_base,
                "dry_run": False,
                "gatekeeper": {
                    **response_base["gatekeeper"],
                    "applied": _adoption_bootstrap_profile_gatekeeper_excerpt(applied_config),
                },
                "snapshot_id": snapshot_id,
            }
            if snapshot_warning:
                response["warning"] = snapshot_warning

            mark_request_completed(
                conn,
                endpoint="/v1/adoption/bootstrap-profile/apply",
                idempotency_key=idempotency_key,
                status_code=200,
                response_body=response,
            )
            return response
        except Exception as exc:
            mark_request_failed(
                conn,
                endpoint="/v1/adoption/bootstrap-profile/apply",
                idempotency_key=idempotency_key,
                error_message=str(exc),
            )
            raise


