@app.get("/v1/gatekeeper/config/snapshots")
def list_gatekeeper_config_snapshots(
    project_id: str,
    source: str | None = Query(default=None, pattern="^(calibration_cycle|manual|rollback)$"),
    limit: int = Query(default=20, ge=1, le=200),
) -> dict[str, Any]:
    params: list[Any] = [project_id]
    filters = ["project_id = %s"]
    if source is not None:
        filters.append("source = %s")
        params.append(source)
    params.append(limit)

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                f"""
                SELECT
                  id::text,
                  project_id,
                  source,
                  approved_by,
                  note,
                  config,
                  guardrails_met,
                  holdout_meta,
                  calibration_report,
                  artifact_refs,
                  created_at
                FROM gatekeeper_config_snapshots
                WHERE {' AND '.join(filters)}
                ORDER BY created_at DESC
                LIMIT %s
                """,
                tuple(params),
            )
            rows = cur.fetchall()

    snapshots = [
        {
            "id": row[0],
            "project_id": row[1],
            "source": row[2],
            "approved_by": row[3],
            "note": row[4],
            "config": row[5],
            "guardrails_met": row[6],
            "holdout_meta": row[7],
            "calibration_report": row[8],
            "artifact_refs": row[9],
            "created_at": row[10].isoformat(),
        }
        for row in rows
    ]
    return {"snapshots": snapshots}


